const FRONTEND_CHUNK_3 = "ment.getElementById('mr-visual-settings-modal').style.display = 'flex';\r\n   }\r\n}\r\n\r\nfunction applyMrVisuals() {\r\n   let evH = document.getElementById('mr-event-height').value;\r\n   let shH = document.getElementById('mr-shift-height').value;\r\n   let rowH = document.getElementById('mr-row-height').value;\r\n   \r\n   document.getElementById('mr-event-height-val').innerText = evH + 'px';\r\n   document.getElementById('mr-shift-height-val').innerText = shH + 'px';\r\n   document.getElementById('mr-row-height-val').innerText = rowH + 'px';\r\n   \r\n   MR_VISUAL_SETTINGS.eventHeight = parseInt(evH, 10);\r\n   MR_VISUAL_SETTINGS.shiftHeight = parseInt(shH, 10);\r\n   MR_VISUAL_SETTINGS.rowHeight = parseInt(rowH, 10);\r\n   \r\n   initMrVisualsCSS();\r\n   if (typeof renderMonthGrid === 'function' && document.getElementById('month-roster-layer').style.display !== 'none') {\r\n       renderMonthGrid();\r\n   }\r\n}\r\n\r\nfunction closeMrVisualSettings() {\r\n   if (typeof closeContextualSettings === 'function') {\r\n       closeContextualSettings();\r\n   } else {\r\n       document.getElementById('mr-visual-settings-modal').style.display = 'none';\r\n   }\r\n}\r\n\r\nfunction openAssetVisualSettings() {\r\n    if (window.GridEngine && window.GridEngine.configs['vault']) {\r\n        window.GridEngine.openSettings('vault', '📦 ASSET REGISTRY SETTINGS');\r\n        let dynamicDiv = document.getElementById('ug-dynamic-settings');\r\n        if (dynamicDiv && !document.getElementById('asset-spacing-controls')) {\r\n            dynamicDiv.insertAdjacentHTML('afterbegin', `\r\n                <div id=\"asset-spacing-controls\" style=\"padding:15px; border-bottom:1px solid #333;\">\r\n                    <div class=\"input-label\" style=\"display:flex; justify-content:space-between; margin-bottom:8px;\">\r\n                        <span>Row Padding & Font Size</span>\r\n                    </div>\r\n                    <div style=\"display:flex; gap:10px;\">\r\n                        <button class=\"btn-outline btn-sm\" style=\"flex:1; margin:0;\" onclick=\"updateAssetSpacing(-1)\">- SMALLER</button>\r\n                        <button class=\"btn-outline btn-sm\" style=\"flex:1; margin:0;\" onclick=\"updateAssetSpacing(1)\">+ LARGER</button>\r\n                    </div>\r\n                </div>\r\n            `);\r\n        }\r\n    }\r\n}\r\n\r\nwindow.updateAssetSpacing = function(dir) {\r\n    ASSET_ROW_PADDING = Math.max(2, Math.min(24, ASSET_ROW_PADDING + (dir * 2)));\r\n    ASSET_FONT_SIZE = Math.max(8, Math.min(18, ASSET_FONT_SIZE + dir));\r\n    if (typeof renderAssetRegistry === 'function') renderAssetRegistry();\r\n};\r\n\r\nwindow.saveGridEngineSettings = function(gridId, e) {\r\n    let btn = e ? e.currentTarget : null;\r\n    let orig = btn ? btn.innerText : 'SAVING...';\r\n    if (btn) { btn.innerText = \"SAVING...\"; btn.disabled = true; }\r\n\r\n    let conf = window.GridEngine.configs[gridId];\r\n    if (gridId === 'vault' && conf) {\r\n        ASSET_COL_ORDER = [...conf.order];\r\n        if (typeof ASSET_COL_GAPS === 'undefined') window.ASSET_COL_GAPS = {};\r\n        Object.keys(conf.cols).forEach(k => {\r\n            ASSET_COL_WIDTHS[k] = conf.cols[k].w + 'px';\r\n            ASSET_COL_GAPS[k] = conf.cols[k].mL + 'px';\r\n            ASSET_COL_VISIBILITY[k] = conf.cols[k].vis;\r\n        });\r\n        let payload = { rowPadding: ASSET_ROW_PADDING, fontSize: ASSET_FONT_SIZE, colWidths: ASSET_COL_WIDTHS, colGaps: ASSET_COL_GAPS, colVisibility: ASSET_COL_VISIBILITY, colOrder: ASSET_COL_ORDER };\r\n        \r\n        google.script.run.withSuccessHandler(() => {\r\n            if (btn) { btn.innerText = orig; btn.disabled = false; }\r\n            if (typeof closeContextualSettings === 'function') closeContextualSettings();\r\n        }).withFailureHandler(err => {\r\n            alert(\"Save failed: \" + err.message);\r\n            if (btn) { btn.innerText = orig; btn.disabled = false; }\r\n        }).saveModuleVisualSettings('asset', payload, 'current');\r\n    } else if (gridId === 'tracker' && conf) {\r\n        TRACKER_COL_ORDER = [...conf.order];\r\n        if (typeof TRACKER_COL_GAPS === 'undefined') window.TRACKER_COL_GAPS = {};\r\n        Object.keys(conf.cols).forEach(k => {\r\n            TRACKER_COL_WIDTHS[k] = conf.cols[k].w + 'px';\r\n            TRACKER_COL_GAPS[k] = conf.cols[k].mL + 'px';\r\n            TRACKER_COL_VISIBILITY[k] = conf.cols[k].vis;\r\n        });\r\n        let payload = { rowPadding: TRACKER_ROW_PADDING, fontSize: TRACKER_FONT_SIZE, colWidths: TRACKER_COL_WIDTHS, colGaps: TRACKER_COL_GAPS, colVisibility: TRACKER_COL_VISIBILITY, colOrder: TRACKER_COL_ORDER };\r\n        \r\n        google.script.run.withSuccessHandler(() => {\r\n            if (btn) { btn.innerText = orig; btn.disabled = false; }\r\n            if (typeof closeContextualSettings === 'function') closeContextualSettings();\r\n        }).withFailureHandler(err => {\r\n            alert(\"Save failed: \" + err.message);\r\n            if (btn) { btn.innerText = orig; btn.disabled = false; }\r\n        }).saveModuleVisualSettings('tracker', payload, 'current');\r\n    }\r\n}\r\n\r\nfunction applyAssetVisuals() {\r\n    ASSET_ROW_PADDING = parseInt(document.getElementById('asset-vs-padding').value, 10);\r\n    ASSET_FONT_SIZE = parseInt(document.getElementById('asset-vs-font').value, 10);\r\n    document.getElementById('asset-vs-padding-val').innerText = ASSET_ROW_PADDING + 'px';\r\n    document.getElementById('asset-vs-font-val').innerText = ASSET_FONT_SIZE + 'px';\r\n    \r\n    document.querySelectorAll('.asset-col-cb').forEach(cb => {\r\n        ASSET_COL_VISIBILITY[cb.dataset.col] = cb.checked;\r\n    });\r\n\r\n    if (document.getElementById('tab-content-assets').style.display !== 'none') renderAssetRegistry();\r\n}\r\n\r\nfunction closeAssetVisualSettings() { \r\n    if (typeof closeContextualSettings === 'function') {\r\n        closeContextualSettings();\r\n    } else {\r\n        document.getElementById('asset-visual-settings-modal').style.display = 'none'; \r\n    }\r\n    let container = document.getElementById('asset-list-container');\r\n    if (container) container.classList.remove('editing-cols');\r\n}\r\n\r\n// --- TRACKER VISUAL SETTINGS ---\r\nfunction openTrackerVisualSettings() {\r\n    if (window.GridEngine && window.GridEngine.configs['tracker']) {\r\n        window.GridEngine.openSettings('tracker', '🌍 EQUIPMENT TRACKER SETTINGS');\r\n        let dynamicDiv = document.getElementById('ug-dynamic-settings');\r\n        if (dynamicDiv && !document.getElementById('tracker-spacing-controls')) {\r\n            dynamicDiv.insertAdjacentHTML('afterbegin', `\r\n                <div id=\"tracker-spacing-controls\" style=\"padding:15px; border-bottom:1px solid #333;\">\r\n                    <div class=\"input-label\" style=\"display:flex; justify-content:space-between; margin-bottom:8px;\">\r\n                        <span>Row Padding & Font Size</span>\r\n                    </div>\r\n                    <div style=\"display:flex; gap:10px;\">\r\n                        <button class=\"btn-outline btn-sm\" style=\"flex:1; margin:0;\" onclick=\"updateTrackerSpacing(-1)\">- SMALLER</button>\r\n                        <button class=\"btn-outline btn-sm\" style=\"flex:1; margin:0;\" onclick=\"updateTrackerSpacing(1)\">+ LARGER</button>\r\n                    </div>\r\n                </div>\r\n            `);\r\n        }\r\n    }\r\n}\r\n\r\nwindow.updateTrackerSpacing = function(dir) {\r\n    TRACKER_ROW_PADDING = Math.max(2, Math.min(24, TRACKER_ROW_PADDING + (dir * 2)));\r\n    TRACKER_FONT_SIZE = Math.max(8, Math.min(18, TRACKER_FONT_SIZE + dir));\r\n    if (typeof fetchTrackerData === 'function') fetchTrackerData();\r\n};\r\n\r\nfunction applyTrackerVisuals() {\r\n    if (typeof fetchTrackerData === 'function') fetchTrackerData();\r\n}\r\n\r\nfunction closeTrackerVisualSettings() {\r\n    closeContextualSettings();\r\n    let container = document.getElementById('tracker-list-content');\r\n    if (container) container.classList.remove('editing-cols');\r\n}\r\n\r\nfunction openProjectAssetVisualSettings() {\r\n    document.body.classList.add('editing-grid');\r\n    let confV = window.GridEngine.configs['project_vault'];\r\n    let confA = window.GridEngine.configs['project_assigned'];\r\n    let defs = window.GridEngine.defs['project_vault'];\r\n    if (!confV || !confA) return;\r\n\r\n    let html = `\r\n    <div style=\"padding:15px; border-bottom:1px solid #333;\">\r\n        <div class=\"input-label\" style=\"display:flex; justify-content:space-between; margin-bottom:8px;\">\r\n            <span>Row Padding & Font Size</span>\r\n        </div>\r\n        <div style=\"display:flex; gap:10px;\">\r\n            <button class=\"btn-outline btn-sm\" style=\"flex:1; margin:0;\" onclick=\"updatePaSpacing(-1)\">- SMALLER</button>\r\n            <button class=\"btn-outline btn-sm\" style=\"flex:1; margin:0;\" onclick=\"updatePaSpacing(1)\">+ LARGER</button>\r\n        </div>\r\n    </div>\r\n    <div style=\"padding:15px; border-bottom:1px solid #333;\">\r\n        <div class=\"input-label\" style=\"display:flex; justify-content:space-between;\">\r\n            <span>Panel Split Ratio (Left/Right)</span>\r\n            <span id=\"pa-split-val\" style=\"color:#d8b4fe;\">${PA_SPLIT_RATIO}% / ${100 - PA_SPLIT_RATIO}%</span>\r\n        </div>\r\n        <input type=\"range\" min=\"20\" max=\"80\" value=\"${PA_SPLIT_RATIO}\" oninput=\"document.getElementById('pa-split-val').innerText = this.value + '% / ' + (100 - this.value) + '%'; updatePaSplit(this.value);\" style=\"width: 100%; cursor: pointer; padding: 0;\">\r\n    </div>\r\n    <div style=\"display:flex; gap:15px; padding:15px; max-height:400px; overflow-y:auto;\">\r\n        <div style=\"flex:1; display:flex; flex-direction:column;\">\r\n            <div class=\"input-label\" style=\"margin-bottom:10px; color:#10b981;\">LEFT PANEL (VAULT)</div>\r\n            <div style=\"display:flex; flex-direction:column; gap:6px;\">`;\r\n            \r\n    confV.order.forEach(key => {\r\n        let def = defs.find(d => d.key === key);\r\n        if (!def) return;\r\n        html += `\r\n        <div draggable=\"true\" ondragstart=\"GridEngine.dragStartSettings(event, 'project_vault', '${key}')\" ondragover=\"GridEngine.dragOverSettings(event)\" ondrop=\"GridEngine.dropSettings(event, 'project_vault', '${key}')\" ondragend=\"GridEngine.dragEndSettings(event)\" style=\"display:flex; align-items:center; justify-content:space-between; background:#111; padding:6px 8px; border-radius:4px; border:1px solid #333; margin-bottom:4px; cursor:grab;\">\r\n            <label style=\"display:flex; align-items:center; gap:8px; cursor:pointer; margin:0;\">\r\n                <span style=\"color:#555; padding-right:4px;\">⋮⋮</span>\r\n                <input type=\"checkbox\" ${confV.cols[key].vis ? 'checked' : ''} onchange=\"togglePaSettingsCol('project_vault', '${key}', this.checked)\" style=\"margin:0; width:14px; height:14px;\">\r\n                <span style=\"color:#ccc; font-size:11px; font-weight:bold;\">${def.label}</span>\r\n            </label>\r\n            <div style=\"display:flex; gap:4px;\">\r\n                <button class=\"btn-outline btn-sm\" style=\"padding:2px 6px!important; margin:0; border-color:#10b981; color:#10b981;\" onclick=\"movePaSettingsCol('project_vault', '${key}', -1)\">▲</button>\r\n                <button class=\"btn-outline btn-sm\" style=\"padding:2px 6px!important; margin:0; border-color:#10b981; color:#10b981;\" onclick=\"movePaSettingsCol('project_vault', '${key}', 1)\">▼</button>\r\n            </div>\r\n        </div>`;\r\n    });\r\n\r\n    html += `</div></div><div style=\"flex:1; display:flex; flex-direction:column;\">\r\n            <div class=\"input-label\" style=\"margin-bottom:10px; color:#d8b4fe;\">RIGHT PANEL (ASSIGNED)</div>\r\n            <div style=\"display:flex; flex-direction:column; gap:6px;\">`;\r\n\r\n    confA.order.forEach(key => {\r\n        let def = defs.find(d => d.key === key);\r\n        if (!def) return;\r\n        html += `\r\n        <div draggable=\"true\" ondragstart=\"GridEngine.dragStartSettings(event, 'project_assigned', '${key}')\" ondragover=\"GridEngine.dragOverSettings(event)\" ondrop=\"GridEngine.dropSettings(event, 'project_assigned', '${key}')\" ondragend=\"GridEngine.dragEndSettings(event)\" style=\"display:flex; align-items:center; justify-content:space-between; background:#111; padding:6px 8px; border-radius:4px; border:1px solid #333; margin-bottom:4px; cursor:grab;\">\r\n            <label style=\"display:flex; align-items:center; gap:8px; cursor:pointer; margin:0;\">\r\n                <span style=\"color:#555; padding-right:4px;\">⋮⋮</span>\r\n                <input type=\"checkbox\" ${confA.cols[key].vis ? 'checked' : ''} onchange=\"togglePaSettingsCol('project_assigned', '${key}', this.checked)\" style=\"margin:0; width:14px; height:14px;\">\r\n                <span style=\"color:#ccc; font-size:11px; font-weight:bold;\">${def.label}</span>\r\n            </label>\r\n            <div style=\"display:flex; gap:4px;\">\r\n                <button class=\"btn-outline btn-sm\" style=\"padding:2px 6px!important; margin:0; border-color:#d8b4fe; color:#d8b4fe;\" onclick=\"movePaSettingsCol('project_assigned', '${key}', -1)\">▲</button>\r\n                <button class=\"btn-outline btn-sm\" style=\"padding:2px 6px!important; margin:0; border-color:#d8b4fe; color:#d8b4fe;\" onclick=\"movePaSettingsCol('project_assigned', '${key}', 1)\">▼</button>\r\n            </div>\r\n        </div>`;\r\n    });\r\n    \r\n    html += `</div></div></div>\r\n    <div style=\"display:flex; gap:12px; padding:15px; border-top: 1px solid #333; justify-content: flex-end; align-items: center;\">\r\n        <button class=\"btn-close\" style=\"width:auto; margin:0;\" onclick=\"closeProjectAssetVisualSettings()\">CANCEL</button>\r\n        <button class=\"btn-main\" style=\"width:auto; margin:0;\" onclick=\"saveProjectAssetVisualSettings(event)\">DONE & SAVE</button>\r\n    </div>`;\r\n    \r\n    let drawerContent = document.getElementById('settings-drawer-content');\r\n    if (drawerContent) {\r\n        Array.from(drawerContent.children).forEach(child => child.style.display = 'none');\r\n        let dynamicDiv = document.getElementById('ug-dynamic-settings');\r\n        if (!dynamicDiv) { dynamicDiv = document.createElement('div'); dynamicDiv.id = 'ug-dynamic-settings'; drawerContent.appendChild(dynamicDiv); }\r\n        dynamicDiv.innerHTML = html;\r\n        dynamicDiv.style.display = 'block';\r\n        document.getElementById('settings-drawer-title').innerText = '⚙️ PROJECT EQUIPMENT';\r\n        document.getElementById('settings-drawer-title').style.color = '#f59e0b';\r\n        document.getElementById('settings-drawer-wrapper').style.display = 'flex';\r\n    }\r\n}\r\n\r\nwindow.togglePaSettingsCol = function(gridId, key, isVis) {\r\n    window.GridEngine.configs[gridId].cols[key].vis = isVis;\r\n    if (window.GridEngine.updateGlobals) window.GridEngine.updateGlobals(gridId);\r\n    window.GridEngine.fireRender(gridId);\r\n};\r\n\r\nwindow.movePaSettingsCol = function(gridId, key, dir) {\r\n    let conf = window.GridEngine.configs[gridId];\r\n    let idx = conf.order.indexOf(key);\r\n    if (idx === -1) return;\r\n    let newIdx = idx + dir;\r\n    if (newIdx < 0 || newIdx >= conf.order.length) return;\r\n    let temp = conf.order[idx]; conf.order[idx] = conf.order[newIdx]; conf.order[newIdx] = temp;\r\n    \r\n    if (window.GridEngine.updateGlobals) window.GridEngine.updateGlobals(gridId);\r\n    openProjectAssetVisualSettings();\r\n    window.GridEngine.fireRender(gridId);\r\n};\r\n\r\nwindow.updatePaSpacing = function(dir) {\r\n    PA_ROW_PADDING = Math.max(2, Math.min(24, PA_ROW_PADDING + (dir * 2)));\r\n    PA_FONT_SIZE = Math.max(8, Math.min(18, PA_FONT_SIZE + dir));\r\n    if (typeof renderProjectAssetsUI === 'function') renderProjectAssetsUI();\r\n};\r\n\r\nwindow.updatePaSplit = function(val) {\r\n    PA_SPLIT_RATIO = parseInt(val, 10);\r\n    let pane = document.getElementById('pa-split-pane');\r\n    if (pane) {\r\n        pane.style.setProperty('--pa-split-left', PA_SPLIT_RATIO + '%');\r\n        pane.style.setProperty('--pa-split-right', (100 - PA_SPLIT_RATIO) + '%');\r\n    }\r\n};\r\n\r\nwindow.saveProjectAssetVisualSettings = function(e) {\r\n    let btn = e ? e.currentTarget : null;\r\n    let orig = btn ? btn.innerText : 'SAVING...';\r\n    if (btn) { btn.innerText = \"SAVING...\"; btn.disabled = true; }\r\n\r\n    let confV = window.GridEngine.configs['project_vault'];\r\n    let confA = window.GridEngine.configs['project_assigned'];\r\n    \r\n    if (confV && confA) {\r\n        PA_VAULT_COL_ORDER = [...confV.order];\r\n        if (typeof PA_VAULT_COL_GAPS === 'undefined') window.PA_VAULT_COL_GAPS = {};\r\n        Object.keys(confV.cols).forEach(k => {\r\n            PA_VAULT_COL_WIDTHS[k] = confV.cols[k].w + 'px';\r\n            PA_VAULT_COL_GAPS[k] = confV.cols[k].mL + 'px';\r\n            PA_VAULT_COL_VISIBILITY[k] = confV.cols[k].vis;\r\n        });\r\n        \r\n        PA_COL_ORDER = [...confA.order];\r\n        if (typeof PA_COL_GAPS === 'undefined') window.PA_COL_GAPS = {};\r\n        Object.keys(confA.cols).forEach(k => {\r\n            PA_COL_WIDTHS[k] = confA.cols[k].w + 'px';\r\n            PA_COL_GAPS[k] = confA.cols[k].mL + 'px';\r\n            PA_COL_VISIBILITY[k] = confA.cols[k].vis;\r\n        });\r\n        \r\n        let payload = { rowPadding: PA_ROW_PADDING, fontSize: PA_FONT_SIZE, paSplitRatio: PA_SPLIT_RATIO, colWidths: PA_COL_WIDTHS, colGaps: PA_COL_GAPS, colVisibility: PA_COL_VISIBILITY, colOrder: PA_COL_ORDER, paVault: { colWidths: PA_VAULT_COL_WIDTHS, colGaps: PA_VAULT_COL_GAPS, colVisibility: PA_VAULT_COL_VISIBILITY, colOrder: PA_VAULT_COL_ORDER } };\r\n        \r\n        google.script.run.withSuccessHandler(() => {\r\n            if (btn) { btn.innerText = orig; btn.disabled = false; }\r\n            closeProjectAssetVisualSettings();\r\n        }).withFailureHandler(err => {\r\n            alert(\"Save failed: \" + err.message);\r\n            if (btn) { btn.innerText = orig; btn.disabled = false; }\r\n        }).saveModuleVisualSettings('projectAsset', payload, 'current');\r\n    }\r\n}\r\n\r\nfunction closeProjectAssetVisualSettings() { \r\n    closeContextualSettings();\r\n}\r\n\r\nfunction openMiniVisualSettings() {\r\n   document.getElementById('mini-color-main').value = PAINT_COLORS['main'].color;\r\n   document.getElementById('mini-color-wh').value = PAINT_COLORS['wh'].color;\r\n   document.getElementById('mini-color-show').value = PAINT_COLORS['show'].color;\r\n   document.getElementById('mini-color-recovery').value = PAINT_COLORS['recovery'].color;\r\n   document.getElementById('mini-color-transit').value = PAINT_COLORS['transit'].color;\r\n   document.getElementById('mini-height-val').innerText = MINI_EVENT_HEIGHT + 'px';\r\n   document.getElementById('mini-height').value = MINI_EVENT_HEIGHT;\r\n   document.getElementById('mini-font-val').innerText = MINI_FONT_SIZE + 'px';\r\n   document.getElementById('mini-font').value = MINI_FONT_SIZE;\r\n   mountToDrawer('mini-visual-settings-modal', '⚙️ STRIP COLORS', '#d8b4fe');\r\n}\r\n\r\nfunction applyMiniVisuals() {\r\n   PAINT_COLORS['main'].color = document.getElementById('mini-color-main').value;\r\n   PAINT_COLORS['wh'].color = document.getElementById('mini-color-wh').value;\r\n   PAINT_COLORS['show'].color = document.getElementById('mini-color-show').value;\r\n   PAINT_COLORS['recovery'].color = document.getElementById('mini-color-recovery').value;\r\n   PAINT_COLORS['transit'].color = document.getElementById('mini-color-transit').value;\r\n   MINI_EVENT_HEIGHT = document.getElementById('mini-height').value;\r\n   document.getElementById('mini-height-val').innerText = MINI_EVENT_HEIGHT + 'px';\r\n   MINI_FONT_SIZE = document.getElementById('mini-font').value;\r\n   document.getElementById('mini-font-val').innerText = MINI_FONT_SIZE + 'px';\r\n   initMiniVisualsCSS();\r\n}\r\n\r\nfunction closeMiniVisualSettings() {\r\n   closeContextualSettings();\r\n}\r\n\r\nfunction openPhaseManager() {\r\n    let html = '';\r\n    for(let phase in PHASE_PALETTE) {\r\n        html += createPhaseRow(phase, PHASE_PALETTE[phase]);\r\n    }\r\n    document.getElementById('pm-list').innerHTML = html;\r\n    mountToDrawer('phase-manager-modal', '🎯 PHASE MANAGER', '#ef4444');\r\n}\r\n\r\nfunction createPhaseRow(name, color) {\r\n    return `\r\n    <div class=\"pm-row\" style=\"display:flex; gap:10px; align-items:center; background:#222; padding:10px; border-radius:6px; margin-bottom:8px;\">\r\n        <input type=\"hidden\" class=\"pm-old\" value=\"${String(name || '').replace(/\"/g, '&quot;')}\">\r\n        <input type=\"text\" class=\"pm-name\" value=\"${String(name || '').replace(/\"/g, '&quot;')}\" placeholder=\"Phase Name\" style=\"flex:1; padding:8px; font-size:12px; background:#111;\">\r\n        <input type=\"color\" class=\"pm-color\" value=\"${color}\" style=\"width:35px; height:35px; padding:0; border:none; border-radius:4px; cursor:pointer; background:transparent;\">\r\n        <button class=\"btn-delete\" style=\"width:auto;\" onclick=\"this.parentElement.remove()\" title=\"Delete\">DELETE</button>\r\n    </div>`;\r\n}\r\n\r\nfunction addPhaseRow() {\r\n    document.getElementById('pm-list').insertAdjacentHTML('beforeend', createPhaseRow('New Phase', '#ffffff'));\r\n}\r\n\r\nfunction savePhaseManager() {\r\n    let newPalette = {};\r\n    let renameMap = {};\r\n    \r\n    document.querySelectorAll('.pm-row').forEach(row => {\r\n        let oldName = row.querySelector('.pm-old').value;\r\n        let newName = row.querySelector('.pm-name').value.trim();\r\n        let color = row.querySelector('.pm-color').value;\r\n        \r\n        if(newName) {\r\n            newPalette[newName] = color;\r\n            if(oldName && oldName !== newName) {\r\n                renameMap[oldName] = newName; \r\n            }\r\n        }\r\n    });\r\n    \r\n    PHASE_PALETTE = newPalette;\r\n    \r\n    activePhases.forEach(p => {\r\n        if(renameMap[p.type]) p.type = renameMap[p.type];\r\n    });\r\n    \r\n    applyRealTimeVisuals();\r\n    openVisualSettings();\r\n}\r\n\r\nfunction cancelPhaseManager() {\r\n    openVisualSettings();\r\n}\r\n\r\nfunction openDeptManager() {\r\n    document.getElementById('master-settings-overlay').style.display = 'none';\r\n    let html = '';\r\n    SYSTEM_DEPARTMENTS.forEach(dept => { html += createListRow(dept, 'dept'); });\r\n    document.getElementById('dept-list').innerHTML = html;\r\n    document.getElementById('dept-manager-modal').style.display = 'flex';\r\n}\r\n\r\nfunction openMealManager() {\r\n    document.getElementById('master-settings-overlay').style.display = 'none';\r\n    let html = '';\r\n    SYSTEM_MEALS.forEach(meal => { html += createListRow(meal, 'meal'); });\r\n    document.getElementById('meal-list').innerHTML = html;\r\n    document.getElementById('meal-manager-modal').style.display = 'flex';\r\n}\r\n\r\nfunction createListRow(val, type) {\r\nif (type === 'dept') {\r\n    let uid = typeof val === 'object' ? (val.uid || '') : '';\r\n    let name = typeof val === 'object' ? val.name : val;\r\n    let color = typeof val === 'object' ? val.color : '#3b82f6';\r\n    let isCore = ['Lighting', 'Audio', 'Video', 'Rigging', 'Trucks'].includes(name);\r\n    let inputAttr = isCore ? 'readonly style=\"flex:1; padding:8px; font-size:12px; background:#111; color:#888; border:1px solid #333;\"' : 'style=\"flex:1; padding:8px; font-size:12px; background:#111; color:#fff; border:1px solid #444;\"';\r\n          let btnHtml = isCore ? `<div style=\"width:60px;\"></div>` : `<button class=\"btn-delete\" style=\"width:auto;\" onclick=\"this.parentElement.remove()\" title=\"Delete\">DELETE</button>`;\r\n    return `<div class=\"${type}-row\" style=\"display:flex; gap:10px; align-items:center; background:#222; padding:10px; border-radius:6px; margin-bottom:8px;\">\r\n              <input type=\"hidden\" class=\"dept-uid\" value=\"${uid}\">\r\n              <input type=\"color\" class=\"${type}-color\" value=\"${color}\" style=\"width:35px; height:35px; padding:0; border:none; cursor:pointer; border-radius:4px; background:transparent;\">\r\n              <input type=\"text\" class=\"${type}-val\" value=\"${String(name || '').replace(/\"/g, '&quot;')}\" ${inputAttr}>\r\n              ${btnHtml}\r\n            </div>`;\r\n} else {\r\n    let inputAttr = 'style=\"flex:1; padding:8px; font-size:12px; background:#111; color:#fff; border:1px solid #444;\"';\r\n    return `<div class=\"${type}-row\" style=\"display:flex; gap:10px; align-items:center; background:#222; padding:10px; border-radius:6px; margin-bottom:8px;\">\r\n              <input type=\"text\" class=\"${type}-val\" value=\"${String(val || '').replace(/\"/g, '&quot;')}\" ${inputAttr}>\r\n                <button class=\"btn-delete\" style=\"width:auto;\" onclick=\"this.parentElement.remove()\" title=\"Delete\">DELETE</button>\r\n            </div>`;\r\n}\r\n}\r\n\r\nfunction addListRow(type) {\r\n  let defaultVal = type === 'dept' ? {uid: '', name: 'New Department', color: '#888888'} : 'New Meal';\r\n  document.getElementById(`${type}-list`).insertAdjacentHTML('beforeend', createListRow(defaultVal, type));\r\n}\r\n\r\nfunction saveListManager(type) {\r\n    let newList = [];\r\n    if (type === 'dept') {\r\n        document.querySelectorAll(`.${type}-row`).forEach(row => {\r\n            let u = row.querySelector('.dept-uid').value.trim();\r\n            if (!u) u = 'dept_' + Date.now() + Math.random().toString(36).substr(2, 5);\r\n            let n = row.querySelector(`.${type}-val`).value.trim();\r\n            let c = row.querySelector(`.${type}-color`).value;\r\n            if (n) newList.push({ uid: u, name: n, color: c });\r\n        });\r\n    } else {\r\n        document.querySelectorAll(`.${type}-row`).forEach(row => {\r\n            let val = row.querySelector(`.${type}-val`).value.trim();\r\n            if (val) newList.push(val);\r\n        });\r\n    }\r\n\r\n    const modal = document.getElementById(`${type}-manager-modal`);\r\n    const btn = modal.querySelector('.btn-main');\r\n    const origText = btn.innerText;\r\n    btn.innerText = 'SAVING...';\r\n    btn.disabled = true;\r\n\r\n    // These elements might not exist in the current view, so we must check for them safely.\r\n    let boss1El = document.getElementById('set-boss1-email');\r\n    let boss2El = document.getElementById('set-boss2-email');\r\n    let boss1 = boss1El ? boss1El.value : '';\r\n    let boss2 = boss2El ? boss2El.value : '';\r\n\r\n    let deptsToSave = (type === 'dept') ? newList : SYSTEM_DEPARTMENTS;\r\n    let mealsToSave = (type === 'meal') ? newList : SYSTEM_MEALS;\r\n\r\n    google.script.run\r\n        .withSuccessHandler(res => {\r\n            btn.innerText = 'SAVED!';\r\n            SYSTEM_DEPARTMENTS = deptsToSave; // Update global state after successful save\r\n            SYSTEM_MEALS = mealsToSave;\r\n            setTimeout(() => {\r\n                btn.innerText = origText; btn.disabled = false;\r\n                modal.style.display = 'none'; openMasterSettings();\r\n            }, 500);\r\n        })\r\n        .withFailureHandler(err => { alert(\"Save Failed: \" + err.message); btn.innerText = origText; btn.disabled = false; })\r\n        .saveSystemSettings(boss1, boss2, deptsToSave, mealsToSave);\r\n}\r\n\r\nfunction cancelListManager(type) {\r\n  document.getElementById(`${type}-manager-modal`).style.display = 'none';\r\n  openMasterSettings(); // Brings you back to the giant screen\r\n}\r\n\r\nfunction toggleDept(safeDept, prefix) {\r\n    const rows = document.querySelectorAll(`.${prefix}-row-${safeDept}`);\r\n    const icon = document.getElementById(`icon-${prefix}-${safeDept}`);\r\n    const summaryContainer = document.getElementById(`summary-${prefix}-${safeDept}`);\r\n    if(!icon) return;\r\n    let isClosing = icon.innerText === '▼';\r\n    rows.forEach(r => {\r\n      r.style.setProperty('display', isClosing ? 'none' : '', 'important');\r\n    });\r\n    icon.innerText = isClosing ? '▶' : '▼';\r\n    if (summaryContainer) {\r\n      summaryContainer.style.display = isClosing ? 'block' : 'none';\r\n    }\r\n}\r\n\r\nfunction openAssignmentManager() {\r\n    document.getElementById('master-settings-overlay').style.display = 'none';\r\n    let html = '';\r\n    let index = 0;\r\n    \r\n    for (let [name, colors] of Object.entries(ROLE_COLORS)) {\r\n        html += createAssignmentRow(name, colors.bg, colors.text, index);\r\n        index++;\r\n    }\r\n    \r\n    document.getElementById('assignment-list').innerHTML = html;\r\n    document.getElementById('assignment-manager-modal').style.display = 'flex';\r\n}\r\n\r\nfunction createAssignmentRow(name, bg, text, index) {\r\n    return `\r\n    <div id=\"assign-row-${index}\" class=\"assign-row\" style=\"display:flex; gap:10px; margin-bottom:10px; align-items:center;\">\r\n        <input type=\"hidden\" class=\"assign-bg\" value=\"${bg}\">\r\n        <input type=\"hidden\" class=\"assign-text\" value=\"${text}\">\r\n        <input type=\"text\" class=\"assign-name\" value=\"${name}\" placeholder=\"e.g. Technician\" style=\"flex:1; padding:8px; background:#18181b; border:1px solid #3f3f46; color:white; border-radius:4px; box-sizing:border-box;\">\r\n        <button class=\"btn-delete\" style=\"margin:0;\" onclick=\"document.getElementById('assign-row-${index}').remove()\">DELETE</button>\r\n    </div>`;\r\n}\r\n\r\nfunction addAssignmentRow() {\r\n    const list = document.getElementById('assignment-list');\r\n    const index = Date.now(); \r\n    list.insertAdjacentHTML('beforeend', createAssignmentRow('', '#3b82f6', '#ffffff', index));\r\n}\r\n\r\nfunction saveAssignmentManager() {\r\n    const list = document.getElementById('assignment-list');\r\n    const rows = list.querySelectorAll('.assign-row');\r\n    let newColors = {};\r\n    \r\n    for (let i = 0; i < rows.length; i++) {\r\n        const name = rows[i].querySelector('.assign-name').value.trim();\r\n        const bg = rows[i].querySelector('.assign-bg').value;\r\n        const text = rows[i].querySelector('.assign-text').value;\r\n        if (name !== \"\") {\r\n            newColors[name] = { bg: bg, text: text };\r\n        }\r\n    }\r\n    \r\n    ROLE_COLORS = newColors;\r\n    \r\n    const payload = {\r\n        sidebarWidth: CURRENT_SIDEBAR_WIDTH, rowHeight: CURRENT_ROW_HEIGHT, shiftHeight: SHIFT_HEIGHT,\r\n        shiftFontSize: SHIFT_FONT_SIZE, shiftFontWeight: SHIFT_FONT_WEIGHT, shiftFontStyle: SHIFT_FONT_STYLE,\r\n        shiftTextDeco: SHIFT_TEXT_DECORATION, shiftTimeX: SHIFT_TIME_X, shiftTimeY: SHIFT_TIME_Y,\r\n        shiftRoleX: SHIFT_ROLE_X, shiftRoleY: SHIFT_ROLE_Y, phases: PHASE_PALETTE, roles: ROLE_COLORS\r\n    };\r\n    \r\n    google.script.run.withSuccessHandler(res => {\r\n        document.getElementById('assignment-manager-modal').style.display = 'none';\r\n        openMasterSettings(); \r\n    }).saveModuleVisualSettings('timeline', payload, 'current');\r\n}\r\n\r\nfunction cancelAssignmentManager() {\r\n    document.getElementById('assignment-manager-modal').style.display = 'none';\r\n    openMasterSettings();\r\n}\r\n\r\nfunction openColorManager() {\r\n    let html = '';\r\n    let index = 0;\r\n    \r\n    for (let [name, colors] of Object.entries(ROLE_COLORS)) {\r\n        html += createColorRow(name, colors.bg, colors.text, index);\r\n        index++;\r\n    }\r\n    \r\n    document.getElementById('color-list').innerHTML = html;\r\n    mountToDrawer('color-manager-modal', '🎨 EDIT COLORS', '#f59e0b');\r\n}\r\n\r\nfunction createColorRow(name, bg, text, index) {\r\n    return `\r\n    <div id=\"color-row-${index}\" class=\"color-row\" style=\"display:flex; gap:10px; margin-bottom:10px; align-items:center;\">\r\n        <input type=\"text\" class=\"color-name\" value=\"${name}\" disabled style=\"flex:2; padding:8px; background:#18181b; border:1px solid #3f3f46; color:#a1a1aa; border-radius:4px; box-sizing:border-box; opacity: 0.8;\">\r\n        <input type=\"color\" class=\"color-bg\" value=\"${bg}\" style=\"flex:1; height:35px; padding:0; border:none; border-radius:4px; cursor:pointer;\">\r\n        <input type=\"color\" class=\"color-text\" value=\"${text}\" style=\"flex:1; height:35px; padding:0; border:none; border-radius:4px; cursor:pointer;\">\r\n    </div>`;\r\n}\r\n\r\nfunction saveColorManager() {\r\n    const list = document.getElementById('color-list');\r\n    const rows = list.querySelectorAll('.color-row');\r\n    let newColors = {};\r\n    \r\n    for (let i = 0; i < rows.length; i++) {\r\n        const name = rows[i].querySelector('.color-name').value.trim();\r\n        const bg = rows[i].querySelector('.color-bg').value;\r\n        const text = rows[i].querySelector('.color-text').value;\r\n        if (name !== \"\") {\r\n            newColors[name] = { bg: bg, text: text };\r\n        }\r\n    }\r\n    \r\n    ROLE_COLORS = newColors;\r\n    \r\n    const payload = {\r\n        sidebarWidth: CURRENT_SIDEBAR_WIDTH, rowHeight: CURRENT_ROW_HEIGHT, shiftHeight: SHIFT_HEIGHT,\r\n        shiftFontSize: SHIFT_FONT_SIZE, shiftFontWeight: SHIFT_FONT_WEIGHT, shiftFontStyle: SHIFT_FONT_STYLE,\r\n        shiftTextDeco: SHIFT_TEXT_DECORATION, shiftTimeX: SHIFT_TIME_X, shiftTimeY: SHIFT_TIME_Y,\r\n        shiftRoleX: SHIFT_ROLE_X, shiftRoleY: SHIFT_ROLE_Y, phases: PHASE_PALETTE, roles: ROLE_COLORS\r\n    };\r\n    \r\n    google.script.run.withSuccessHandler(res => {\r\n        applyRealTimeVisuals();\r\n        openVisualSettings();\r\n    }).saveModuleVisualSettings('timeline', payload, 'current');\r\n}\r\n\r\nfunction cancelColorManager() {\r\n    openVisualSettings();\r\n}\r\n\r\nfunction toggleContextualSettings() {\r\n    let drawer = document.getElementById('settings-drawer-wrapper');\r\n    if (drawer && drawer.style.display === 'flex') {\r\n        if (typeof closeContextualSettings === 'function') {\r\n            closeContextualSettings();\r\n        } else {\r\n            drawer.style.display = 'none';\r\n        }\r\n        return;\r\n    }\r\n\r\n    let shiftLayer = document.getElementById('shift-layer');\r\n    let monthRoster = document.getElementById('month-roster-layer');\r\n    let projectAssetsModal = document.getElementById('project-assets-modal-overlay');\r\n    let masterSettings = document.getElementById('master-settings-overlay');\r\n    let editModal = document.getElementById('edit-modal-overlay');\r\n    let availabilityModal = document.getElementById('availability-modal-overlay');\r\n\r\n    if (availabilityModal && availabilityModal.style.display !== 'none' && availabilityModal.style.display !== '') {\r\n        openTrackerVisualSettings();\r\n    } else if (projectAssetsModal && projectAssetsModal.style.display !== 'none' && projectAssetsModal.style.display !== '') {\r\n        openProjectAssetVisualSettings();\r\n    } else if (shiftLayer && shiftLayer.style.display !== 'none' && shiftLayer.style.display !== '') {\r\n        openVisualSettings();\r\n    } else if (monthRoster && monthRoster.style.display !== 'none' && monthRoster.style.display !== '') {\r\n        openMrVisualSettings();\r\n    } else if (masterSettings && masterSettings.style.display !== 'none' && masterSettings.style.display !== '') {\r\n        let assetsTab = document.getElementById('tab-content-assets');\r\n        if (assetsTab && assetsTab.style.display !== 'none' && assetsTab.style.display !== '') {\r\n            openAssetVisualSettings();\r\n        } else {\r\n            if (drawer) {\r\n                document.getElementById('settings-empty-state').style.display = 'block';\r\n                document.getElementById('settings-drawer-title').innerText = '⚙️ VISUAL SETTINGS';\r\n                document.getElementById('settings-drawer-title').style.color = '#10b981';\r\n                Array.from(document.getElementById('settings-drawer-content').children).forEach(child => {\r\n                    if(child.id !== 'settings-empty-state') child.style.display = 'none';\r\n                });\r\n                drawer.style.display = 'flex';\r\n            }\r\n        }\r\n    } else if (editModal && editModal.style.display !== 'none' && editModal.style.display !== '') {\r\n        openMiniVisualSettings();\r\n    } else {\r\n        openCalendarVisualSettings();\r\n    }\r\n}\r\n\n\n\r\n/**\r\n * 06d_Admin_Fleet.html\r\n * Domain: Fleet Database, Vehicle Logic.\r\n */\r\n\r\n// @INDEX: FLEET -> Render Vehicle Database\r\nfunction loadVehicles() {\r\n    const container = document.getElementById('vehicle-list-container');\r\n    \r\n    let needsFetch = false;\r\n    let isCachedRendered = false;\r\n\r\n    if (!globalVehicles || globalVehicles.length === 0) {\r\n        needsFetch = true;\r\n        try {\r\n            let cachedRaw = localStorage.getItem('sm_fleet_cache');\r\n            if (cachedRaw) {\r\n                globalVehicles = JSON.parse(cachedRaw) || [];\r\n                if (globalVehicles.length > 0) {\r\n                    renderVehicles();\r\n                    if (typeof populateTruckSelector === 'function') populateTruckSelector();\r\n                    isCachedRendered = true;\r\n                }\r\n            }\r\n        } catch(e) {}\r\n    }\r\n\r\n    if (needsFetch) {\r\n        if (!isCachedRendered) {\r\n            container.innerHTML = '<div style=\"text-align:center; padding: 40px; color: #10b981; font-weight:bold;\">Decrypting Fleet Data...</div>';\r\n        }\r\n        google.script.run.withSuccessHandler(res => {\r\n            globalVehicles = res || [];\r\n            try { localStorage.setItem('sm_fleet_cache', JSON.stringify(globalVehicles)); } catch(e) {}\r\n            renderVehicles();\r\n            if (typeof populateTruckSelector === 'function') populateTruckSelector();\r\n        }).getVehiclesVault();\r\n    } else {\r\n        renderVehicles();\r\n    }\r\n}\r\n\r\nfunction renderVehicles() {\r\n    const container = document.getElementById('vehicle-list-container');\r\n    if (!globalVehicles || globalVehicles.length === 0) {\r\n        container.innerHTML = '<div style=\"text-align:center; padding: 40px; color: #888;\">No vehicles found. Click \"ADD NEW VEHICLE\" to start.</div>';\r\n        return;\r\n    }\r\n    \r\n    let html = '';\r\n    globalVehicles.forEach(v => {\r\n        let isGen = (v.isGeneric === true || v.isGeneric === \"true\");\r\n        let plateHtml = isGen ? `<span style=\"background:rgba(245,158,11,0.1); color:#f59e0b; padding:2px 6px; border-radius:4px; font-size:10px; font-weight:bold; border:1px dashed #f59e0b;\">GENERIC / RANDOM</span>` \r\n                              : `<span style=\"color:#a1a1aa; font-family:monospace; background:#111; padding:2px 6px; border-radius:4px; border:1px solid #333;\">${v.plate || 'No Plate'}</span>`;\r\n                              \r\n        html += `\r\n        <div style=\"background:#1a1a1e; border:1px solid #333; padding:15px; border-radius:8px; margin-bottom:10px; display:flex; justify-content:space-between; align-items:center; transition:0.2s;\" onmouseover=\"this.style.borderColor='#3b82f6'\" onmouseout=\"this.style.borderColor='#333'\">\r\n            <div>\r\n                <div style=\"color:#fff; font-weight:900; font-size:15px; margin-bottom:4px; display:flex; align-items:center; gap:10px;\">\r\n                    <span>🚛 ${v.name}</span>\r\n                    ${plateHtml}\r\n                </div>\r\n                <div style=\"color:#888; font-size:11px; display:flex; gap:15px;\">\r\n                    <span><b>Vendor:</b> ${v.vendor || 'Internal'}</span>\r\n                    <span><b>Dims:</b> ${v.l || 0}m x ${v.w || 0}m x ${v.h || 0}m</span>\r\n                    <span><b>Payload:</b> ${v.kg || 0}kg</span>\r\n                    <span><b>Vol:</b> ${v.vol || 0}m³</span>\r\n                    ${v.lift ? `<span style=\"color:#10b981;\"><b>Lift:</b> ${v.lift}kg</span>` : ''}\r\n                </div>\r\n            </div>\r\n            <button class=\"btn-outline btn-sm\" style=\"margin:0; border-color:#3b82f6; color:#3b82f6;\" onclick=\"openVehicleModal('${v.id}')\">EDIT</button>\r\n        </div>`;\r\n    });\r\n    container.innerHTML = html;\r\n}\r\n\r\nfunction openVehicleModal(id = null) {\r\n    document.querySelectorAll('#vehicle-modal-overlay input').forEach(i => { if (i.type !== 'checkbox') i.value = ''; });\r\n    document.getElementById('veh-generic').checked = false;\r\n    \r\n    if (id) {\r\n        let v = globalVehicles.find(x => x.id === id);\r\n        if (v) {\r\n            document.getElementById('veh-id').value = v.id;\r\n            document.getElementById('veh-name').value = v.name;\r\n            document.getElementById('veh-generic').checked = (v.isGeneric === true || v.isGeneric === \"true\");\r\n            document.getElementById('veh-plate').value = v.plate || '';\r\n            document.getElementById('veh-model').value = v.model || '';\r\n            document.getElementById('veh-vendor').value = v.vendor || '';\r\n            document.getElementById('veh-l').value = v.l || '';\r\n            document.getElementById('veh-w').value = v.w || '';\r\n            document.getElementById('veh-h').value = v.h || '';\r\n            document.getElementById('veh-kg').value = v.kg || '';\r\n            document.getElementById('veh-vol').value = v.vol || '';\r\n            document.getElementById('veh-lift').value = v.lift || '';\r\n        }\r\n        document.getElementById('veh-modal-title').innerText = \"🚛 Edit Vehicle\";\r\n        document.getElementById('btn-del-veh').style.display = \"block\";\r\n    } else {\r\n        document.getElementById('veh-modal-title').innerText = \"🚛 Provision Vehicle\";\r\n        document.getElementById('btn-del-veh').style.display = \"none\";\r\n    }\r\n    \r\n    toggleGenericVehicle();\r\n    document.getElementById('vehicle-modal-overlay').style.display = 'flex';\r\n}\r\n\r\nfunction toggleGenericVehicle() {\r\n    let isGen = document.getElementById('veh-generic').checked;\r\n    document.getElementById('veh-specific-fields').style.display = isGen ? 'none' : 'flex';\r\n}\r\n\r\nfunction calcVehicleVolume() {\r\n    let l = parseFloat(document.getElementById('veh-l').value) || 0;\r\n    let w = parseFloat(document.getElementById('veh-w').value) || 0;\r\n    let h = parseFloat(document.getElementById('veh-h').value) || 0;\r\n    if (l > 0 && w > 0 && h > 0) {\r\n        document.getElementById('veh-vol').value = (l * w * h).toFixed(2);\r\n    }\r\n}\r\n\r\nfunction saveVehicle() {\r\n    let name = document.getElementById('veh-name').value.trim();\r\n    if (!name) return alert(\"Vehicle name is required.\");\r\n    \r\n    let btn = document.getElementById('btn-save-veh');\r\n    let origText = btn.innerText;\r\n    btn.innerText = \"SAVING...\"; btn.disabled = true;\r\n    \r\n    let payload = {\r\n        id: document.getElementById('veh-id').value,\r\n        name: name,\r\n        isGeneric: document.getElementById('veh-generic').checked,\r\n        plate: document.getElementById('veh-plate').value.trim(),\r\n        model: document.getElementById('veh-model').value.trim(),\r\n        vendor: document.getElementById('veh-vendor').value.trim(),\r\n        l: document.getElementById('veh-l').value,\r\n        w: document.getElementById('veh-w').value,\r\n        h: document.getElementById('veh-h').value,\r\n        kg: document.getElementById('veh-kg').value,\r\n        vol: document.getElementById('veh-vol').value,\r\n        lift: document.getElementById('veh-lift').value\r\n    };\r\n    \r\n    google.script.run.withSuccessHandler(res => {\r\n        btn.innerText = origText; btn.disabled = false;\r\n        document.getElementById('vehicle-modal-overlay').style.display = 'none';\r\n        loadVehicles();\r\n    }).withFailureHandler(err => {\r\n        btn.innerText = origText; btn.disabled = false;\r\n        alert(\"Error: \" + err.message);\r\n    }).saveVehicleVault(payload, ACTIVE_USER_NAME);\r\n}\r\n\r\nfunction deleteVehicle() {\r\n    let id = document.getElementById('veh-id').value;\r\n    if (!id) return;\r\n    if (!confirm(\"Are you sure you want to delete this vehicle?\")) return;\r\n    \r\n    let btn = document.getElementById('btn-del-veh');\r\n    let origText = btn.innerText;\r\n    btn.innerText = \"DELETING...\"; btn.disabled = true;\r\n    \r\n    google.script.run.withSuccessHandler(() => {\r\n        btn.innerText = origText; btn.disabled = false;\r\n        document.getElementById('vehicle-modal-overlay').style.display = 'none';\r\n        loadVehicles();\r\n    }).deleteVehicleVault(id, ACTIVE_USER_NAME);\r\n}\r\n\n\n\r\n/**\r\n * 06e_Admin_Automation.html\r\n * Domain: Drive Automation, Archivers, Universal History, and Tag Dictionary.\r\n */\r\n\r\n// ==========================================\r\n// --- CHECKLIST AUTOMATION LOGIC ---\r\n// ==========================================\r\nfunction openSyncPickerModal() {\r\n    document.getElementById('sync-picker-modal').style.display = 'flex';\r\n    let listContainer = document.getElementById('sp-folder-list');\r\n    listContainer.innerHTML = '<div style=\"color:#555; text-align:center; padding:20px;\">Loading Template Contents...</div>';\r\n    \r\n    let checkAllCb = document.getElementById('sync-check-all');\r\n    if (checkAllCb) checkAllCb.checked = false;\r\n    \r\n    let activeSelection = [];\r\n    try { \r\n        let rawVal = null;\r\n        if (typeof globalManagerConfig !== 'undefined' && globalManagerConfig.syncSelection) {\r\n            rawVal = globalManagerConfig.syncSelection;\r\n        } else {\r\n            let el = document.getElementById('mgr-sync-selection');\r\n            if (el) rawVal = el.value;\r\n        }\r\n        \r\n        if (typeof rawVal === 'string') {\r\n            try { activeSelection = JSON.parse(rawVal || \"[]\"); } catch(e) { activeSelection = []; }\r\n        } else if (Array.isArray(rawVal)) {\r\n            activeSelection = rawVal;\r\n        }\r\n        \r\n        let el = document.getElementById('mgr-sync-selection');\r\n        if (el) el.value = JSON.stringify(activeSelection);\r\n    } catch(e) { activeSelection = []; }\r\n    \r\n    google.script.run.withSuccessHandler(res => {\r\n        let html = '';\r\n        if (!res || res.length === 0) {\r\n            html = '<div style=\"color:#ef4444; text-align:center; padding:20px;\">No template folder configured or it is empty.</div>';\r\n        } else {\r\n            res.forEach(item => {\r\n                let safeName = item.name.replace(/\"/g, '&quot;');\r\n                let isCheckedAttr = '';\r\n                if (Array.isArray(activeSelection)) {\r\n                    let matched = activeSelection.some(s => s === item.name || s === safeName || (typeof s === 'string' && s.replace(/&quot;/g, '\"') === item.name));\r\n                    if (matched) isCheckedAttr = 'checked';\r\n                }\r\n                let icon = item.type === 'folder' ? '📁' : '📄';\r\n                html += `<label style=\"display:flex; align-items:center; gap:10px; cursor:pointer; padding:8px 12px; background:#1a1a1e; border:1px solid #333; border-radius:4px; transition:0.2s;\" onmouseover=\"this.style.background='#222'\" onmouseout=\"this.style.background='#1a1a1e'\"><input type=\"checkbox\" class=\"sync-item-cb\" value=\"${safeName}\" ${isCheckedAttr} style=\"width:16px; height:16px; margin:0;\" onchange=\"document.getElementById('sync-check-all').checked = false;\"><span style=\"color:#fff; font-size:13px; font-weight:bold; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;\">${icon} ${item.name}</span></label>`;\r\n            });\r\n        }\r\n        listContainer.innerHTML = html;\r\n        \r\n        if (checkAllCb) {\r\n            let total = document.querySelectorAll('.sync-item-cb').length;\r\n            let checked = document.querySelectorAll('.sync-item-cb:checked').length;\r\n            checkAllCb.checked = (total > 0 && total === checked);\r\n        }\r\n    }).getTemplateContent(ACTIVE_USER_NAME);\r\n}\r\n\r\nfunction toggleAllSyncItems(isChecked) {\r\n    let checkboxes = document.querySelectorAll('.sync-item-cb');\r\n    checkboxes.forEach(cb => cb.checked = isChecked);\r\n}\r\n\r\nfunction saveSyncSelection() {\r\n    let checkboxes = document.querySelectorAll('.sync-item-cb:checked');\r\n    let newSelection = Array.from(checkboxes).map(cb => cb.value);\r\n    document.getElementById('mgr-sync-selection').value = JSON.stringify(newSelection);\r\n    \r\n    if (typeof globalManagerConfig !== 'undefined') {\r\n        globalManagerConfig.syncSelection = newSelection;\r\n    }\r\n    \r\n    let btn = document.querySelector('#sync-picker-modal .btn-main');\r\n    let originalText = btn ? btn.innerText : \"APPLY & SAVE\";\r\n    if (btn) { btn.innerText = \"SAVING...\"; btn.disabled = true; }\r\n    \r\n    google.script.run.withSuccessHandler(() => {\r\n        if (btn) { btn.innerText = originalText; btn.disabled = false; }\r\n        document.getElementById('sync-picker-modal').style.display = 'none';\r\n        \r\n        // Cascade to the rest of the settings module if it's currently open\r\n        if (typeof submitManagerConfig === 'function') submitManagerConfig(); \r\n    }).withFailureHandler(err => {\r\n        if (btn) { btn.innerText = originalText; btn.disabled = false; }\r\n        alert(\"Failed to save Sync Selection: \" + err.message);\r\n    }).saveManagerConfig(ACTIVE_USER_NAME, globalManagerConfig);\r\n}\r\n\r\nfunction triggerRetroactiveSync(btn) {\r\n    if (!confirm(\"This will scan all existing projects and drop any missing shortcuts into your Google Drive.\\n\\nThis process may take 1-2 minutes depending on the number of projects. Proceed?\")) return;\r\n\r\n    let originalText = btn.innerText;\r\n    btn.innerText = \"SCANNING DRIVE...\";\r\n    btn.disabled = true;\r\n\r\n    google.script.run.withSuccessHandler(res => {\r\n        btn.innerText = originalText;\r\n        btn.disabled = false;\r\n        alert(res);\r\n    }).withFailureHandler(err => {\r\n        btn.innerText = originalText;\r\n        btn.disabled = false;\r\n        alert(\"Sync Failed: \" + err.message);\r\n    }).runRetroactiveDriveSync(ACTIVE_USER_NAME);\r\n}\r\n\r\n// ==========================================\r\n// --- MANAGER HUB LOGIC ---\r\n// ==========================================\r\nlet currentPickerTarget = null;\r\nlet currentPickerFolder = null;\r\nlet currentPickerParent = null;\r\nlet currentRuleRow = null;\r\nlet pickerIncludesFiles = false;\r\n\r\nfunction toggleMgrAccordion(id) {\r\n  const el = document.getElementById(id);\r\n  const icon = document.getElementById(id + '-icon');\r\n  if (el.style.display === 'none' || el.style.display === '') {\r\n      el.style.display = 'flex';\r\n      icon.innerText = '▲';\r\n  } else {\r\n      el.style.display = 'none';\r\n      icon.innerText = '▼';\r\n  }\r\n}\r\n\r\nfunction openManagerSettings() {\r\n  if (typeof closeModals === 'function') {\r\n      if (!closeModals()) return;\r\n  }\r\n  let overlay = document.getElementById('manager-settings-overlay');\r\n  if (!overlay) return;\r\n  overlay.style.display = 'flex';\r\n  if (typeof updateActiveNav === 'function') updateActiveNav('nav-btn-manager');\r\n  if (typeof refreshPersonalHubUI === 'function') refreshPersonalHubUI();\r\n\r\n  const isManager = (typeof accessTierAtLeast === 'function') && accessTierAtLeast('MANAGER');\r\n  if (!isManager) return;\r\n\r\n  const addBtn = document.getElementById('add-rule-btn');\r\n  const addRenameBtn = document.getElementById('add-rename-rule-btn');\r\n  const addAssetBtn = document.getElementById('add-asset-checklist-btn');\r\n  if (addBtn) {\r\n      addBtn.disabled = true;\r\n      addBtn.style.opacity = 0.5;\r\n      addBtn.style.cursor = 'wait';\r\n      if (addRenameBtn) { addRenameBtn.disabled = true; addRenameBtn.style.opacity = 0.5; addRenameBtn.style.cursor = 'wait'; }\r\n      if (addAssetBtn) { addAssetBtn.disabled = true; addAssetBtn.style.opacity = 0.5; addAssetBtn.style.cursor = 'wait'; }\r\n  }\r\n  \r\n  google.script.run.withSuccessHandler(config => {\r\n      globalManagerConfig = config || { rules: [], renameRules: [], syncSelection: [], assetChecklistItems: [] };\r\n      renderRuleRows(globalManagerConfig.rules || []);\r\n      renderRenameRuleRows(globalManagerConfig.renameRules || []);\r\n      renderAssetChecklistRows(globalManagerConfig.assetChecklistItems || []);\r\n      let syncInput = document.getElementById('mgr-sync-selection');\r\n      if (syncInput) syncInput.value = JSON.stringify(globalManagerConfig.syncSelection || []);\r\n\r\n      if (addBtn) {\r\n          addBtn.disabled = false;\r\n          addBtn.style.opacity = 1;\r\n          addBtn.style.cursor = 'pointer';\r\n          if (addRenameBtn) { addRenameBtn.disabled = false; addRenameBtn.style.opacity = 1; addRenameBtn.style.cursor = 'pointer'; }\r\n          if (addAssetBtn) { addAssetBtn.disabled = false; addAssetBtn.style.opacity = 1; addAssetBtn.style.cursor = 'pointer'; }\r\n      }\r\n  }).getManagerConfig(ACTIVE_USER_NAME);\r\n}\r\n\r\nfunction renderRuleRows(rulesArray) {\r\n let html = '';\r\n if (!rulesArray) rulesArray = [];\r\n rulesArray.forEach(r => { html += createRuleRow(r); });\r\n document.getElementById('rule-list').innerHTML = html;\r\n document.querySelectorAll('.rule-row').forEach(syncRuleRowUI);\r\n}\r\n\r\nfunction normalizeRuleTaskType(rule) {\r\n let t = (rule && rule.taskType) ? String(rule.taskType).toLowerCase() : '';\r\n if (t === 'basic' || t === 'automated') return t;\r\n return 'automated';\r\n}\r\n\r\nfunction syncRuleRowUI(row) {\r\n if (!row) return;\r\n let typeEl = row.querySelector('.rule-task-type');\r\n let type = typeEl ? typeEl.value : 'automated';\r\n let autoBlock = row.querySelector('.rule-automated-fields');\r\n if (autoBlock) autoBlock.style.display = (type === 'basic') ? 'none' : 'flex';\r\n\r\n let typeLabel = row.querySelector('.rule-row-type-label');\r\n if (typeLabel) typeLabel.innerText = (type === 'basic') ? 'MANUAL TASK' : 'AUTOMATED TASK';\r\n\r\n let remCb = row.querySelector('.rule-reminder-enabled');\r\n let remDays = row.querySelector('.rule-reminder-days');\r\n if (remCb && remDays) {\r\n     remDays.disabled = !remCb.checked;\r\n     remDays.style.opacity = remCb.checked ? '1' : '0.45';\r\n }\r\n}\r\n\r\nfunction createRuleRow(r) {\r\n let taskType = normalizeRuleTaskType(r);\r\n let reminderEnabled = !!(r && (r.reminderEnabled === true || r.reminderEnabled === 'true'));\r\n let reminderDays = (r && r.reminderDaysBefore) ? parseInt(r.reminderDaysBefore, 10) : 5;\r\n if (!reminderDays || reminderDays < 1) reminderDays = 5;\r\n return `\r\n <div class=\"rule-row\" style=\"display:flex; flex-direction:column; gap:10px; background:#222; padding:12px; border-radius:6px; border: 1px solid #333;\">\r\n    <div style=\"display:flex; justify-content:space-between; align-items:center;\">\r\n        <div class=\"rule-row-type-label\" style=\"font-size:11px; font-weight:800; color:#f97316; text-transform:uppercase;\">${taskType === 'basic' ? 'MANUAL TASK' : 'AUTOMATED TASK'}</div>\r\n        <button class=\"btn-delete\" style=\"width:auto; margin:0; padding:4px 8px; height:auto; font-size:10px;\" onclick=\"this.closest('.rule-row').remove()\" title=\"Delete Rule\">X</button>\r\n    </div>\r\n\r\n    <div style=\"display:flex; gap:10px; align-items:flex-end; flex-wrap:wrap;\">\r\n        <div style=\"flex:2; min-width:140px;\">\r\n            <div class=\"input-label\" style=\"margin-bottom:2px;\">Task Name</div>\r\n            <input type=\"text\" class=\"rule-task input-compact\" placeholder=\"e.g. Rider\" value=\"${String(r.taskName || r.word || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; box-sizing:border-box;\">\r\n        </div>\r\n        <div style=\"flex:1; min-width:130px;\">\r\n            <div class=\"input-label\" style=\"margin-bottom:2px;\">Task Type</div>\r\n            <select class=\"rule-task-type input-compact\" onchange=\"syncRuleRowUI(this.closest('.rule-row'))\" style=\"width:100%; box-sizing:border-box; height:32px;\">\r\n                <option value=\"basic\" ${taskType === 'basic' ? 'selected' : ''}>Manual checkbox</option>\r\n                <option value=\"automated\" ${taskType === 'automated' ? 'selected' : ''}>Automated files</option>\r\n            </select>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"rule-automated-fields\" style=\"display:${taskType === 'basic' ? 'none' : 'flex'}; flex-direction:column; gap:10px;\">\r\n        <div style=\"display:flex; gap:10px; align-items:center; flex-wrap:wrap;\">\r\n            <div style=\"flex:1; min-width:120px;\">\r\n                <div class=\"input-label\" style=\"margin-bottom:2px;\">Source (Template)</div>\r\n                <div style=\"display:flex; gap:5px;\">\r\n                   <input type=\"text\" class=\"rule-src-name input-compact\" disabled placeholder=\"Event Root\" value=\"${String(r.srcFolderName || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; cursor:not-allowed; opacity:0.8; box-sizing:border-box;\">\r\n                   <button class=\"btn-outline btn-sm\" style=\"width:auto; margin:0;\" onclick=\"openSharedDrivePicker('rule-src', this)\" title=\"Browse\">📁</button>\r\n                </div>\r\n            </div>\r\n            <div style=\"flex:1.5; min-width:140px;\">\r\n                <div class=\"input-label\" style=\"margin-bottom:2px;\">Search Contains</div>\r\n                <input type=\"text\" class=\"rule-search input-compact\" placeholder=\"Tech Rider\" value=\"${String(r.searchString || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; box-sizing:border-box;\">\r\n            </div>\r\n        </div>\r\n        <div style=\"display:flex; gap:10px; align-items:center; flex-wrap:wrap;\">\r\n            <div style=\"flex:1; min-width:100px;\">\r\n                <div class=\"input-label\" style=\"margin-bottom:2px;\">Append Suffix</div>\r\n                <input type=\"text\" class=\"rule-suffix input-compact\" placeholder=\"_FINAL\" value=\"${String(r.suffix || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; box-sizing:border-box;\">\r\n            </div>\r\n            <div style=\"flex:2; min-width:140px;\">\r\n                <div class=\"input-label\" style=\"margin-bottom:2px;\">Destination (Template)</div>\r\n                <div style=\"display:flex; gap:5px;\">\r\n                   <input type=\"text\" class=\"rule-dest-name input-compact\" disabled placeholder=\"Event Root\" value=\"${String(r.destFolderName || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; cursor:not-allowed; opacity:0.8; box-sizing:border-box;\">\r\n                   <button class=\"btn-outline btn-sm\" style=\"width:auto; margin:0;\" onclick=\"openSharedDrivePicker('rule-dest', this)\" title=\"Browse\">📁</button>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"rule-reminder-row\" style=\"display:flex; align-items:center; gap:12px; flex-wrap:wrap; padding-top:8px; border-top:1px solid #333;\">\r\n        <label style=\"display:flex; align-items:center; gap:8px; cursor:pointer; margin:0;\">\r\n            <input type=\"checkbox\" class=\"rule-reminder-enabled\" ${reminderEnabled ? 'checked' : ''} onchange=\"syncRuleRowUI(this.closest('.rule-row'))\" style=\"width:16px; height:16px; margin:0;\">\r\n            <span style=\"color:#e4e4e7; font-size:12px; font-weight:700;\">Remind if not done</span>\r\n        </label>\r\n        <div style=\"display:flex; align-items:center; gap:8px;\">\r\n            <input type=\"number\" class=\"rule-reminder-days input-compact\" min=\"1\" max=\"365\" value=\"${reminderDays}\" ${reminderEnabled ? '' : 'disabled'} style=\"width:64px; box-sizing:border-box; opacity:${reminderEnabled ? '1' : '0.45'};\">\r\n            <span style=\"color:#71717a; font-size:11px; font-weight:700; text-transform:uppercase;\">days before event</span>\r\n        </div>\r\n    </div>\r\n </div>`;\r\n}\r\n\r\nfunction addRuleRow() {\r\n document.getElementById('rule-list').insertAdjacentHTML('beforeend', createRuleRow({ taskType: 'basic' }));\r\n let rows = document.querySelectorAll('.rule-row');\r\n syncRuleRowUI(rows[rows.length - 1]);\r\n}\r\n\r\nfunction renderRenameRuleRows(rulesArray) {\r\n let html = '';\r\n if (!rulesArray) rulesArray = [];\r\n rulesArray.forEach(r => { html += createRenameRuleRow(r); });\r\n document.getElementById('rename-rule-list').innerHTML = html;\r\n}\r\n\r\nfunction createRenameRuleRow(r) {\r\n return `\r\n <div class=\"rename-row\" style=\"display:flex; flex-direction:column; gap:10px; background:#222; padding:12px; border-radius:6px; border: 1px solid #333;\">\r\n    <div style=\"display:flex; justify-content:space-between; align-items:center;\">\r\n        <div style=\"font-size:11px; font-weight:800; color:#10b981;\">RENAME RULE</div>\r\n        <button class=\"btn-delete\" style=\"width:auto; margin:0; padding:4px 8px; height:auto; font-size:10px;\" onclick=\"this.closest('.rename-row').remove()\" title=\"Delete Rule\">X</button>\r\n    </div>\r\n    <div style=\"display:flex; flex-wrap:nowrap; gap:10px; align-items:flex-end;\">\r\n        <div style=\"flex:2; min-width:120px;\">\r\n            <div style=\"font-size:9px; color:#888; margin-bottom:2px; text-transform:uppercase; font-weight:bold;\">File to Rename</div>\r\n            <input type=\"hidden\" class=\"rename-file-id\" value=\"${String(r.fileId || '').replace(/\"/g, '&quot;')}\">\r\n            <div style=\"display:flex; gap:5px;\">\r\n               <input type=\"text\" class=\"rename-file-name\" disabled placeholder=\"Select File\" value=\"${String(r.originalName || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; cursor:not-allowed; opacity:0.8; padding:6px; height: 30px; box-sizing:border-box; font-size:11px;\">\r\n               <button class=\"btn-outline\" style=\"border-color:#10b981; color:#10b981; width:auto; margin:0; padding:6px 10px; height: 30px;\" onclick=\"openSharedDrivePicker('rename-file', this)\" title=\"Browse\">📄</button>\r\n            </div>\r\n        </div>\r\n\r\n        <div style=\"flex:1; min-width:80px;\">\r\n            <div style=\"font-size:9px; color:#888; margin-bottom:2px; text-transform:uppercase; font-weight:bold;\">Prefix</div>\r\n            <input type=\"text\" class=\"rename-prefix\" placeholder=\"BUDGET\" value=\"${String(r.prefix || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; padding:6px; height:30px; box-sizing:border-box; font-size:11px;\">\r\n        </div>\r\n\r\n        <div style=\"flex:1; min-width:80px;\">\r\n            <div style=\"font-size:9px; color:#888; margin-bottom:2px; text-transform:uppercase; font-weight:bold;\">Suffix</div>\r\n            <input type=\"text\" class=\"rename-suffix\" placeholder=\"V1\" value=\"${String(r.suffix || '').replace(/\"/g, '&quot;')}\" style=\"width:100%; padding:6px; height:30px; box-sizing:border-box; font-size:11px;\">\r\n        </div>\r\n    </div>\r\n </div>`;\r\n}\r\n\r\nfunction addRenameRuleRow() {\r\n document.getElementById('rename-rule-list').insertAdjacentHTML('beforeend', createRenameRuleRow({}));\r\n}\r\n\r\nfunction renderAssetChecklistRows(itemsArray) {\r\n let html = '';\r\n if (!itemsArray) itemsArray = [];\r\n itemsArray.forEach(item => {\r\n     let name = (typeof item === 'string') ? item : (item && item.name ? item.name : '');\r\n     if (name) html += createAssetChecklistRow({ name: name });\r\n });\r\n document.getElementById('asset-checklist-list').innerHTML = html;\r\n}\r\n\r\nfunction createAssetChecklistRow(r) {\r\n return `\r\n <div class=\"asset-checklist-row\" style=\"display:flex; gap:10px; align-items:center; background:#222; padding:10px 12px; border-radius:6px; border:1px solid #333;\">\r\n    <input type=\"text\" class=\"asset-checklist-name input-compact\" placeholder=\"e.g. Distro box\" value=\"${String(r.name || '').replace(/\"/g, '&quot;')}\" style=\"flex:1; box-sizing:border-box;\">\r\n    <button class=\"btn-delete\" style=\"width:auto; margin:0; padding:4px 8px; height:auto; font-size:10px; flex-shrink:0;\" onclick=\"this.closest('.asset-checklist-row').remove()\" title=\"Delete Item\">X</button>\r\n </div>`;\r\n}\r\n\r\nfunction addAssetChecklistRow() {\r\n document.getElementById('asset-checklist-list').insertAdjacentHTML('beforeend', createAssetChecklistRow({}));\r\n}\r\n\r\n// @INDEX: AUTOMATION -> Save Manager Rules\r\nfunction submitManagerConfig() {\r\n  const btn = document.getElementById('btn-save-mgr');\r\n  btn.innerText = \"SAVING...\"; btn.disabled = true;\r\n  \r\n  let rules = [];\r\n  let taskNames = new Set();\r\n  let searchCombos = new Set();\r\n  let hasError = false;\r\n  \r\n  document.querySelectorAll('.rule-row').forEach(row => {\r\n     let taskName = row.querySelector('.rule-task').value.trim();\r\n     if (taskName) {\r\n         if (taskNames.has(taskName.toLowerCase())) {\r\n             alert(\"Validation Error: Multiple Automation Tasks have the exact same name ('\" + taskName + \"'). Task names must be unique.\");\r\n             hasError = true;\r\n         }\r\n         taskNames.add(taskName.toLowerCase());\r\n\r\n         let taskType = row.querySelector('.rule-task-type').value || 'automated';\r\n         let searchStr = row.querySelector('.rule-search').value.trim();\r\n         let srcFolder = row.querySelector('.rule-src-name').value.trim();\r\n         if (taskType === 'automated') {\r\n             let comboKey = (srcFolder + \"|||\" + searchStr).toLowerCase();\r\n             if (searchStr && searchCombos.has(comboKey)) {\r\n                 alert(\"Validation Error: Multiple rules are searching for the exact same keyword ('\" + searchStr + \"') in the exact same source folder. This overlap will cause conflicting file duplications.\");\r\n                 hasError = true;\r\n             }\r\n             if (searchStr) searchCombos.add(comboKey);\r\n         }\r\n\r\n         let reminderEnabled = row.querySelector('.rule-reminder-enabled').checked;\r\n         let reminderDays = parseInt(row.querySelector('.rule-reminder-days').value, 10) || 0;\r\n         if (reminderEnabled && reminderDays < 1) {\r\n             alert(\"Validation Error: Reminder days must be at least 1 for task '\" + taskName + \"'.\");\r\n             hasError = true;\r\n         }\r\n\r\n         rules.push({\r\n             taskName: taskName,\r\n             taskType: taskType,\r\n             srcFolderName: srcFolder,\r\n             searchString: searchStr,\r\n             suffix: row.querySelector('.rule-suffix').value.trim(),\r\n             destFolderName: row.querySelector('.rule-dest-name').value.trim(),\r\n             reminderEnabled: reminderEnabled,\r\n             reminderDaysBefore: reminderEnabled ? reminderDays : 0\r\n         });\r\n     }\r\n  });\r\n  \r\n  if (hasError) {\r\n      btn.innerText = \"SAVE CONFIGURATION\"; btn.disabled = false;\r\n      return;\r\n  }\r\n\r\n  let renameRules = [];\r\n  let originalNames = new Set();\r\n  \r\n  document.querySelectorAll('.rename-row').forEach(row => {\r\n     let originalName = row.querySelector('.rename-file-name').value.trim();\r\n     let fileId = row.querySelector('.rename-file-id').value.trim();\r\n     if (originalName) {\r\n         if (originalNames.has(originalName.toLowerCase())) {\r\n             alert(\"Validation Error: Multiple Rename Rules are targeting the exact same file ('\" + originalName + \"'). Each file can only have one active rename rule.\");\r\n             hasError = true;\r\n         }\r\n         originalNames.add(originalName.toLowerCase());\r\n         renameRules.push({\r\n             fileId: fileId,\r\n             originalName: originalName,\r\n             prefix: row.querySelector('.rename-prefix').value.trim(),\r\n             suffix: row.querySelector('.rename-suffix').value.trim()\r\n         });\r\n     }\r\n  });\r\n  \r\n  if (hasError) {\r\n      btn.innerText = \"SAVE CONFIGURATION\"; btn.disabled = false;\r\n      return;\r\n  }\r\n\r\n  let assetChecklistItems = [];\r\n  let assetNames = new Set();\r\n\r\n  document.querySelectorAll('.asset-checklist-row').forEach(row => {\r\n     let itemName = row.querySelector('.asset-checklist-name').value.trim();\r\n     if (itemName) {\r\n         if (assetNames.has(itemName.toLowerCase())) {\r\n             alert(\"Validation Error: Multiple asset reminder items have the same name ('\" + itemName + \"'). Each item must be unique.\");\r\n             hasError = true;\r\n         }\r\n         assetNames.add(itemName.toLowerCase());\r\n         assetChecklistItems.push({ name: itemName });\r\n     }\r\n  });\r\n\r\n  if (hasError) {\r\n      btn.innerText = \"SAVE CONFIGURATION\"; btn.disabled = false;\r\n      return;\r\n  }\r\n\r\n  let parsedSyncSelection = [];\r\n  try {\r\n      parsedSyncSelection = JSON.parse(document.getElementById('mgr-sync-selection').value || \"[]\");\r\n  } catch (e) {\r\n      alert(\"Configuration Error: Failed to read sync selection rules. Settings may be corrupted.\");\r\n      btn.innerText = \"SAVE CONFIGURATION\"; btn.disabled = false;\r\n      return;\r\n  }\r\n\r\n  // FIX: Safely mutate existing config so we do not erase other properties like templateFolder\r\n  if (typeof globalManagerConfig === 'undefined' || !globalManagerConfig) {\r\n      globalManagerConfig = {};\r\n  }\r\n  globalManagerConfig.rules = rules;\r\n  globalManagerConfig.renameRules = renameRules;\r\n  globalManagerConfig.syncSelection = parsedSyncSelection;\r\n  globalManagerConfig.assetChecklistItems = assetChecklistItems;\r\n  \r\n  google.script.run\r\n      .withFailureHandler(err => {\r\n          if (err.message.includes(\"COLLISION_DETECTED\")) {\r\n              alert(\"🛑 \" + err.message);\r\n          } else {\r\n              alert(\"Save Failed: \" + err.message);\r\n          }\r\n          btn.innerText = \"SAVE CONFIGURATION\"; btn.disabled = false;\r\n      })\r\n      .withSuccessHandler(res => {\r\n          btn.innerText = \"SAVE CONFIGURATION\"; btn.disabled = false; \r\n          alert(res);\r\n          openManagerSettings(); // Re-fetch to update local timestamp secretly\r\n      })\r\n      .saveManagerConfig(ACTIVE_USER_NAME, globalManagerConfig);\r\n}\r\n\r\nfunction openSharedDrivePicker(target, btnEl) {\r\n  currentPickerTarget = target;\r\n  if (target.startsWith('rule')) currentRuleRow = btnEl.closest('.rule-row');\r\n  if (target === 'rename-file') currentRuleRow = btnEl.closest('.rename-row');\r\n  \r\n  pickerIncludesFiles = (target === 'rename-file');\r\n\r\n  document.getElementById('drive-picker-modal').style.display = 'flex';\r\n  document.getElementById('dp-folder-list').innerHTML = '<div style=\"color:#888; text-align:center; padding:20px; font-size:12px;\">Connecting to System...</div>';\r\n  document.getElementById('dp-current-path').innerText = 'Loading...';\r\n  document.getElementById('dp-select-btn').disabled = true;\r\n  document.getElementById('dp-back-btn').disabled = true;\r\n  \r\n  // Default strictly to the child template folder ID when searching for rules/rename files\r\n  let startFolderId = '19J-3qT7ABLIRK7Si1xfp_KEPRQYcbKbe';\r\n  \r\n  loadSharedDriveFolder(startFolderId);\r\n}\r\n\r\nfunction loadSharedDriveFolder(folderId) {\r\n  document.getElementById('dp-folder-list').innerHTML = '<div style=\"color:#888; text-align:center; padding:20px; font-size:12px;\">Fetching Folders...</div>';\r\n  document.getElementById('dp-select-btn').disabled = true;\r\n  google.script.run.withSuccessHandler(renderSharedDrivePicker).withFailureHandler(err => {\r\n      if (folderId !== 'root') loadSharedDriveFolder('root');\r\n      else document.getElementById('dp-folder-list').innerHTML = `<div style=\"color:#ef4444; text-align:center; padding:20px; font-size:12px;\">Error: ${err.message}</div>`;\r\n  }).getHostDriveDirectory(ACTIVE_USER_NAME, folderId, pickerIncludesFiles);\r\n}\r\n\r\nfunction renderSharedDrivePicker(data) {\r\n  currentPickerFolder = data.current;\r\n  currentPickerParent = data.parent;\r\n  \r\n  document.getElementById('dp-current-path').innerText = data.current.name;\r\n  document.getElementById('dp-back-btn').disabled = (data.parent === null);\r\n  \r\n  if (currentPickerTarget === 'rename-file') {\r\n      document.getElementById('dp-select-btn').disabled = true;\r\n      document.getElementById('dp-select-btn').innerText = 'CLICK A FILE TO SELECT';\r\n  } else {\r\n      document.getElementById('dp-select-btn').disabled = (data.current.id === 'root');\r\n      let templateFolderId = '19J-3qT7ABLIRK7Si1xfp_KEPRQYcbKbe';\r\n      let isTemplateRoot = ((currentPickerTarget === 'rule-src' || currentPickerTarget === 'rule-dest') && data.current.id === templateFolderId);\r\n      document.getElementById('dp-select-btn').innerText = data.current.id === 'root' ? 'BROWSE A FOLDER' : (isTemplateRoot ? 'SELECT EVENT ROOT' : `SELECT \"${data.current.name.toUpperCase()}\"`);\r\n  }\r\n  \r\n  if (data.subfolders.length === 0) {\r\n      document.getElementById('dp-folder-list').innerHTML = '<div style=\"color:#555; text-align:center; padding:20px; font-size:12px;\">This folder is empty.</div>';\r\n  } else {\r\n      document.getElementById('dp-folder-list').innerHTML = data.subfolders.map(f => `\r\n          <div class=\"dp-folder-item\" onclick=\"${f.isFile ? `selectFileFromPicker('${f.id}', '${f.name.replace(/'/g, \"\\\\'\")}')` : `loadSharedDriveFolder('${f.id}')`}\"><span class=\"dp-folder-icon\">${f.isFile ? '📄' : '📁'}</span><span style=\"white-space:nowrap; overflow:hidden; text-overflow:ellipsis;\">${f.name}</span></div>\r\n      `).join('');\r\n  }\r\n}\r\n\r\nfunction navigateSharedDriveUp() {\r\n  if (currentPickerParent) loadSharedDriveFolder(currentPickerParent.id);\r\n}\r\n\r\nfunction selectFileFromPicker(id, name) {\r\n  if (currentPickerTarget === 'rename-file' && currentRuleRow) {\r\n      currentRuleRow.querySelector('.rename-file-id').value = id;\r\n      currentRuleRow.querySelector('.rename-file-name').value = name;\r\n      document.getElementById('drive-picker-modal').style.display = 'none';\r\n  }\r\n}\r\n\r\nfunction confirmSharedDriveSelection() {\r\n  if (!currentPickerFolder) return;\r\n  \r\n  let templateFolderId = '19J-3qT7ABLIRK7Si1xfp_KEPRQYcbKbe';\r\n\r\n  if (currentPickerTarget === 'rule-src' && currentRuleRow) {\r\n      if (currentPickerFolder.id === templateFolderId || currentPickerFolder.id === 'root') {\r\n          currentRuleRow.querySelector('.rule-src-name').value = ''; \r\n      } else {\r\n          currentRuleRow.querySelector('.rule-src-name').value = currentPickerFolder.name;\r\n      }\r\n  } else if (currentPickerTarget === 'rule-dest' && currentRuleRow) {\r\n      if (currentPickerFolder.id === templateFolderId || currentPickerFolder.id === 'root') {\r\n          currentRuleRow.querySelector('.rule-dest-name').value = ''; \r\n      } else {\r\n          currentRuleRow.querySelector('.rule-dest-name').value = currentPickerFolder.name;\r\n      }\r\n  }\r\n  \r\n  document.getElementById('drive-picker-modal').style.display = 'none';\r\n}\r\n\r\n// ==========================================\r\n// --- INFINITE TAG DICTIONARY BUILDER ---\r\n// ==========================================\r\n\r\nfunction openTagManager() {\r\n    document.getElementById('master-settings-overlay').style.display = 'none';\r\n    mapAliasesToTags(SYSTEM_TAGS);\r\n    renderTagTree();\r\n    document.getElementById('tag-manager-modal').style.display = 'flex';\r\n}\r\n\r\nfunction getShortcutForTag(tagName) {\r\n    if (!tagName) return '';\r\n    let lowerTag = tagName.trim().toLowerCase();\r\n    for (let [code, trans] of Object.entries(SYSTEM_ALIASES)) {\r\n        if (trans.trim().toLowerCase() === lowerTag) return code;\r\n    }\r\n    return '';\r\n}\r\n\r\nfunction mapAliasesToTags(nodes) {\r\n    if (!nodes) return;\r\n    nodes.forEach(n => {\r\n        n.shortcut = getShortcutForTag(n.name);\r\n        if (n.children) mapAliasesToTags(n.children);\r\n    });\r\n}\r\n\r\nfunction renderTagTree() {\r\n    let html = `<div id=\"tag-root-dropzone\" ondragover=\"handleTagDragOver(event)\" ondragenter=\"handleTagDragEnter(event)\" ondragleave=\"handleTagDragLeave(event)\" ondrop=\"handleTagDrop(event, 'root')\" style=\"padding:15px; border:2px dashed #333; text-align:center; color:#888; border-radius:6px; margin-bottom:10px; transition:0.2s;\">Drop here to move to Root Level</div>`;\r\n    html += buildTagTreeHTML(SYSTEM_TAGS, 0);\r\n    document.getElementById('tag-tree-container').innerHTML = html;\r\n}\r\n\r\nfunction buildTagTreeHTML(nodes, depth) {\r\n    if (!nodes || nodes.length === 0) return '';\r\n    let html = '';\r\n    nodes.forEach(node => {\r\n        let padding = depth * 20;\r\n        let hasChildren = node.children && node.children.length > 0;\r\n        let toggleIcon = hasChildren ? (node.expanded ? '▼' : '▶') : '<span style=\"opacity:0.2;\">●</span>';\r\n        \r\n        html += `\r\n        <div style=\"display:flex; flex-direction:column; margin-bottom: 4px;\">\r\n            <div id=\"tag-node-${node.id}\" draggable=\"true\" ondragstart=\"handleTagDragStart(event, '${node.id}')\" ondragover=\"handleTagDragOver(event)\" ondragenter=\"handleTagDragEnter(event)\" ondragleave=\"handleTagDragLeave(event)\" ondrop=\"handleTagDrop(event, '${node.id}')\" ondragend=\"handleTagDragEnd(event)\" style=\"display:flex; align-items:center; gap:6px; padding: 4px 6px 4px ${padding + 6}px; border-radius: 4px; border: 1px solid transparent; transition: 0.2s;\">\r\n                <span style=\"color:#a855f7; font-size:10px; cursor:pointer; width:16px; text-align:center;\" onclick=\"toggleTagNode('${node.id}')\">${toggleIcon}</span>\r\n                <span style=\"cursor:grab; color:#555; padding:0 4px;\" title=\"Drag to move\">⋮⋮</span>\r\n                <input type=\"color\" value=\"${node.color || '#a855f7'}\" oninput=\"updateTagColor('${node.id}', this.value)\" style=\"width:25px; height:25px; padding:0; border:1px solid #333; border-radius:4px; background:transparent; cursor:pointer; flex-shrink:0;\">\r\n                <input type=\"text\" value=\"${(node.name || '').replace(/\"/g, '&quot;')}\" oninput=\"updateTagName('${node.id}', this.value)\" placeholder=\"Tag Name...\" style=\"flex:1; padding:6px 10px; font-size:12px; background:#18181b; color:#fff; border:1px solid #333; border-radius:4px;\">\r\n                <input type=\"text\" value=\"${(node.shortcut || '').replace(/\"/g, '&quot;')}\" oninput=\"updateTagShortcut('${node.id}', this.value)\" placeholder=\"Shortcut (e.g. s)\" style=\"width:120px; padding:6px 10px; font-size:12px; background:#111; color:#10b981; border:1px solid #10b981; border-radius:4px; text-align:center;\">\r\n                <label style=\"display:flex; align-items:center; gap:4px; margin: 0 4px; padding: 4px 8px; background: #111; border: 1px solid #333; border-radius: 4px; cursor:pointer;\" title=\"Include assets with this tag in mathematical formula strings\"><input type=\"checkbox\" ${node.inFormula ? 'checked' : ''} onchange=\"updateTagFormula('${node.id}', this.checked)\" style=\"margin:0; width:12px; height:12px; accent-color:#3b82f6;\"><span style=\"font-size:10px; color:#a1a1aa; font-weight:bold;\">∑ MATH</span></label>\r\n                <button class=\"btn-outline btn-sm\" style=\"padding:6px 10px !important; margin:0; border-color:#10b981; color:#10b981;\" onclick=\"addTagNode('${node.id}')\" title=\"Add Sub-Tag\">+ SUB</button>\r\n                <button class=\"btn-delete btn-sm\" style=\"padding:6px 10px !important; margin:0;\" onclick=\"deleteTagNode('${node.id}')\" title=\"Delete\">X</button>\r\n            </div>\r\n            <div style=\"display:${node.expanded ? 'block' : 'none'}; margin-top:4px;\">\r\n                ${buildTagTreeHTML(node.children, depth + 1)}\r\n            </div>\r\n        </div>`;\r\n    });\r\n    return html;\r\n}\r\n\r\nfunction findTagNode(nodes, id) {\r\n    for (let i=0; i<nodes.length; i++) {\r\n        if (nodes[i].id === id) return nodes[i];\r\n        if (nodes[i].children) { let f = findTagNode(nodes[i].children, id); if (f) return f; }\r\n    }\r\n    return null;\r\n}\r\n\r\nfunction removeTagNode(nodes, id) {\r\n    for (let i=0; i<nodes.length; i++) {\r\n        if (nodes[i].id === id) { nodes.splice(i, 1); return true; }\r\n        if (nodes[i].children && removeTagNode(nodes[i].children, id)) return true;\r\n    }\r\n    return false;\r\n}\r\n\r\nfunction toggleTagNode(id) { let n = findTagNode(SYSTEM_TAGS, id); if (n) { n.expanded = !n.expanded; renderTagTree(); } }\r\nfunction updateTagName(id, val) { let n = findTagNode(SYSTEM_TAGS, id); if (n) n.name = val; }\r\nfunction updateTagColor(id, val) { let n = findTagNode(SYSTEM_TAGS, id); if (n) n.color = val; }\r\nfunction updateTagShortcut(id, val) { let n = findTagNode(SYSTEM_TAGS, id); if (n) n.shortcut = val; }\r\nfunction updateTagFormula(id, val) { let n = findTagNode(SYSTEM_TAGS, id); if (n) n.inFormula = val; }\r\n\r\nfunction addTagNode(parentId) {\r\n    let newNode = { id: 'tag_' + Date.now() + Math.floor(Math.random()*1000), name: '', color: '#a855f7', shortcut: '', children: [], expanded: true, inFormula: false };\r\n    if (parentId) {\r\n        let parent = findTagNode(SYSTEM_TAGS, parentId);\r\n        if (parent) {\r\n            if (!parent.children) parent.children = [];\r\n            parent.children.push(newNode);\r\n            parent.expanded = true;\r\n        }\r\n    } else { SYSTEM_TAGS.push(newNode); }\r\n    renderTagTree();\r\n}\r\n\r\nfunction deleteTagNode(id) { if (confirm(\"Delete this tag and all its nested sub-tags?\")) { removeTagNode(SYSTEM_TAGS, id); renderTagTree(); } }\r\n\r\nfunction saveTagManager() {\r\n    let newAliases = {};\r\n    let duplicates = new Set();\r\n    let warnings = [];\r\n\r\n    const extractAliases = (nodes) => {\r\n        nodes.forEach(n => {\r\n            let code = (n.shortcut || '').trim().toLowerCase();\r\n            let trans = (n.name || '').trim().toLowerCase();\r\n            if (code && trans) {\r\n                if (newAliases[code] && newAliases[code] !== trans) {\r\n                    duplicates.add(code);\r\n                } else {\r\n                    newAliases[code] = trans;\r\n                }\r\n            }\r\n            if (n.children) extractAliases(n.children);\r\n        });\r\n    };\r\n    \r\n    extractAliases(SYSTEM_TAGS);\r\n\r\n    if (duplicates.size > 0) {\r\n        duplicates.forEach(dupCode => {\r\n            delete newAliases[dupCode];\r\n            warnings.push(dupCode);\r\n        });\r\n        alert(\"⚠️ Duplicate Shortcuts Detected:\\nThe code(s) [\" + warnings.join(', ') + \"] were assigned to multiple different tags. They have been skipped.\\n\\nAll other tags and unique shortcuts were saved successfully.\");\r\n    }\r\n\r\n    SYSTEM_ALIASES = newAliases;\r\n\r\n    document.getElementById('tag-manager-modal').style.display = 'none';\r\n    openMasterSettings('assets');\r\n    \r\n    google.script.run.saveSystemTags(SYSTEM_TAGS);\r\n    google.script.run.saveVaultAsset('syntax_aliases', SYSTEM_ALIASES);\r\n}\r\n\r\nfunction cancelTagManager() { document.getElementById('tag-manager-modal').style.display = 'none'; openMasterSettings('assets'); }\r\n\r\n// ==========================================\r\n// --- DRAG AND DROP TAG DICTIONARY ENGINE ---\r\n// ==========================================\r\nlet draggedTagId = null;\r\n\r\nfunction handleTagDragStart(e, id) {\r\n    draggedTagId = id;\r\n    e.dataTransfer.effectAllowed = 'move';\r\n    e.dataTransfer.setData('text/plain', id);\r\n    setTimeout(() => { e.target.style.opacity = '0.4'; }, 0);\r\n    e.stopPropagation();\r\n}\r\n\r\nfunction handleTagDragOver(e) {\r\n    e.preventDefault();\r\n    e.dataTransfer.dropEffect = 'move';\r\n    return false;\r\n}\r\n\r\nfunction handleTagDragEnter(e) {\r\n    e.preventDefault();\r\n    let target = e.currentTarget;\r\n    if (target.id === 'tag-root-dropzone') {\r\n        target.style.borderColor = '#a855f7';\r\n        target.style.background = 'rgba(168, 85, 247, 0.1)';\r\n    } else {\r\n        target.style.background = 'rgba(255,255,255,0.1)';\r\n    }\r\n    e.stopPropagation();\r\n}\r\n\r\nfunction handleTagDragLeave(e) {\r\n    let target = e.currentTarget;\r\n    if (target.id === 'tag-root-dropzone') {\r\n        target.style.borderColor = '#333';\r\n        target.style.background = 'transparent';\r\n    } else {\r\n        target.style.background = 'transparent';\r\n    }\r\n    e.stopPropagation();\r\n}\r\n\r\nfunction handleTagDrop(e, targetId) {\r\n    e.stopPropagation();\r\n    e.preventDefault();\r\n    let target = e.currentTarget;\r\n    \r\n    if (target.id === 'tag-root-dropzone') {\r\n        target.style.borderColor = '#333';\r\n        target.style.background = 'transparent';\r\n    } else {\r\n        target.style.background = 'transparent';\r\n    }\r\n\r\n    if (!draggedTagId || draggedTagId === targetId) { draggedTagId = null; return false; }\r\n\r\n    if (isTagDescendant(SYSTEM_TAGS, draggedTagId, targetId)) {\r\n        alert(\"Cannot move a parent tag into its own child category.\");\r\n        draggedTagId = null;\r\n        return false;\r\n    }\r\n\r\n    let nodeToMove = null;\r\n    const extractNode = (nodes) => {\r\n        for (let i = 0; i < nodes.length; i++) {\r\n            if (nodes[i].id === draggedTagId) { nodeToMove = nodes.splice(i, 1)[0]; return true; }\r\n            if (nodes[i].children && extractNode(nodes[i].children)) return true;\r\n        }\r\n        return false;\r\n    };\r\n    extractNode(SYSTEM_TAGS);\r\n\r\n    if (nodeToMove) {\r\n        if (targetId === 'root') { SYSTEM_TAGS.push(nodeToMove); } \r\n        else {\r\n            let targetNode = findTagNode(SYSTEM_TAGS, targetId);\r\n            if (targetNode) {\r\n                if (!targetNode.children) targetNode.children = [];\r\n                targetNode.children.push(nodeToMove);\r\n                targetNode.expanded = true;\r\n            } else { SYSTEM_TAGS.push(nodeToMove); }\r\n        }\r\n    }\r\n\r\n    draggedTagId = null;\r\n    renderTagTree();\r\n    return false;\r\n}\r\n\r\nfunction handleTagDragEnd(e) {\r\n    e.target.style.opacity = '1';\r\n    document.querySelectorAll('[id^=\"tag-node-\"]').forEach(el => el.style.background = 'transparent');\r\n    let rootDrop = document.getElementById('tag-root-dropzone');\r\n    if (rootDrop) { rootDrop.style.borderColor = '#333'; rootDrop.style.background = 'transparent'; }\r\n    draggedTagId = null;\r\n    e.stopPropagation();\r\n}\r\n\r\nfunction isTagDescendant(nodes, parentId, targetId) {\r\n    let parentNode = findTagNode(nodes, parentId);\r\n    if (!parentNode || !parentNode.children) return false;\r\n    return findTagNode(parentNode.children, targetId) !== null;\r\n}\r\n\r\n// ==========================================\r\n// --- CHECKLIST AUTOMATION LOGIC ---\r\n// ==========================================\r\nfunction openChecklistModal(projectId, e) {\r\n  if (e) e.stopPropagation();\r\n  if (!globalManagerConfig.rules || globalManagerConfig.rules.length === 0) {\r\n      alert(\"No automation rules configured. Go to the Manager Hub to set up Task Rules.\");\r\n      return;\r\n  }\r\n  \r\n  let ev = calendar.getEventById(projectId);\r\n  if (!ev) return;\r\n  \r\n  document.getElementById('checklist-project-id').value = projectId;\r\n  document.getElementById('checklist-title').innerText = \"Checklist: \" + ev.title;\r\n  \r\n  let state = ev.extendedProps.rawDbData.checklistState || {};\r\n  if (typeof state === 'string') {\r\n      try { state = JSON.parse(state); } catch(e) { state = {}; }\r\n  }\r\n  \r\n  let html = '';\r\n  globalManagerConfig.rules.forEach((r, idx) => {\r\n      let isChecked = state[r.taskName] && state[r.taskName].checked;\r\n      let loadingId = `chk-load-${idx}`;\r\n      let taskType = normalizeRuleTaskType(r);\r\n      let typeBadge = taskType === 'basic'\r\n          ? '<span style=\"font-size:9px; font-weight:800; color:#3b82f6; background:rgba(59,130,246,0.15); padding:2px 6px; border-radius:4px; margin-left:6px;\">MANUAL</span>'\r\n          : '<span style=\"font-size:9px; font-weight:800; color:#f97316; background:rgba(249,115,22,0.15); padding:2px 6px; border-radius:4px; margin-left:6px;\">AUTO</span>';\r\n      html += `\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; background:#222; padding:12px; border-radius:6px;\">\r\n         <label style=\"display:flex; align-items:center; gap:10px; cursor:pointer; flex:1;\">\r\n            <input type=\"checkbox\" id=\"chk-${idx}\" class=\"crew-cb\" ${isChecked ? 'checked' : ''} onchange=\"toggleChecklistItem('${projectId}', ${idx}, this.checked)\">\r\n            <span style=\"color:#fff; font-weight:bold; font-size:13px;\">${r.taskName}${typeBadge}</span>\r\n         </label>\r\n         <span id=\"${loadingId}\" style=\"font-size:11px; color:#a855f7; display:none; font-weight:800;\">PROCESSING...</span>\r\n      </div>`;\r\n  });\r\n  document.getElementById('checklist-items').innerHTML = html;\r\n  document.getElementById('checklist-modal-overlay').style.display = 'flex';\r\n}\r\n\r\nfunction toggleChecklistItem(projectId, ruleIdx, isChecked) {\r\n  let rule = globalManagerConfig.rules[ruleIdx];\r\n  let taskType = normalizeRuleTaskType(rule);\r\n  let loader = document.getElementById(`chk-load-${ruleIdx}`);\r\n  let chk = document.getElementById(`chk-${ruleIdx}`);\r\n\r\n  if (loader) {\r\n      loader.innerText = (taskType === 'basic') ? 'SAVING...' : 'PROCESSING...';\r\n      loader.style.display = 'block';\r\n  }\r\n  chk.disabled = true;\r\n  \r\n  google.script.run\r\n  .withFailureHandler(err => {\r\n      alert((taskType === 'basic' ? \"Checklist Error: \" : \"Automation Error: \") + err.message);\r\n      if (loader) loader.style.display = 'none';\r\n      chk.disabled = false;\r\n      chk.checked = !isChecked; \r\n  })\r\n  .withSuccessHandler(newStateStr => {\r\n      if (loader) loader.style.display = 'none';\r\n      chk.disabled = false;\r\n      \r\n      let ev = calendar.getEventById(projectId);\r\n      if (ev) {\r\n          let raw = ev.extendedProps.rawDbData;\r\n          raw.checklistState = JSON.parse(newStateStr);\r\n          ev.setExtendedProp('rawDbData', raw); \r\n      }\r\n  })\r\n  .processChecklistAction(\r\n      projectId,\r\n      rule.taskName,\r\n      rule.srcFolderName,\r\n      rule.searchString,\r\n      rule.suffix,\r\n      rule.destFolderName,\r\n      isChecked,\r\n      ACTIVE_USER_NAME,\r\n      taskType\r\n  );\r\n}\r\n\r\n// ==========================================\r\n// --- DATABASE ARCHIVER ENGINE (UI) ---\r\n// ==========================================\r\n// @INDEX: AUTOMATION -> Database Archivers\r\nfunction triggerMonthlyLogArchive() {\r\n  const overlay = document.getElementById('backup-modal-overlay');\r\n  const subText = document.getElementById('backup-modal-sub');\r\n  const mainText = document.getElementById('backup-modal-text');\r\n  \r\n  if (overlay) {\r\n      overlay.style.display = 'flex';\r\n      overlay.style.pointerEvents = 'auto';\r\n      overlay.style.background = 'rgba(0,0,0,0.8)';\r\n      overlay.style.backdropFilter = 'blur(8px)';\r\n      mainText.innerHTML = `<span style=\"font-size: 24px; font-weight: 900; color: #a855f7;\">ARCHIVING LOGS...</span>`;\r\n      subText.innerText = \"Scanning Audit Logs for old entries. Do not close this window.\";\r\n  } else {\r\n      console.log(\"Monthly Archiver starting...\");\r\n  }\r\n  \r\n  google.script.run\r\n    .withSuccessHandler(res => {\r\n       if (mainText) {\r\n           mainText.innerHTML = `<span style=\"font-size: 24px; font-weight: 900; color: #10b981;\">ARCHIVE COMPLETE</span>`;\r\n           subText.innerText = res;\r\n           setTimeout(() => { overlay.style.display = 'none'; }, 4000);\r\n       } else alert(\"Archive Complete:\\n\" + res);\r\n    })\r\n    .withFailureHandler(err => {\r\n       if (mainText) {\r\n           mainText.innerHTML = `<span style=\"font-size: 24px; font-weight: 900; color: #ef4444;\">ARCHIVE FAILED</span>`;\r\n           subText.innerText = err.message;\r\n           setTimeout(() => { overlay.style.display = 'none'; }, 5000);\r\n       } else alert(\"Archive Failed:\\n\" + err.message);\r\n    })\r\n    .runMonthlyLogArchive(ACTIVE_USER_NAME);\r\n}\r\n\r\nfunction triggerYearlyEngineArchive() {\r\n  const overlay = document.getElementById('backup-modal-overlay');\r\n  const subText = document.getElementById('backup-modal-sub');\r\n  const mainText = document.getElementById('backup-modal-text');\r\n  \r\n  overlay.style.display = 'flex';\r\n  overlay.style.pointerEvents = 'none';\r\n  overlay.style.background = 'transparent';\r\n  overlay.style.backdropFilter = 'none';\r\n  \r\n  let count = 10; // 10s Warning Phase\r\n  let phase = 1;\r\n  \r\n  mainText.innerHTML = `Engine will start archiving in <br><span id=\"backup-countdown\" style=\"font-size: 48px; font-weight: 900; color: #a855f7;\">${count}</span><br> seconds.`;\r\n  subText.innerText = \"Please save your work. The interface will lock soon.\";\r\n\r\n  const timer = setInterval(() => {\r\n    count--;\r\n    const newCountdownEl = document.getElementById('backup-countdown');\r\n    if (newCountdownEl) newCountdownEl.innerText = count;\r\n    \r\n    if (count <= 0) {\r\n      if (phase === 1) {\r\n        phase = 2;\r\n        count = 15; // 15s Extended Hard Lock for Data Destruction\r\n        overlay.style.pointerEvents = 'auto';\r\n        overlay.style.background = 'rgba(0,0,0,0.8)';\r\n        overlay.style.backdropFilter = 'blur(8px)';\r\n        mainText.innerHTML = `Interface locked. Safety buffer: <br><span id=\"backup-countdown\" style=\"font-size: 48px; font-weight: 900; color: #f59e0b;\">${count}</span><br> seconds.`;\r\n        subText.innerText = \"Waiting for pending background saves to complete...\";\r\n      } else if (phase === 2) {\r\n        clearInterval(timer);\r\n        mainText.innerHTML = `<span style=\"font-size: 24px; font-weight: 900; color: #a855f7;\">ARCHIVING ENGINE...</span>`;\r\n        subText.innerText = \"Checking 18-month threshold for Project Engine. Please wait.\";\r\n        \r\n        google.script.run\r\n          .withSuccessHandler(res => {\r\n             mainText.innerHTML = `<span style=\"font-size: 24px; font-weight: 900; color: #10b981;\">ARCHIVE COMPLETE</span>`;\r\n             subText.innerText = res;\r\n             setTimeout(() => { overlay.style.display = 'none'; }, 4000);\r\n          })\r\n          .withFailureHandler(err => {\r\n             mainText.innerHTML = `<span style=\"font-size: 24px; font-weight: 900; color: #ef4444;\">ARCHIVE FAILED</span>`;\r\n             subText.innerText = err.message;\r\n             setTimeout(() => { overlay.style.display = 'none'; }, 5000);\r\n          })\r\n          .runYearlyEngineArchive(ACTIVE_USER_NAME);\r\n      }\r\n    }\r\n  }, 1000);\r\n}\r\n\r\n// ==========================================\r\n// --- UNIVERSAL ENTITY AUDIT TRAIL UI ---\r\n// ==========================================\r\nwindow.currentUhHistory = [];\r\nwindow.currentUhFilter = 'ALL';\r\n\r\nfunction fetchEntitySummary(uid, btnId) {\r\n    let btn = document.getElementById(btnId);\r\n    if (!btn) return;\r\n    if (!uid || uid === 'NEW') { btn.style.display = 'none'; return; }\r\n    if (typeof accessTierAtLeast === 'function' && !accessTierAtLeast('EDITOR')) return;\r\n\r\n    btn.style.display = 'inline-flex';\r\n    btn.innerHTML = `<span style=\"opacity:0.5;\">LOADING...</span>`;\r\n\r\n    google.script.run.withSuccessHandler(history => {\r\n        if (!history || history.length === 0) {\r\n            btn.innerHTML = `NO HISTORY`;\r\n            return;\r\n        }\r\n        let createdLog = history[history.length - 1]; // Oldest log\r\n\r\n        // Clean up the name (e.g., \"John Doe (uid-123)\" -> \"John Doe\")\r\n        let createdName = createdLog.actor.split('(')[0].trim().toUpperCase();\r\n\r\n        btn.innerHTML = `🕒 CREATOR: ${createdName}`;\r\n    }).getEntityAuditHistory(uid);\r\n}\r\n\r\nfunction openUniversalHistory(uid) {\r\n    document.getElementById('universal-history-modal').style.display = 'flex';\r\n    document.getElementById('uh-timeline').innerHTML = '';\r\n    document.getElementById('uh-loading').style.display = 'block';\r\n\r\n    filterUhTimeline('ALL', true); // Reset visual styling\r\n\r\n    google.script.run.withSuccessHandler(history => {\r\n        document.getElementById('uh-loading').style.display = 'none';\r\n        window.currentUhHistory = history || [];\r\n        renderUhTimeline();\r\n    }).getEntityAuditHistory(uid);\r\n}\r\n\r\nfunction filterUhTimeline(moduleName, noRender = false) {\r\n    window.currentUhFilter = moduleName;\r\n    document.querySelectorAll('.uh-filter-btn').forEach(btn => {\r\n        if (btn.dataset.filter === moduleName) {\r\n            btn.style.borderColor = '#a855f7';\r\n            btn.style.color = '#a855f7';\r\n        } else {\r\n            btn.style.borderColor = '';\r\n            btn.style.color = '';\r\n        }\r\n    });\r\n    if (!noRender) renderUhTimeline();\r\n}\r\n\r\nfunction renderUhTimeline() {\r\n    let html = '';\r\n    let filtered = window.currentUhHistory;\r\n    \r\n    if (window.currentUhFilter !== 'ALL') {\r\n        filtered = window.currentUhHistory.filter(log => {\r\n            if (window.currentUhFilter === 'TIMELINE') return log.module === 'TIMELINE' || log.module === 'SHIFTS';\r\n            return log.module === window.currentUhFilter;\r\n        });\r\n    }\r\n\r\n    if (!filtered || filtered.length === 0) {\r\n        html = '<div style=\"color:#888; text-align:center; padding: 20px;\">No audit logs found for this filter.</div>';\r\n    } else {\r\n        filtered.forEach(log => {\r\n            let d = new Date(log.timestamp);\r\n            let dateStr = d.toLocaleDateString() + ' ' + d.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});\r\n            let actionColor = log.action === 'CREATE' ? '#10b981' : (log.action === 'DELETE' ? '#ef4444' : (log.action === 'RESTORE' ? '#f59e0b' : '#3b82f6'));\r\n            let cleanActor = log.actor.split('(')[0].trim();\r\n\r\n            // Module-based color points for easy scanning\r\n            let moduleColor = '#888888'; \r\n            if (log.module === 'PROJECTS') moduleColor = '#3b82f6'; // Blue\r\n            else if (log.module === 'TIMELINE' || log.module === 'SHIFTS') moduleColor = '#a855f7'; // Purple\r\n            else if (log.module === 'PROJECT_ASSETS' || log.module === 'ASSETS') moduleColor = '#10b981'; // Green\r\n            else if (log.module === 'CHECKLIST' || log.module === 'TASKS') moduleColor = '#f59e0b'; // Orange\r\n            else if (log.module === 'IAM' || log.module === 'IAM_ROLES') moduleColor = '#ef4444'; // Red\r\n            else if (log.module === 'ROSTER_LEAVE') moduleColor = '#f43f5e'; // Rose\r\n\r\n            html += `<div style=\"display:flex; gap:15px;\">\r\n                        <div style=\"display:flex; flex-direction:column; align-items:center; width:20px;\">\r\n                            <div style=\"width:12px; height:12px; border-radius:50%; background:${moduleColor}; box-shadow: 0 0 6px ${moduleColor}; z-index:2;\"></div>\r\n                            <div style=\"flex:1; width:2px; background:#333; margin-top:5px; margin-bottom:-10px; z-index:1;\"></div>\r\n                        </div>\r\n                        <div style=\"flex:1; background:#1a1a1e; border:1px solid #333; padding:12px; border-radius:6px; margin-bottom:12px;\">\r\n                            <div style=\"display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:8px;\">\r\n                                <div style=\"color:#fff; font-size:14px; font-weight:bold;\">${cleanActor}</div>\r\n                                <div style=\"color:#a1a1aa; font-size:12px;\">${dateStr}</div>\r\n                            </div>\r\n                            <div style=\"display:flex; gap:8px; align-items:center; margin-bottom:8px;\">\r\n                                <span style=\"background:rgba(255,255,255,0.1); color:${actionColor}; padding:3px 8px; border-radius:4px; font-size:11px; font-weight:900;\">${log.action}</span>\r\n                                <span style=\"color:${moduleColor}; font-size:11px; font-weight:bold; text-transform:uppercase;\">${log.module}</span>\r\n                            </div>\r\n                            <div style=\"color:#e4e4e7; font-size:14px; line-height:1.4;\">${log.delta}</div>\r\n                        </div>\r\n                    </div>`;\r\n        });\r\n    }\r\n    document.getElementById('uh-timeline').innerHTML = html;\r\n}\r\n\n\n\r\nwindow.auditedAssetIds = new Set();\r\nwindow.unauditedList = [];\r\nwindow.activeAuditAsset = null;\r\nwindow.isAuditModeActive = false;\r\n\r\nfunction openAuditStudio() {\r\n    document.getElementById('audit-studio-overlay').style.display = 'flex';\r\n    window.isAuditModeActive = true;\r\n    \r\n    // Load progress from backend\r\n    google.script.run.withSuccessHandler(res => {\r\n        window.auditedAssetIds = new Set(res || []);\r\n        switchAuditTab('dup'); // Default to duplicate scanner first\r\n    }).getVaultAsset('audited_assets_list', []);\r\n}\r\n\r\nfunction closeAuditStudio() {\r\n    document.getElementById('audit-studio-overlay').style.display = 'none';\r\n    window.isAuditModeActive = false;\r\n}\r\n\r\nfunction switchAuditTab(tab) {\r\n    document.getElementById('audit-view-dup').style.display = (tab === 'dup') ? 'flex' : 'none';\r\n    document.getElementById('audit-view-item').style.display = (tab === 'item') ? 'flex' : 'none';\r\n    \r\n    let btnDup = document.getElementById('audit-tab-btn-dup');\r\n    let btnItem = document.getElementById('audit-tab-btn-item');\r\n    \r\n    btnDup.classList.toggle('active', tab === 'dup');\r\n    btnItem.classList.toggle('active', tab === 'item');\r\n    \r\n    if (tab === 'dup') runDuplicateScan();\r\n    if (tab === 'item') loadNextUnaudited();\r\n}\r\n\r\n// ==========================================\r\n// 1. DUPLICATE SCANNER & MERGE ENGINE\r\n// ==========================================\r\nfunction _localLevenshtein(a, b) {\r\n    if (a.length === 0) return b.length;\r\n    if (b.length === 0) return a.length;\r\n    let matrix = [];\r\n    for (let i = 0; i <= b.length; i++) { matrix[i] = [i]; }\r\n    for (let j = 0; j <= a.length; j++) { matrix[0][j] = j; }\r\n    for (let i = 1; i <= b.length; i++) {\r\n        for (let j = 1; j <= a.length; j++) {\r\n            if (b.charAt(i - 1) === a.charAt(j - 1)) matrix[i][j] = matrix[i - 1][j - 1];\r\n            else matrix[i][j] = Math.min(matrix[i - 1][j - 1] + 1, Math.min(matrix[i][j - 1] + 1, matrix[i - 1][j] + 1));\r\n        }\r\n    }\r\n    return matrix[b.length][a.length];\r\n}\r\n\r\nfunction runDuplicateScan() {\r\n    let listEl = document.getElementById('audit-dup-list');\r\n    let statusEl = document.getElementById('audit-dup-status');\r\n    listEl.innerHTML = '<div style=\"color:#f59e0b; text-align:center; padding:40px; font-size:16px; font-weight:bold;\">Running Fuzzy Logic Scanner...</div>';\r\n    \r\n    setTimeout(() => {\r\n        let groups = [];\r\n        \r\n        // Pass A: Find overlapping Bulk Items\r\n        let bulkMap = {};\r\n        globalAssets.forEach(a => {\r\n            if (a.type === 'Bulk') {\r\n                let key = (String(a.name || '') + '|||' + String(a.manufacturer || '')).toLowerCase();\r\n                if (!bulkMap[key]) bulkMap[key] = [];\r\n                bulkMap[key].push(a);\r\n            }\r\n        });\r\n        Object.values(bulkMap).forEach(arr => {\r\n            if (arr.length > 1) {\r\n                groups.push({ type: 'BULK', title: `Fragmented Bulk Item: ${arr[0].name}`, suggested: arr[0].name, assets: arr });\r\n            }\r\n        });\r\n\r\n        // Pass B: Fuzzy Name Typos (Spelling normalization)\r\n        let nameGroups = [];\r\n        globalAssets.forEach(a => {\r\n            // Skip if already in a Bulk conflict\r\n            let bKey = (String(a.name || '') + '|||' + String(a.manufacturer || '')).toLowerCase();\r\n            if (a.type === 'Bulk' && bulkMap[bKey] && bulkMap[bKey].length > 1) return;\r\n            \r\n            let clean = String(a.name || '').toLowerCase().replace(/[^a-z0-9]/g, '');\r\n            let placed = false;\r\n            for (let g of nameGroups) {\r\n                let dist = _localLevenshtein(clean, g.repClean);\r\n                // Group if extreme similarity (<= 2 typos) AND they share the same brand\r\n                if (dist > 0 && dist <= 2 && String(a.manufacturer || '').toLowerCase() === g.brand) {\r\n                    g.assets.push(a);\r\n                    g.uniqueNames.add(String(a.name || ''));\r\n                    placed = true;\r\n                    break;\r\n                }\r\n            }\r\n            if (!placed) {\r\n                nameGroups.push({ repClean: clean, brand: String(a.manufacturer || '').toLowerCase(), uniqueNames: new Set([String(a.name || '')]), assets: [a] });\r\n            }\r\n        });\r\n        \r\n        nameGroups.forEach(g => {\r\n            if (g.uniqueNames.size > 1) {\r\n                groups.push({ type: 'SPELLING', title: `Spelling Variations: ${Array.from(g.uniqueNames).join(' vs ')}`, suggested: Array.from(g.uniqueNames)[0], assets: g.assets });\r\n            }\r\n        });\r\n\r\n        // Render Results\r\n        if (groups.length === 0) {\r\n            if (statusEl) statusEl.innerText = \"✅ 0 conflicts remaining.\";\r\n            listEl.innerHTML = '<div style=\"color:#10b981; text-align:center; padding:40px; font-size:16px; font-weight:bold;\">✅ Database is clean! No duplicates or misspellings found.</div>';\r\n            return;\r\n        } else {\r\n            if (statusEl) statusEl.innerHTML = `<span style=\"color:#f59e0b; font-weight:bold;\">⚠️ ${groups.length} Conflicts Found</span> (Spelling variations or overlapping bulk items)`;\r\n        }\r\n        \r\n        let html = '';\r\n        groups.forEach((g, idx) => {\r\n            let isBulk = g.type === 'BULK';\r\n            let icon = isBulk ? '📦' : '🔤';\r\n            let color = isBulk ? '#f59e0b' : '#3b82f6';\r\n            \r\n            let itemRows = g.assets.map(a => `<div style=\"display:flex; justify-content:space-between; background:#111; padding:6px 12px; border-bottom:1px solid #222; font-size:12px; color:#a1a1aa;\"><span>${a.name} ${a.unitNumber ? '#'+a.unitNumber : ''}</span><span>UID: ...${a.id.slice(-5)}</span></div>`).join('');\r\n            \r\n            html += `\r\n            <div class=\"dup-card\" style=\"background:#1a1a1e; border:1px solid ${color}; border-radius:8px; overflow:hidden;\">\r\n                <div style=\"background:rgba(255,255,255,0.05); padding:12px 15px; border-bottom:1px solid ${color}; display:flex; justify-content:space-between; align-items:center;\">\r\n                    <div style=\"color:#fff; font-weight:bold; font-size:14px;\">${icon} ${g.title}</div>\r\n                    <div style=\"color:${color}; font-size:11px; font-weight:bold; text-transform:uppercase;\">${g.assets.length} Items</div>\r\n                </div>\r\n                <div style=\"padding:15px;\">\r\n                    <div style=\"margin-bottom:15px; border:1px solid #333; border-radius:4px; overflow:hidden;\">${itemRows}</div>\r\n                    <div style=\"display:flex; gap:10px; align-items:flex-end;\">\r\n                        <div style=\"flex:1;\">\r\n                            <div style=\"font-size:10px; color:#888; margin-bottom:4px; text-transform:uppercase; font-weight:bold;\">Official Name to Apply</div>\r\n                            <input type=\"text\" id=\"merge-name-${idx}\" value=\"${g.suggested}\" style=\"width:100%; padding:10px; background:#111; border:1px solid #333; color:#fff; border-radius:4px; font-size:14px; box-sizing:border-box;\">\r\n                        </div>\r\n                        <button class=\"btn-main\" style=\"height:38px; margin:0;\" onclick=\"executeMerge(${idx}, '${g.type}')\">MERGE & NORMALIZE</button>\r\n                    </div>\r\n                </div>\r\n            </div>`;\r\n        });\r\n        window.currentDuplicateGroups = groups;\r\n        listEl.innerHTML = html;\r\n    }, 100);\r\n}\r\n\r\nfunction executeMerge(groupIdx, type) {\r\n    let group = window.currentDuplicateGroups[groupIdx];\r\n    let newName = document.getElementById(`merge-name-${groupIdx}`).value.trim();\r\n    if (!newName) return alert(\"Official Name cannot be blank.\");\r\n    \r\n    let btn = event.currentTarget;\r\n    let origText = btn.innerText;\r\n    btn.innerText = \"MERGING...\"; btn.disabled = true;\r\n\r\n    if (type === 'BULK') {\r\n        // Merge Quantities into the first item, delete the rest\r\n        let primary = group.assets[0];\r\n        let totalQty = 0;\r\n        let idsToDelete = [];\r\n        group.assets.forEach((a, i) => {\r\n            totalQty += parseInt(a.totalQuantity, 10) || 1;\r\n            if (i > 0) idsToDelete.push(a.id);\r\n        });\r\n        \r\n        let payload = {\r\n            name: newName, unitNumber: primary.unitNumber, rfidTag: primary.rfidTag, manufacturer: primary.manufacturer,\r\n            containerType: primary.containerType, nestingLevel: primary.nestingLevel, type: primary.type,\r\n            department: primary.department, whId: primary.whId, zoneId: primary.zoneId, areaId: primary.areaId,\r\n            weight: primary.weight, dims: primary.dims, capacity: primary.capacity, length: primary.length,\r\n            power: primary.power, price: primary.price, rental: primary.rental, dateBought: primary.dateBought,\r\n            lifecycle: primary.status, lastService: primary.lastService, serviceInterval: primary.serviceInterval, tags: primary.tags\r\n        };\r\n\r\n        google.script.run.withSuccessHandler(() => {\r\n            google.script.run.withSuccessHandler(() => {\r\n                if (typeof loadAssetRegistry === 'function') loadAssetRegistry();\r\n                setTimeout(runDuplicateScan, 1000);\r\n            }).deleteVaultAsset(ACTIVE_USER_NAME, idsToDelete);\r\n        }).provisionNewAsset(ACTIVE_USER_NAME, payload, primary.id, totalQty);\r\n\r\n    } else {\r\n        // Spelling Normalization (Update Name for all items in group)\r\n        let allIds = group.assets.map(a => a.id);\r\n        let sample = group.assets[0];\r\n        let payload = {\r\n            name: newName, unitNumber: sample.unitNumber, rfidTag: sample.rfidTag, manufacturer: sample.manufacturer,\r\n            containerType: sample.containerType, nestingLevel: sample.nestingLevel, type: sample.type,\r\n            department: sample.department, whId: sample.whId, zoneId: sample.zoneId, areaId: sample.areaId,\r\n            weight: sample.weight, dims: sample.dims, capacity: sample.capacity, length: sample.length,\r\n            power: sample.power, price: sample.price, rental: sample.rental, dateBought: sample.dateBought,\r\n            lifecycle: sample.status, lastService: sample.lastService, serviceInterval: sample.serviceInterval, tags: sample.tags\r\n        };\r\n\r\n        google.script.run.withSuccessHandler(() => {\r\n            if (typeof loadAssetRegistry === 'function') loadAssetRegistry();\r\n            setTimeout(runDuplicateScan, 1000);\r\n        }).provisionNewAsset(ACTIVE_USER_NAME, payload, allIds, 1);\r\n    }\r\n}\r\n\r\n// ==========================================\r\n// 2. ITEM BY ITEM AUDIT ENGINE\r\n// ==========================================\r\nfunction loadNextUnaudited() {\r\n    window.unauditedList = globalAssets.filter(a => !window.auditedAssetIds.has(a.id));\r\n    \r\n    let total = globalAssets.length;\r\n    let done = window.auditedAssetIds.size;\r\n    document.getElementById('audit-progress-text').innerText = `Progress: ${done} / ${total} Items Audited`;\r\n\r\n    let cardEl = document.getElementById('audit-item-card');\r\n    \r\n    if (window.unauditedList.length === 0) {\r\n        cardEl.innerHTML = `\r\n            <div style=\"font-size: 60px; margin-bottom: 20px;\">🎉</div>\r\n            <h2 style=\"color:#10b981; margin:0 0 10px 0;\">DATABASE FULLY AUDITED</h2>\r\n            <p style=\"color:#a1a1aa;\">You have successfully reviewed every single item in the database.</p>\r\n        `;\r\n        return;\r\n    }\r\n\r\n    window.activeAuditAsset = window.unauditedList[0];\r\n    let a = window.activeAuditAsset;\r\n    let dObj = getDeptObj(a.department);\r\n    \r\n    let tagsArr = [];\r\n    try { tagsArr = JSON.parse(a.tags || '[]'); } catch(e){}\r\n    let tagHtml = buildTagPathsHtml(tagsArr, 10);\r\n\r\n    cardEl.innerHTML = `\r\n        <div style=\"font-size:11px; color:${dObj.color}; font-weight:bold; text-transform:uppercase; margin-bottom:10px;\">${dObj.name}</div>\r\n        <h2 style=\"color:#fff; margin:0 0 5px 0; font-size:28px;\">${a.name} ${a.unitNumber ? '#'+a.unitNumber : ''}</h2>\r\n        <div style=\"color:#a1a1aa; font-size:14px; margin-bottom:25px;\">${a.manufacturer || 'Unknown Brand'}</div>\r\n        \r\n        <div style=\"display:flex; justify-content:center; gap:20px; margin-bottom:25px;\">\r\n            <div style=\"background:#111; padding:10px 20px; border-radius:6px; border:1px solid #333;\">\r\n                <div style=\"font-size:10px; color:#888; text-transform:uppercase; margin-bottom:4px;\">Type</div>\r\n                <div style=\"color:#fff; font-weight:bold;\">${a.type}</div>\r\n            </div>\r\n            <div style=\"background:#111; padding:10px 20px; border-radius:6px; border:1px solid #333;\">\r\n                <div style=\"font-size:10px; color:#888; text-transform:uppercase; margin-bottom:4px;\">Total Qty</div>\r\n                <div style=\"color:#10b981; font-weight:bold;\">${a.type === 'Bulk' ? a.totalQuantity : 1}</div>\r\n            </div>\r\n        </div>\r\n        \r\n        <div style=\"margin-bottom:30px; display:flex; justify-content:center;\">${tagHtml}</div>\r\n        \r\n        <div style=\"display:flex; justify-content:center; gap:15px;\">\r\n            <button class=\"btn-delete\" style=\"padding:14px 24px!important; font-size:14px!important;\" onclick=\"deleteAuditItem()\">🗑️ DELETE</button>\r\n            <button class=\"btn-outline\" style=\"border-color:#52525b; color:#a1a1aa; padding:14px 24px!important; font-size:14px!important;\" onclick=\"skipAuditItem()\">⏭️ SKIP FOR NOW</button>\r\n            <button class=\"btn-outline\" style=\"border-color:#3b82f6; color:#3b82f6; padding:14px 24px!important; font-size:14px!important;\" onclick=\"openAuditSetup()\">✏️ EDIT IN SETUP</button>\r\n            <button class=\"btn-main\" style=\"padding:14px 24px!important; font-size:14px!important;\" onclick=\"markAuditDone()\">✅ LOOKS GOOD</button>\r\n        </div>\r\n    `;\r\n}\r\n\r\nfunction skipAuditItem() {\r\n    let skipped = window.unauditedList.shift();\r\n    window.unauditedList.push(skipped); // Move to end of line\r\n    loadNextUnaudited();\r\n}\r\n\r\nfunction openAuditSetup() {\r\n    if (typeof openAssetModal === 'function' && window.activeAuditAsset) {\r\n        openAssetModal(window.activeAuditAsset.id);\r\n    }\r\n}\r\n\r\nfunction markAuditDone() {\r\n    if (window.activeAuditAsset) {\r\n        window.auditedAssetIds.add(window.activeAuditAsset.id);\r\n        google.script.run.saveVaultAsset('audited_assets_list', Array.from(window.auditedAssetIds));\r\n        loadNextUnaudited();\r\n    }\r\n}\r\n\r\nfunction deleteAuditItem() {\r\n    if (window.activeAuditAsset) {\r\n        if (!confirm(`PERMANENT WARNING: Delete ${window.activeAuditAsset.name} from the Vault completely?`)) return;\r\n        \r\n        let idToDel = window.activeAuditAsset.id;\r\n        window.auditedAssetIds.add(idToDel); // Mark as audited so it doesn't show up again\r\n        google.script.run.saveVaultAsset('audited_assets_list', Array.from(window.auditedAssetIds));\r\n        \r\n        google.script.run.withSuccessHandler(() => {\r\n            if (typeof loadAssetRegistry === 'function') loadAssetRegistry();\r\n            loadNextUnaudited();\r\n        }).deleteVaultAsset(ACTIVE_USER_NAME, [idToDel]);\r\n    }\r\n}\r\n\r\nfunction resetAuditProgress() {\r\n    if (!confirm(\"Are you sure you want to completely wipe your review progress? This will force you to review all items again.\")) return;\r\n    window.auditedAssetIds.clear();\r\n    google.script.run.saveVaultAsset('audited_assets_list', []);\r\n    loadNextUnaudited();\r\n}\r\n\r\n// ==========================================\r\n// 3. THE LIVE INTERCEPTOR HOOK\r\n// ==========================================\r\n// This is called by 06b_Admin_Assets.html when the Asset Modal closes\r\nwindow.handleAuditModalClose = function(wasSaved) {\r\n    if (window.isAuditModeActive && window.activeAuditAsset) {\r\n        setTimeout(() => {\r\n            if (confirm(\"You just reviewed this item in Setup.\\n\\nDo you want to mark it as DONE and move to the next item?\")) {\r\n                markAuditDone();\r\n            }\r\n        }, 200);\r\n    }\r\n};\r\n\n\n\r\n/**\r\n * 06g_Admin_Database.html\r\n * Root-only Database Operations — sub-tabs:\r\n *   BACKUP & ARCHIVE | OPS & NOTIFICATIONS\r\n */\r\n\r\nlet _dbOpsCache = [];\r\nlet _dbLiveStatus = null;\r\nlet _dbActiveSubTab = 'backup';\r\n\r\nfunction switchDatabaseSubTab(tabId) {\r\n  _dbActiveSubTab = tabId === 'ops' ? 'ops' : 'backup';\r\n  const backupBtn = document.getElementById('db-subtab-btn-backup');\r\n  const opsBtn = document.getElementById('db-subtab-btn-ops');\r\n  const backupPane = document.getElementById('db-subtab-backup');\r\n  const opsPane = document.getElementById('db-subtab-ops');\r\n  if (backupBtn) backupBtn.classList.toggle('active', _dbActiveSubTab === 'backup');\r\n  if (opsBtn) opsBtn.classList.toggle('active', _dbActiveSubTab === 'ops');\r\n  if (backupPane) backupPane.style.display = _dbActiveSubTab === 'backup' ? 'flex' : 'none';\r\n  if (opsPane) opsPane.style.display = _dbActiveSubTab === 'ops' ? 'flex' : 'none';\r\n  if (_dbLiveStatus) {\r\n    if (_dbActiveSubTab === 'ops') renderDatabaseOpsTab(_dbLiveStatus);\r\n    else renderDatabaseBackupArchiveTab(_dbLiveStatus);\r\n  } else if (_dbActiveSubTab === 'ops') {\r\n    loadDatabaseOpsPanel();\r\n  }\r\n}\r\n\r\nfunction refreshDatabasePanel() {\r\n  loadDatabaseOpsPanel();\r\n}\r\n\r\nfunction loadDatabaseOpsPanel() {\r\n  const backupPanel = document.getElementById('db-ops-panel');\r\n  const opsPanel = document.getElementById('db-ops-notifications-panel');\r\n  const loadingHtml = '<div style=\"color:#f59e0b; padding:40px; text-align:center; font-weight:bold;\">Loading database status...</div>';\r\n  if (_dbActiveSubTab === 'backup' && backupPanel) {\r\n    backupPanel.innerHTML = loadingHtml;\r\n  } else if (opsPanel) {\r\n    opsPanel.innerHTML = loadingHtml;\r\n  }\r\n\r\n  google.script.run\r\n    .withFailureHandler(function(err) {\r\n      const errHtml = '<div style=\"color:#ef4444; padding:40px; text-align:center;\">' + err.message + '</div>';\r\n      if (backupPanel) backupPanel.innerHTML = errHtml;\r\n      if (opsPanel) opsPanel.innerHTML = errHtml;\r\n    })\r\n    .withSuccessHandler(function(res) {\r\n      try {\r\n        _dbLiveStatus = res;\r\n        _dbOpsCache = (res && res.operations) ? res.operations : [];\r\n        if (_dbActiveSubTab === 'backup') {\r\n          renderDatabaseBackupArchiveTab(res);\r\n        } else {\r\n          renderDatabaseOpsTab(res);\r\n        }\r\n      } catch (err) {\r\n        const errHtml = '<div style=\"color:#ef4444; padding:40px; text-align:center;\">'\r\n          + escapePushHtml((err && err.message) ? err.message : String(err)) + '</div>';\r\n        if (backupPanel) backupPanel.innerHTML = errHtml;\r\n        if (opsPanel) opsPanel.innerHTML = errHtml;\r\n      }\r\n    })\r\n    .getLiveDatabaseStatus(ACTIVE_USER_NAME);\r\n}\r\n\r\nfunction toggleDbOpsLogRow(stepId) {\r\n  const body = document.getElementById('db-ops-body-' + stepId);\r\n  const chev = document.getElementById('db-ops-chev-' + stepId);\r\n  if (!body) return;\r\n  const open = body.style.display !== 'none';\r\n  body.style.display = open ? 'none' : 'block';\r\n  if (chev) chev.textContent = open ? '▸' : '▾';\r\n}\r\n\r\nfunction buildInfoCell(label, valueHtml, valueClass) {\r\n  const cls = 'info-cell-value' + (valueClass ? ' ' + valueClass : '');\r\n  return '<div class=\"info-cell\">'\r\n    + '<div class=\"info-cell-label\">' + label + '</div>'\r\n    + '<div class=\"' + cls + '\">' + valueHtml + '</div>'\r\n    + '</div>';\r\n}\r\n\r\nfunction buildInfoGridRow(cellsHtml) {\r\n  return '<div class=\"pill-info-grid\">' + cellsHtml + '</div>';\r\n}\r\n\r\nfunction buildOpsLogListHtml(ops) {\r\n  if (!ops || !ops.length) {\r\n    return '<div class=\"admin-panel-muted\" style=\"padding:8px 4px;\">No operations logged yet.</div>';\r\n  }\r\n  let html = '';\r\n  ops.forEach(function(op) {\r\n    const canRevert = op.operation === 'RESTORE' && op.status === 'ACTIVE';\r\n    const badge = op.status === 'ACTIVE' ? '#10b981' : (op.status === 'REVERTED' ? '#6b7280' : '#a855f7');\r\n    html += '<div class=\"admin-card\" style=\"margin-bottom:8px; padding:10px 12px;\">'\r\n      + '<div onclick=\"toggleDbOpsLogRow(\\'' + op.step_id + '\\')\" style=\"display:flex; align-items:center; gap:8px; cursor:pointer; user-select:none;\">'\r\n      + '<span id=\"db-ops-chev-' + op.step_id + '\" class=\"admin-panel-muted\" style=\"width:14px;\">▸</span>'\r\n      + '<span class=\"admin-card-title\" style=\"flex:1; margin:0; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;\">'\r\n      + '#' + op.step_id + ' ' + op.file_type + ' ' + op.operation\r\n      + '</span>'\r\n      + '<span style=\"color:' + badge + '; font-size:11px; font-weight:800;\">' + op.status + '</span>'\r\n      + '</div>'\r\n      + '<div id=\"db-ops-body-' + op.step_id + '\" style=\"display:none; padding:8px 0 0 22px; border-top:1px solid #333; margin-top:8px;\">'\r\n      + '<div class=\"admin-panel-muted\">' + op.timestamp + '</div>'\r\n      + '<div class=\"admin-panel-body\" style=\"margin-top:6px;\">' + (op.notes || '—') + '</div>';\r\n    if (canRevert) {\r\n      html += '<button class=\"btn-outline btn-sm\" style=\"margin-top:10px; border-color:#3b82f6; color:#3b82f6;\" onclick=\"event.stopPropagation(); revertDatabaseStep(\\'' + op.step_id + '\\')\">REVERT</button>';\r\n    }\r\n    html += '</div></div>';\r\n  });\r\n  return html;\r\n}\r\n\r\nfunction renderFolderLinksCells(driveFolders) {\r\n  if (!driveFolders) return '';\r\n  const keys = ['database', 'replaced', 'archives'];\r\n  let html = '';\r\n  keys.forEach(function(k) {\r\n    const f = driveFolders[k];\r\n    if (!f || !f.url) return;\r\n    html += buildInfoCell(f.label, '<a class=\"admin-panel-link\" href=\"' + f.url + '\" target=\"_blank\" style=\"margin-top:0;\">Open ↗</a>');\r\n  });\r\n  return html;\r\n}\r\n\r\nfunction renderLiveFileTicket(label, file, accentClass) {\r\n  if (!file) return '';\r\n  const layoutHtml = file.layoutOk\r\n    ? '<span class=\"admin-status-ok\">✓ ' + escapePushHtml(file.expectedPath) + '</span>'\r\n    : '<span class=\"admin-status-warn\">⚠ ' + escapePushHtml(file.expectedPath) + '</span>';\r\n  const locationHtml = file.parentFolderName\r\n    ? '<strong style=\"color:#e4e4e7;\">' + escapePushHtml(file.parentFolderName + '/' + file.name) + '</strong>'\r\n    : '—';\r\n  const factoryHtml = file.isOriginalFactoryFile\r\n    ? 'Factory original — never restored'\r\n    : 'Active file differs from factory original';\r\n  const linkHtml = file.url\r\n    ? '<a class=\"admin-panel-link\" href=\"' + file.url + '\" target=\"_blank\" style=\"margin-top:0;\">Open live file ↗</a>'\r\n    : '—';\r\n\r\n  return '<div class=\"info-pill ' + accentClass + '\">'\r\n    + buildInfoGridRow(\r\n      buildInfoCell(label, escapePushHtml(file.name), 'info-cell-value--title')\r\n      + buildInfoCell('Expected', layoutHtml)\r\n      + buildInfoCell('Now', locationHtml)\r\n      + buildInfoCell('Modified', escapePushHtml(file.modifiedLabel || '—'))\r\n    )\r\n    + buildInfoGridRow(\r\n      buildInfoCell('Factory', factoryHtml)\r\n      + buildInfoCell('Drive', linkHtml)\r\n    )\r\n    + '</div>';\r\n}\r\n\r\nfunction buildCanonicalFolderPill(res, repairBtnHtml) {\r\n  const dbName = res.canonicalFolder ? res.canonicalFolder.name : '05_DATABASE';\r\n  const folderLink = (res.canonicalFolder && res.canonicalFolder.url)\r\n    ? '<a class=\"admin-panel-link\" href=\"' + res.canonicalFolder.url + '\" target=\"_blank\" style=\"margin-top:0;\">Open folder ↗</a>'\r\n    : '—';\r\n  const backups = res.driveFolders && res.driveFolders.backups;\r\n  const backupPath = backups && backups.path ? backups.path : '05_DATABASE/BACKUPS';\r\n  const backupLink = backups && backups.url\r\n    ? '<a class=\"admin-panel-link\" href=\"' + backups.url + '\" target=\"_blank\" style=\"margin-top:0;\">Open BACKUPS ↗</a>'\r\n    : (backups && backups.error ? escapePushHtml(backups.error) : '—');\r\n  const folderLinks = renderFolderLinksCells(res.driveFolders);\r\n  let html = '<div class=\"info-pill info-pill--slate\">'\r\n    + buildInfoGridRow(\r\n      buildInfoCell('Live folder', escapePushHtml(dbName), 'info-cell-value--title')\r\n      + buildInfoCell('Live files', 'SM_Showrunner_ENGINE + SM_Showrunner_VAULT')\r\n      + buildInfoCell('Backups', escapePushHtml(backupPath))\r\n      + buildInfoCell('Backup drive', backupLink)\r\n    );\r\n  if (repairBtnHtml) {\r\n    html += buildInfoGridRow(buildInfoCell('Layout', repairBtnHtml));\r\n  }\r\n  if (folderLinks) {\r\n    html += buildInfoGridRow(folderLinks);\r\n  }\r\n  html += '</div>';\r\n  return html;\r\n}\r\n\r\nfunction buildRestorePill(label, selectId, fileType, optionsHtml) {\r\n  return '<div class=\"info-pill\" style=\"border-left:3px solid #ef4444;\">'\r\n    + buildInfoGridRow(\r\n      buildInfoCell('Restore', label, 'info-cell-value--title')\r\n      + '<div class=\"info-cell\" style=\"grid-column: span 2;\">'\r\n      + '<div class=\"info-cell-label\">Backup</div>'\r\n      + '<select id=\"' + selectId + '\" style=\"width:100%; padding:8px 10px; font-size:12px; background:#1a1a1e; color:#fff; border:1px solid #444; border-radius:4px; box-sizing:border-box;\">' + optionsHtml + '</select>'\r\n      + '</div>'\r\n      + '<div class=\"info-cell\">'\r\n      + '<div class=\"info-cell-label\">&nbsp;</div>'\r\n      + '<button class=\"btn-outline btn-sm\" style=\"margin:0; width:100%; border-color:#ef4444; color:#ef4444; justify-content:center;\" onclick=\"runDbRestore(\\'' + fileType + '\\')\">RESTORE</button>'\r\n      + '</div>'\r\n    )\r\n    + '</div>';\r\n}\r\n\r\nfunction buildBackupHealthBannerHtml(health, backupFolders) {\r\n  if (!health) return '';\r\n  const writePath = (backupFolders && backupFolders.writeFolder && backupFolders.writeFolder.path)\r\n    ? backupFolders.writeFolder.path\r\n    : (health.backupFolderPath || '05_DATABASE/BACKUPS');\r\n  if (health.healthy) {\r\n    return '<div class=\"admin-banner-ok\" style=\"margin-bottom:10px;\">'\r\n      + '✓ Backup OK — last Engine+Vault pair: <strong>' + (health.lastPairedDate || '—') + '</strong>'\r\n      + ' · ' + health.fileCount + ' backup files · write folder: <strong>' + escapePushHtml(writePath) + '</strong></div>';\r\n  }\r\n  let extra = '';\r\n  if (backupFolders && backupFolders.writeError) {\r\n    extra = ' Write folder error: ' + escapePushHtml(backupFolders.writeError);\r\n  } else if (backupFolders && backupFolders.scannedFolders && backupFolders.scannedFolders.length) {\r\n    extra = ' Scanned: ' + backupFolders.scannedFolders.map(function(f) { return f.path; }).join(', ') + '.';\r\n  }\r\n  return '<div class=\"admin-banner-warn\" style=\"margin-bottom:10px;\">'\r\n    + '⚠️ <strong>BACKUP FAILSAFE:</strong> ' + (health.warning || 'Backup unhealthy') + extra + '</div>';\r\n}\r\n\r\nfunction renderDatabaseBackupArchiveTab(res) {\r\n  const panel = document.getElementById('db-ops-panel');\r\n  if (!panel || !res) return;\r\n\r\n  const engOpts = (res.backups.engine || []).map(function(b) {\r\n    return '<option value=\"' + b.id + '\">' + b.name + ' — ' + b.modifiedLabel + '</option>';\r\n  }).join('') || '<option value=\"\">No engine backups</option>';\r\n\r\n  const vaultOpts = (res.backups.vault || []).map(function(b) {\r\n    return '<option value=\"' + b.id + '\">' + b.name + ' — ' + b.modifiedLabel + '</option>';\r\n  }).join('') || '<option value=\"\">No vault backups</option>';\r\n\r\n  const layoutOk = res.engine && res.engine.layoutOk && res.vault && res.vault.layoutOk;\r\n  const repairBtnHtml = layoutOk\r\n    ? '<span class=\"admin-status-ok\">✓ In canonical folder</span>'\r\n    : '<button class=\"btn-outline btn-sm\" style=\"margin:0; width:100%; border-color:#f59e0b; color:#f59e0b; justify-content:center;\" onclick=\"runDbRepairLayout()\">REPAIR LAYOUT</button>';\r\n\r\n  const colStyle = 'flex:1; min-width:0; display:flex; flex-direction:column; border-right:1px solid #333; min-height:0;';\r\n  const colLast = 'flex:1; min-width:0; display:flex; flex-direction:column; min-height:0;';\r\n\r\n  panel.innerHTML = ''\r\n    + '<div style=\"display:flex; flex:1; min-height:0; width:100%;\">'\r\n\r\n    + '<div style=\"' + colStyle + '\">'\r\n    + '<div style=\"padding:12px 14px 8px; border-bottom:1px solid #333; flex-shrink:0;\">'\r\n    + '<div style=\"color:#f59e0b; font-weight:900; font-size:11px; letter-spacing:1px;\">BACKUP COLUMN</div>'\r\n    + '</div>'\r\n    + '<div style=\"flex:1; min-height:0; display:flex; flex-direction:column; padding:10px 14px; overflow:hidden;\">'\r\n    + buildBackupHealthBannerHtml(res.health, res.backupFolders)\r\n    + buildCanonicalFolderPill(res, repairBtnHtml)\r\n    + '<div style=\"flex-shrink:0;\">'\r\n    + '<div class=\"info-cell-label\" style=\"margin-bottom:6px;\">LIVE FILES</div>'\r\n    + renderLiveFileTicket('Engine', res.engine, 'info-pill--amber')\r\n    + renderLiveFileTicket('Vault', res.vault, 'info-pill--green')\r\n    + '</div>'\r\n    + '<div style=\"flex-shrink:0; margin-top:4px;\">'\r\n    + '<div class=\"info-cell-label\" style=\"margin-bottom:6px; color:#ef4444;\">RESTORE FROM BACKUP</div>'\r\n    + buildRestorePill('Engine', 'db-restore-engine-select', 'ENGINE', engOpts)\r\n    + buildRestorePill('Vault', 'db-restore-vault-select', 'VAULT', vaultOpts)\r\n    + '</div>'\r\n    + '<div style=\"flex:1; min-height:0; display:flex; flex-direction:column; margin-top:10px; overflow:hidden;\">'\r\n    + '<div class=\"info-cell-label\" style=\"margin-bottom:6px; color:#3b82f6;\">OPERATIONS LOG</div>'\r\n    + '<div style=\"flex:1; min-height:0; overflow-y:auto; padding-right:4px;\">'\r\n    + buildOpsLogListHtml(_dbOpsCache)\r\n    + '</div>'\r\n    + '</div>'\r\n    + '<div style=\"flex-shrink:0; margin-top:10px; padding-top:10px; border-top:1px solid #333;\">'\r\n    + '<div class=\"info-cell-label\" style=\"margin-bottom:6px; color:#10b981;\">CREATE BACKUP</div>'\r\n    + '<div class=\"admin-backup-actions\">'\r\n    + '<button id=\"db-backup-btn-engine\" class=\"btn-outline btn-sm\" style=\"margin:0; border-color:#10b981; color:#10b981;\" onclick=\"runDbBackupQuick(\\'ENGINE\\')\">ENGINE</button>'\r\n    + '<button id=\"db-backup-btn-vault\" class=\"btn-outline btn-sm\" style=\"margin:0; border-color:#10b981; color:#10b981;\" onclick=\"runDbBackupQuick(\\'VAULT\\')\">VAULT</button>'\r\n    + '<button id=\"db-backup-btn-both\" class=\"btn-outline btn-sm\" style=\"margin:0; border:2px solid #f59e0b; color:#f59e0b;\" title=\"Countdown + UI lock\" onclick=\"runDbBackupBoth()\">BOTH</button>'\r\n    + '</div>'\r\n    + '<div class=\"admin-panel-muted\" style=\"margin-top:6px; text-align:center;\">05_DATABASE/BACKUPS · BOTH = countdown + lock</div>'\r\n    + '</div>'\r\n    + '</div></div>'\r\n\r\n    + '<div style=\"' + colLast + '\">'\r\n    + '<div style=\"padding:12px 14px 8px; border-bottom:1px solid #333; flex-shrink:0;\">'\r\n    + '<div style=\"color:#a855f7; font-weight:900; font-size:11px; letter-spacing:1px;\">ARCHIVE COLUMN</div>'\r\n    + '</div>'\r\n    + '<div style=\"flex:1; display:flex; flex-direction:column; padding:14px; min-height:0; overflow:auto;\">'\r\n    + '<div class=\"info-pill\" style=\"border-left:3px solid #a855f7;\">'\r\n    + buildInfoGridRow(\r\n      buildInfoCell('Archives', 'Engine cold-archive and audit log archives.')\r\n      + (res.driveFolders && res.driveFolders.archives && res.driveFolders.archives.url\r\n        ? buildInfoCell('Drive', '<a class=\"admin-panel-link\" href=\"' + res.driveFolders.archives.url + '\" target=\"_blank\" style=\"margin-top:0;\">Open ARCHIVES ↗</a>')\r\n        : '')\r\n      + buildInfoCell('Status', 'Maintenance tools coming soon.')\r\n    )\r\n    + '</div>'\r\n    + '</div></div>'\r\n\r\n    + '</div>';\r\n}\r\n\r\nfunction escapePushHtml(s) {\r\n  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/\"/g, '&quot;');\r\n}\r\n\r\nfunction renderDatabaseOpsTab(res) {\r\n  const panel = document.getElementById('db-ops-notifications-panel');\r\n  if (!panel) return;\r\n\r\n  const colStyle = 'flex:1; min-width:0; display:flex; flex-direction:column; border-right:1px solid #333; min-height:0;';\r\n  const colLast = 'flex:1; min-width:0; display:flex; flex-direction:column; min-height:0; overflow:auto;';\r\n\r\n  panel.innerHTML = ''\r\n    + '<div style=\"display:flex; flex:1; min-height:0; width:100%;\">'\r\n    + '<div style=\"' + colStyle + '\">'\r\n    + '<div style=\"padding:12px 14px 8px; border-bottom:1px solid #333; flex-shrink:0;\">'\r\n    + '<div style=\"color:#3b82f6; font-weight:900; font-size:11px; letter-spacing:1px;\">SOFTWARE LOG HUB</div>'\r\n    + '</div>'\r\n    + '<div style=\"flex:1; display:flex; flex-direction:column; align-items:center; justify-content:center; padding:20px; text-align:center;\">'\r\n    + '<div style=\"font-size:28px; margin-bottom:12px; opacity:0.4;\">🔍</div>'\r\n    + '<div style=\"color:#3b82f6; font-weight:800; font-size:12px; margin-bottom:8px;\">Query &amp; Diagnostics</div>'\r\n    + '<p style=\"color:#52525b; font-size:11px; line-height:1.5; max-width:260px; margin:0;\">What broke, who broke it, and how to get back to a stable state — searchable audit queries and device registry coming here.</p>'\r\n    + '</div></div>'\r\n    + '<div style=\"' + colLast + '\">'\r\n    + '<div style=\"padding:12px 14px 8px; border-bottom:1px solid #333; flex-shrink:0;\">'\r\n    + '<div style=\"color:#10b981; font-weight:900; font-size:11px; letter-spacing:1px;\">PUSH NOTIFICATIONS</div>'\r\n    + '</div>'\r\n    + '<div style=\"flex:1; min-height:0; overflow:hidden; padding:10px 14px; display:flex; flex-direction:column;\">'\r\n    + '<div id=\"push-admin-panel\" style=\"flex:1; min-height:0; display:flex; flex-direction:column;\"></div>'\r\n    + '</div></div>'\r\n    + '</div>';\r\n\r\n  if (typeof renderPushAdminPanel === 'function') {\r\n    try {\r\n      renderPushAdminPanel('push-admin-panel');\r\n    } catch (err) {\r\n      panel.innerHTML = '<div style=\"color:#ef4444; padding:20px; font-size:12px;\">Push panel failed: '\r\n        + escapePushHtml((err && err.message) ? err.message : String(err)) + '</div>';\r\n    }\r\n  }\r\n}\r\n\r\n/** @deprecated use renderDatabaseBackupArchiveTab */\r\nfunction renderDatabaseOpsPanel(res) {\r\n  _dbLiveStatus = res;\r\n  _dbOpsCache = (res && res.operations) ? res.operations : [];\r\n  if (_dbActiveSubTab === 'ops') {\r\n    renderDatabaseOpsTab(res);\r\n  } else {\r\n    renderDatabaseBackupArchiveTab(res);\r\n  }\r\n}\r\n\r\nfunction runDbBackupQuick(type) {\r\n  if (window.isDatabaseBackupLocked && window.isDatabaseBackupLocked()) {\r\n    alert('Full BOTH backup in progress — wait for countdown to finish.');\r\n    return;\r\n  }\r\n  const btn = document.getElementById('db-backup-btn-' + type.toLowerCase());\r\n  const orig = btn ? btn.innerText : type;\r\n  if (btn) { btn.disabled = true; btn.innerText = '...'; }\r\n\r\n  google.script.run\r\n    .withFailureHandler(function(err) {\r\n      if (btn) { btn.disabled = false; btn.innerText = orig; }\r\n      alert('Backup failed: ' + err.message);\r\n    })\r\n    .withSuccessHandler(function(msg) {\r\n      if (btn) {\r\n        btn.innerText = 'OK';\r\n        setTimeout(function() { btn.disabled = false; btn.innerText = orig; }, 2000);\r\n      }\r\n      loadDatabaseOpsPanel();\r\n    })\r\n    .backupDatabaseFile(ACTIVE_USER_NAME, type);\r\n}\r\n\r\nfunction runDbBackupBoth() {\r\n  if (typeof triggerDatabaseBackup === 'function') {\r\n    triggerDatabaseBackup(loadDatabaseOpsPanel);\r\n    return;\r\n  }\r\n  alert('Backup engine not loaded. Refresh the app.');\r\n}\r\n\r\nfunction runDbRestore(fileType) {\r\n  const sel = document.getElementById('db-restore-' + fileType.toLowerCase() + '-select');\r\n  const backupId = sel ? sel.value : '';\r\n  if (!backupId) return alert('Select a ' + fileType + ' backup first.');\r\n\r\n  if (!confirm('RESTORE ' + fileType + '?\\n\\nCurrent live file will be renamed and moved to the Replaced folder. The selected backup becomes the new live database.\\n\\nProceed?')) return;\r\n  if (!confirm('Final confirmation: type-level restore for ' + fileType + '. Continue?')) return;\r\n\r\n  google.script.run\r\n    .withFailureHandler(function(err) { alert('Restore failed: ' + err.message); })\r\n    .withSuccessHandler(function(msg) {\r\n      alert(msg);\r\n      loadDatabaseOpsPanel();\r\n    })\r\n    .restoreDatabaseFromBackup(ACTIVE_USER_NAME, fileType, backupId);\r\n}\r\n\r\nfunction revertDatabaseStep(stepId) {\r\n  if (!confirm('Revert restore step #' + stepId + '?\\n\\nThis promotes the Replaced live file back and moves the mistaken live file aside.')) return;\r\n\r\n  google.script.run\r\n    .withFailureHandler(function(err) { alert('Revert failed: ' + err.message); })\r\n    .withSuccessHandler(function(msg) {\r\n      alert(msg);\r\n      loadDatabaseOpsPanel();\r\n    })\r\n    .revertDatabaseOperation(ACTIVE_USER_NAME, stepId);\r\n}\r\n\r\nfunction runDbRepairLayout() {\r\n  const folderLabel = (_dbLiveStatus && _dbLiveStatus.canonicalFolder && _dbLiveStatus.canonicalFolder.name)\r\n    ? _dbLiveStatus.canonicalFolder.name : '05_DATABASE';\r\n  if (!confirm('Move live Engine and Vault into ' + folderLabel + ' and rename to SM_Showrunner_ENGINE / SM_Showrunner_VAULT?\\n\\nOnly folder location and file names change — no spreadsheet data is copied.')) return;\r\n\r\n  google.script.run\r\n    .withFailureHandler(function(err) { alert('Repair failed: ' + err.message); })\r\n    .withSuccessHandler(function(res) {\r\n      alert(res.message || res);\r\n      loadDatabaseOpsPanel();\r\n    })\r\n    .repairLiveDatabaseLayout(ACTIVE_USER_NAME);\r\n}\r\n\n\n\r\n/**\r\n * 08_Conflict_Manager.html\r\n * Domain: Conflict resolution, notification drawer, and deep linking.\r\n */\r\n\r\nlet globalConflicts = [];\r\n\r\n// @INDEX: CONFLICTS -> Render Triage Drawer\r\nfunction renderConflicts(conflicts) {\r\n    globalConflicts = conflicts || [];\r\n    \r\n    let assetCounts = { red: 0, yellow: 0, grey: 0 };\r\n    let crewCounts = { red: 0, yellow: 0, grey: 0 };\r\n    \r\n    // 1. Calculate Badges based on RAW conflict math\r\n    globalConflicts.forEach(c => {\r\n        let target = c.isAsset ? assetCounts : crewCounts;\r\n        if (c.acknowledged) target.grey++;\r\n        else if (c.level === 'red') target.red++;\r\n        else target.yellow++;\r\n    });\r\n    \r\n    // 2. Compress & Group Conflicts for the Visual Drawer\r\n    let groupedAsset = {};\r\n    let groupedCrew = {};\r\n    \r\n    globalConflicts.forEach(c => {\r\n        if (c.acknowledged) return; // Hide acknowledged from drawer, but keep in badges\r\n        let key = c.groupKey || c.id;\r\n        let targetGroup = c.isAsset ? groupedAsset : groupedCrew;\r\n        \r\n        if (!targetGroup[key]) {\r\n            targetGroup[key] = {\r\n                id: c.id,\r\n                type: c.type,\r\n                level: c.level,\r\n                title: c.title || (c.isAsset ? 'Asset Shortages' : 'Crew Rest Violations'),\r\n                projectId: c.projectId,\r\n                pairNames: c.pairNames || 'Multiple Events',\r\n                isAsset: c.isAsset,\r\n                items: new Set(),\r\n                count: 0\r\n            };\r\n        }\r\n        \r\n        // Elevate severity if a red hides in a yellow group\r\n        let levels = {'yellow':1, 'orange':2, 'red':3};\r\n        if (levels[c.level] > levels[targetGroup[key].level]) {\r\n            targetGroup[key].level = c.level;\r\n            targetGroup[key].type = c.type; \r\n            targetGroup[key].title = c.title || targetGroup[key].title;\r\n        }\r\n        \r\n        targetGroup[key].count++;\r\n        if (c.isAsset && c.entityName) targetGroup[key].items.add(c.entityName);\r\n    });\r\n    \r\n    const sortGroups = (groups) => Object.values(groups).sort((a,b) => {\r\n        let aW = a.level === 'red' ? 2 : (a.level === 'orange' ? 1 : 0);\r\n        let bW = b.level === 'red' ? 2 : (b.level === 'orange' ? 1 : 0);\r\n        return bW - aW;\r\n    });\r\n    \r\n    let assetDisplay = sortGroups(groupedAsset);\r\n    let crewDisplay = sortGroups(groupedCrew);\r\n\r\n    const generateHtml = (displayGroups) => {\r\n        let html = '';\r\n        displayGroups.forEach(g => {\r\n            let dotColor = (g.level === 'red' ? '#ef4444' : (g.level === 'orange' ? '#f97316' : '#f59e0b'));\r\n            let actionWord = (g.level === 'red') ? 'shortages' : 'turnaround overlaps';\r\n            let desc = g.isAsset \r\n                ? `<b>${g.count}x</b> ${actionWord} between ${g.pairNames}. Includes: ${Array.from(g.items).slice(0, 3).join(', ')}${g.items.size > 3 ? '...' : ''}` \r\n                : `<b>${g.count}x</b> rest violations or overlaps between ${g.pairNames}.`;\r\n            html += `\r\n            <div class=\"conflict-item\" onclick=\"routeConflict('${g.type}', null, '${g.projectId}')\">\r\n                <div class=\"conflict-item-title\">\r\n                    <span style=\"display:flex; align-items:center; gap:6px;\"><div style=\"width:8px; height:8px; border-radius:50%; background:${dotColor};\"></div> ${escapeHTML(g.title)} (${g.count})</span>\r\n                    <button class=\"btn-outline btn-sm\" style=\"border:none; color:#888; padding: 2px 6px !important; margin: 0; font-size: 11px !important; opacity:0.8; background:transparent !important;\" onmouseover=\"this.style.color='#fff'; this.style.background='rgba(255,255,255,0.1)'\" onmouseout=\"this.style.color='#888'; this.style.background='transparent'\" onclick=\"event.stopPropagation(); muteConflict('${g.projectId}', '${g.type}')\" title=\"Ignore this conflict\">✖ IGNORE</button>\r\n                </div>\r\n                <div class=\"conflict-item-desc\">${desc}</div>\r\n            </div>`;\r\n        });\r\n        return html;\r\n    };\r\n\r\n    let assetHtml = generateHtml(assetDisplay);\r\n    if (assetHtml === '') assetHtml = '<div style=\"padding: 15px; text-align: center; color: #888; font-size: 13px;\">No active asset shortages.</div>';\r\n    \r\n    let crewHtml = generateHtml(crewDisplay);\r\n    if (crewHtml === '') crewHtml = '<div style=\"padding: 15px; text-align: center; color: #888; font-size: 13px;\">No active crew conflicts.</div>';\r\n\r\n    let aList = document.getElementById('asset-conflict-drawer-list');\r\n    if (aList) aList.innerHTML = assetHtml;\r\n    \r\n    let cList = document.getElementById('crew-conflict-drawer-list');\r\n    if (cList) cList.innerHTML = crewHtml;\r\n\r\n    const setBadges = (id, counts) => {\r\n        let el = document.getElementById(id);\r\n        if (!el) return;\r\n        let bHtml = '';\r\n        if (counts.red > 0) bHtml += `<div class=\"conflict-badge-red\">${counts.red}</div>`;\r\n        if (counts.yellow > 0) bHtml += `<div class=\"conflict-badge-yellow\">${counts.yellow}</div>`;\r\n        if (counts.grey > 0) bHtml += `<div class=\"conflict-badge-grey\">${counts.grey}</div>`;\r\n        el.innerHTML = bHtml;\r\n    };\r\n\r\n    setBadges('asset-conflict-badges', assetCounts);\r\n    setBadges('crew-conflict-badges', crewCounts);\r\n}\r\n\r\nfunction routeConflict(type, entityId, projectId) {\r\n    if (typeof closeModals === 'function') closeModals();\r\n    \r\n    if (type === 'HARD_SHORTAGE' || type === 'SOFT_TURNAROUND') {\r\n        // Deep Route to Asset Vault\r\n        document.getElementById('edit-folder-id').value = projectId;\r\n        let ev = null;\r\n        if (typeof calendar !== 'undefined' && calendar) ev = calendar.getEventById(projectId);\r\n        if (ev) {\r\n            document.getElementById('edit-proj-name').value = ev.title;\r\n        } else {\r\n            try {\r\n                let p = JSON.parse(localStorage.getItem('sm_phantom_payload') || '{}').projects?.find(x => x.id === projectId);\r\n                if (p) document.getElementById('edit-proj-name').value = p.title;\r\n            } catch(e) {}\r\n        }\r\n        if (typeof openProjectAssetsModal === 'function') openProjectAssetsModal();\r\n    } else {\r\n        // Deep Route to Shift Timeline\r\n        if (typeof goToEventTimeline === 'function') goToEventTimeline(projectId, 'main');\r\n    }\r\n}\r\n\r\nwindow.muteConflict = function(projectId, type) {\r\n    if (!confirm(\"Are you sure you want to ignore this conflict? It will be hidden from the active drawer.\")) return;\r\n    \r\n    google.script.run\r\n        .withSuccessHandler(res => {\r\n            if (typeof refreshData === 'function') refreshData(); // Instantly update the UI and badges\r\n        })\r\n        .withFailureHandler(err => alert(\"Error muting conflict: \" + err.message))\r\n        .acknowledgeConflict(projectId, type, typeof ACTIVE_USER_NAME !== 'undefined' ? ACTIVE_USER_NAME : 'System UI');\r\n};\r\n\n\n\r\nlet activePayrollData = null;\r\nlet activeEnrichedShifts = [];\r\nlet currentPayrollView = 'person';\r\n\r\n// @INDEX: FINANCIALS -> Hub Boot & View Router\r\nfunction openFinancialsHub() {\r\n    if (typeof closeModals === 'function') {\r\n        if (!closeModals()) return;\r\n    }\r\n    let now = new Date();\r\n    let y = now.getFullYear();\r\n    let m = String(now.getMonth() + 1).padStart(2, '0');\r\n    let dLast = new Date(y, now.getMonth() + 1, 0).getDate();\r\n    document.getElementById('fin-payroll-start').value = `${y}-${m}-01`;\r\n    document.getElementById('fin-payroll-end').value = `${y}-${m}-${dLast}`;\r\n\r\n    document.getElementById('financials-hub-overlay').style.display = 'flex';\r\n    if (typeof updateActiveNav === 'function') updateActiveNav('nav-btn-financials');\r\n}\r\n\r\nfunction closeFinancialsHub() {\r\n    document.getElementById('financials-hub-overlay').style.display = 'none';\r\n    if (typeof updateActiveNav === 'function') updateActiveNav('nav-btn-dashboard');\r\n}\r\n\r\nfunction switchFinancialTab(tabId) {\r\n    document.getElementById('fin-content-payroll').style.display = 'none';\r\n    document.getElementById('fin-content-pnl').style.display = 'none';\r\n    document.getElementById('fin-content-settings').style.display = 'none';\r\n    \r\n    ['payroll', 'pnl', 'settings'].forEach(function(t) {\r\n        var btn = document.getElementById('fin-tab-btn-' + t);\r\n        if (btn) btn.classList.toggle('active', t === tabId);\r\n    });\r\n    \r\n    document.getElementById('fin-content-' + tabId).style.display = 'flex';\r\n    \r\n    if (tabId === 'settings') {\r\n        loadFinSettingsUI();\r\n    }\r\n}\r\n\r\nfunction switchPayrollView(view) {\r\n    document.getElementById('fin-payroll-view-person').style.display = 'none';\r\n    document.getElementById('fin-payroll-view-event').style.display = 'none';\r\n    \r\n    let btnPerson = document.getElementById('fin-view-btn-person');\r\n    let btnEvent = document.getElementById('fin-view-btn-event');\r\n    \r\n    if (view === 'person') {\r\n        document.getElementById('fin-payroll-view-person').style.display = 'flex';\r\n        btnPerson.classList.add('active');\r\n        btnEvent.classList.remove('active');\r\n        currentPayrollView = 'person';\r\n        if (activePayrollData) renderPayrollByPerson();\r\n    } else {\r\n        document.getElementById('fin-payroll-view-event').style.display = 'flex';\r\n        btnEvent.classList.add('active');\r\n        btnPerson.classList.remove('active');\r\n        currentPayrollView = 'event';\r\n        if (activePayrollData) renderPayrollByEvent();\r\n    }\r\n}\r\n\r\n// @INDEX: FINANCIALS -> Payroll & Labor Engine\r\nfunction calculatePayrollEngine() {\r\n    let startStr = document.getElementById('fin-payroll-start').value;\r\n    let endStr = document.getElementById('fin-payroll-end').value;\r\n    if (!startStr || !endStr) return alert(\"Select a start and end date.\");\r\n    \r\n    let btn = document.getElementById('btn-calc-payroll');\r\n    let orig = btn.innerText;\r\n    btn.innerText = \"CALCULATING...\"; btn.disabled = true;\r\n    \r\n    document.getElementById('fin-payroll-view-person').innerHTML = '<div style=\"text-align:center; padding: 40px; color: #10b981; font-weight:bold;\">Fetching and calculating real-time shifts...</div>';\r\n    document.getElementById('fin-payroll-view-event').innerHTML = '<div style=\"text-align:center; padding: 40px; color: #10b981; font-weight:bold;\">Fetching and calculating real-time shifts...</div>';\r\n    \r\n    google.script.run.withSuccessHandler(res => {\r\n        btn.innerText = orig; btn.disabled = false;\r\n        activePayrollData = res;\r\n        enrichShiftsWithMath(startStr, endStr);\r\n        if (currentPayrollView === 'person') renderPayrollByPerson();\r\n        else renderPayrollByEvent();\r\n    }).withFailureHandler(err => {\r\n        btn.innerText = orig; btn.disabled = false;\r\n        alert(\"Engine Error: \" + err.message);\r\n    }).getFinancialsData(startStr); // Sends startStr just to satisfy backend signature\r\n}\r\n\r\nlet finToggleState = {};\r\n\r\nfunction toggleFinEl(id) {\r\n    let el = document.getElementById(id);\r\n    let icon = document.getElementById('icon-' + id);\r\n    if (!el || !icon) return;\r\n    let isClosed = el.style.display === 'none';\r\n    let newState = isClosed ? 'block' : 'none';\r\n    el.style.display = newState;\r\n    icon.innerText = isClosed ? '▼' : '▶';\r\n    finToggleState[id] = newState;\r\n}\r\n\r\nfunction restoreFinToggles() {\r\n    Object.keys(finToggleState).forEach(id => {\r\n        let el = document.getElementById(id);\r\n        let icon = document.getElementById('icon-' + id);\r\n        if (el && icon) {\r\n            el.style.display = finToggleState[id];\r\n            icon.innerText = finToggleState[id] === 'none' ? '▶' : '▼';\r\n        }\r\n    });\r\n}\r\n\r\nlet globalUnpaidUids = new Set();\r\n\r\nfunction enrichShiftsWithMath(startStr, endStr) {\r\n    if (!activePayrollData) return;\r\n    let { crew, fleet, projects, shifts, timelines, settings, blocks } = activePayrollData;\r\n    let globals = settings.globals || {};\r\n    activeEnrichedShifts = [];\r\n\r\n    let projBaseDates = {};\r\n    timelines.forEach(t => {\r\n        if (!projBaseDates[t.Project_ID] || t.Event_Date < projBaseDates[t.Project_ID]) {\r\n            projBaseDates[t.Project_ID] = t.Event_Date;\r\n        }\r\n    });\r\n\r\n    shifts.forEach(s => {\r\n        let pDateStr = projBaseDates[s.projectId];\r\n        if (!pDateStr) return;\r\n        \r\n        let pDate = new Date(pDateStr + \"T00:00:00Z\"); \r\n        let dayOffset = Math.floor(Number(s.start) / 24);\r\n        let shiftDate = new Date(pDate.getTime() + (dayOffset * 86400000));\r\n        \r\n        let shiftIso = `${shiftDate.getUTCFullYear()}-${String(shiftDate.getUTCMonth()+1).padStart(2,'0')}-${String(shiftDate.getUTCDate()).padStart(2,'0')}`;\r\n        \r\n        let isGlobalUnpaid = globalUnpaidUids.has(s.email) && (s.status !== 'Paid' || (s.status === 'Paid' && parseFloat(s.amount) === 0));\r\n        if ((shiftIso >= startStr && shiftIso <= endStr) || isGlobalUnpaid) {\r\n            s.exactDateStr = shiftIso;\r\n            s.exactDateObj = shiftDate;\r\n\r\n            let vehicle = (fleet || []).find(f => f.uid === s.email);\r\n            if (vehicle) {\r\n                let proj = projects.find(p => p.id === s.projectId) || { id: s.projectId, name: 'Unknown Event', diffMult: 1.0, readinessState: '{}' };\r\n                let rState = {};\r\n                try { rState = JSON.parse(proj.readinessState); } catch(e){}\r\n                let inSofia = rState.inSofia !== false;\r\n                let dist = parseFloat(rState.distanceKm) || 0;\r\n                \r\n                let tMatch = vehicle.tier ? vehicle.tier.match(/Tier (\\d)/i) : null;\r\n                let tKey = tMatch ? 'truck_t' + tMatch[1] : 'truck_t1';\r\n                let trucksConfig = settings.trucks || {};\r\n                \r\n                let isStay = (s.role && s.role.toUpperCase() === 'STAY') || (s.note && s.note.toUpperCase().includes('STAY'));\r\n                let finalVal = 0;\r\n                let bd = `<div style=\"font-size:11px; color:#a1a1aa; line-height:1.4;\">`;\r\n                \r\n                let dur = parseFloat(s.duration) || 0;\r\n                if (isStay) {\r\n                    let stayDays = Math.ceil(dur / 24);\r\n                    if (stayDays < 1) stayDays = 1;\r\n                    let rate = parseFloat(trucksConfig[tKey + '_stay']) || 0;\r\n                    finalVal = stayDays * rate;\r\n                    bd += `<div style=\"display:flex; justify-content:space-between; color:#06b6d4;\"><span>Stay Duration:</span><span>${stayDays} Day(s)</span></div>`;\r\n                    bd += `<div style=\"display:flex; justify-content:space-between;\"><span>Rate (${vehicle.tier}):</span><span style=\"color:#e4e4e7;\">€${rate.toFixed(2)} / day</span></div>`;\r\n                } else {\r\n                    let projTruckShifts = shifts.filter(ts => ts.projectId === s.projectId && ts.email === s.email && ts.role !== 'STAY' && (!ts.note || !ts.note.toUpperCase().includes('STAY')));\r\n                    projTruckShifts.sort((a,b) => Number(a.start) - Number(b.start));\r\n                    let sIndex = projTruckShifts.findIndex(ts => ts.id === s.id);\r\n                    \r\n                    let roleText = s.role;\r\n                    if (roleText !== 'LOAD' && roleText !== 'UNLOAD') {\r\n                        roleText = (sIndex % 2 === 0) ? 'LOAD' : 'UNLOAD';\r\n                    }\r\n                    \r\n                    if (roleText === 'UNLOAD') {\r\n                        return; // User explicitly requested not to see UNLOAD zero-value shifts\r\n                    } else {\r\n                        bd += `<div style=\"display:flex; justify-content:space-between; color:#888;\"><span>Leg Phase:</span><span>LOAD</span></div>`;\r\n                        if (inSofia) {\r\n                            let rate = parseFloat(trucksConfig[tKey + '_in']) || 0;\r\n                            finalVal = rate;\r\n                            bd += `<div style=\"display:flex; justify-content:space-between; color:#10b981;\"><span>Location:</span><span>In Sofia</span></div>`;\r\n                            bd += `<div style=\"display:flex; justify-content:space-between;\"><span>Course Rate (${vehicle.tier}):</span><span style=\"color:#e4e4e7;\">€${rate.toFixed(2)}</span></div>`;\r\n                        } else {\r\n                            let rate = parseFloat(trucksConfig[tKey + '_out']) || 0;\r\n                            finalVal = rate * dist;\r\n                            bd += `<div style=\"display:flex; justify-content:space-between; color:#f59e0b;\"><span>Distance:</span><span>${dist} km</span></div>`;\r\n                            bd += `<div style=\"display:flex; justify-content:space-between;\"><span>Rate (${vehicle.tier}):</span><span style=\"color:#e4e4e7;\">€${rate.toFixed(2)} / km</span></div>`;\r\n                        }\r\n                    }\r\n                }\r\n                \r\n                let rawTotal = finalVal;\r\n                let isPaid = s.status === 'Paid';\r\n                \r\n                if (isPaid && parseFloat(s.amount) > 0) {\r\n                    finalVal = parseFloat(s.amount);\r\n                    rawTotal = finalVal;\r\n                } else {\r\n                    finalVal = rawTotal;\r\n                }\r\n                \r\n                bd = `<div style=\"font-size:14px; color:#e4e4e7; line-height:1.5; font-family: monospace; white-space: pre;\">`;\r\n                bd += `  Base Value: €${rawTotal.toFixed(2)}\\n`;\r\n                bd += `</div>`;\r\n                \r\n                let formatT = (hr) => { let h = Math.floor(hr); let m = Math.round((hr - h)*60); if (h >= 24) h -= 24; return String(h).padStart(2, '0') + \":\" + String(m).padStart(2, '0'); };\r\n                let sStartHr = Number(s.start) % 24;\r\n                \r\n                s.math = { shiftType: isStay ? 'stay' : 'drive', shiftTypeDisplay: isStay ? 'STAY (IDLE)' : 'DRIVE (COURSE)', timeStr: `${formatT(sStartHr)} - ${formatT(sStartHr + dur)} (${dur.toFixed(1)}h)`, finalVal: finalVal, breakdownHtml: bd, isPaid: isPaid, isFleet: true };\r\n                s.person = { uid: vehicle.uid, name: vehicle.name, mult: 1.0, department: 'dept_trucks', role: vehicle.tier, isFleet: true };\r\n                s.proj = proj;\r\n                s.deptUid = 'dept_trucks';\r\n                activeEnrichedShifts.push(s);\r\n                return;\r\n            }\r\n\r\n            let shiftType = 'build';\r\n            let frag = timelines.find(t => t.Project_ID === s.projectId && t.Event_Date === shiftIso);\r\n            if (frag) {\r\n                if (frag.Sub_Event_Type === 'WAREHOUSE') {\r\n                    shiftType = 'prep';\r\n                } else if (frag.Sub_Event_Type === 'RECOVERY') {\r\n                    shiftType = 'recovery';\r\n                } else if (frag.Sub_Event_Type === 'MAIN_EVENT' || frag.Sub_Event_Type === 'SHOW_DAY') {\r\n                    let sStart = Number(s.start);\r\n                    let sEnd = sStart + Number(s.duration);\r\n                    let projBlocks = (blocks || []).filter(b => b.projectId === s.projectId);\r\n                    let intersectingBlock = null;\r\n                    let maxOverlap = 0;\r\n                    projBlocks.forEach(b => {\r\n                        let bStart = Number(b.start);\r\n                        let bEnd = bStart + Number(b.duration);\r\n                        let overlapStart = Math.max(sStart, bStart);\r\n                        let overlapEnd = Math.min(sEnd, bEnd);\r\n                        if (overlapStart < overlapEnd) {\r\n                            let overlap = overlapEnd - overlapStart;\r\n                            if (overlap > maxOverlap) { maxOverlap = overlap; intersectingBlock = b; }\r\n                        }\r\n                    });\r\n                    if (intersectingBlock) {\r\n                        let bName = intersectingBlock.phaseName ? intersectingBlock.phaseName.toLowerCase() : '';\r\n                        if (bName.includes('show') || bName.includes('rehearsal')) shiftType = 'duty';\r\n                        else if (bName.includes('break') || bName.includes('strike') || bName.includes('load out')) shiftType = 'break';\r\n                        else shiftType = 'build';\r\n                    }\r\n                }\r\n            } else { shiftType = 'prep'; }\r\n            \r\n            let baseRate = 0, baseHrs = 8, shiftMult = 1.0;\r\n            if (shiftType === 'prep') { baseRate = parseFloat(globals.prep_rate)||80; baseHrs = parseFloat(globals.prep_hours)||8; }\r\n            else if (shiftType === 'recovery') { baseRate = parseFloat(globals.recovery_rate)||80; baseHrs = parseFloat(globals.recovery_hours)||8; }\r\n            else if (shiftType === 'build') { baseRate = parseFloat(globals.build_rate)||100; baseHrs = parseFloat(globals.build_hours)||6; }\r\n            else if (shiftType === 'duty') { baseRate = parseFloat(globals.duty_rate)||120; baseHrs = parseFloat(globals.duty_hours)||8; }\r\n            else if (shiftType === 'break') { baseRate = parseFloat(globals.break_rate)||80; baseHrs = parseFloat(globals.break_hours)||4; }\r\n            \r\n            let roleRates = settings.roles ? settings.roles[s.role] : null;\r\n            if (roleRates && roleRates.mult !== undefined) shiftMult *= parseFloat(roleRates.mult);\r\n            \r\n            let otMult = parseFloat(globals.overtime_multiplier) || 1.5;\r\n            let otThreshold = parseFloat(globals.default_shift_period) || 12;\r\n            \r\n            let hourlyRate = 0;\r\n            if (shiftType === 'prep' || shiftType === 'recovery') {\r\n                let conf = parseFloat(globals.extra_rate_prep);\r\n                hourlyRate = !isNaN(conf) ? conf : (baseHrs > 0 ? (baseRate / baseHrs) : 0);\r\n            } else {\r\n                let conf = parseFloat(globals.extra_rate_standard);\r\n                hourlyRate = !isNaN(conf) ? conf : (baseHrs > 0 ? (baseRate / baseHrs) : 0);\r\n            }\r\n            \r\n            let dur = parseFloat(s.duration) || 0;\r\n            let stdExtraHrs = 0;\r\n            let otHrs = 0;\r\n            \r\n            if (dur > otThreshold) {\r\n                otHrs = dur - otThreshold;\r\n                stdExtraHrs = Math.max(0, otThreshold - baseHrs);\r\n            } else {\r\n                stdExtraHrs = Math.max(0, dur - baseHrs);\r\n            }\r\n            \r\n            let mathBase = baseRate;\r\n            let mathStd = stdExtraHrs * hourlyRate;\r\n            let mathOt = otHrs * hourlyRate * otMult;\r\n            \r\n            let roleBonus = 0;\r\n            if (s.role === 'Follow Spot') roleBonus = parseFloat(globals.followspot_bonus) || 0;\r\n            if (s.role === 'Operator') roleBonus = parseFloat(globals.console_bonus) || 0;\r\n            \r\n            let person = crew.find(c => c.uid === s.email);\r\n            let proj = projects.find(p => p.id === s.projectId);\r\n            \r\n            let personMult = person ? (person.mult || 1.0) : 1.0;\r\n            let projMult = proj ? (proj.diffMult || 1.0) : 1.0;\r\n            \r\n            let rawTotal = ((mathBase + mathStd + mathOt) * shiftMult) + roleBonus;\r\n            let finalVal = rawTotal * personMult * projMult;\r\n            \r\n            let isPaid = s.status === 'Paid';\r\n            if (isPaid && parseFloat(s.amount) > 0) finalVal = parseFloat(s.amount);\r\n            \r\n            let formatT = (hr) => {\r\n                let h = Math.floor(hr); let m = Math.round((hr - h)*60);\r\n                if (h >= 24) h -= 24;\r\n                return String(h).padStart(2, '0') + \":\" + String(m).padStart(2, '0');\r\n            };\r\n            let sStartHr = Number(s.start) % 24;\r\n            \r\n            let hasOuterParens = (personMult !== 1.0 || projMult !== 1.0);\r\n\r\n            let bd = `<div style=\"display:flex; align-items:center; flex-wrap:nowrap;\">`;\r\n\r\n            // Optional OUTER OPENING parenthesis\r\n            if (hasOuterParens) {\r\n                bd += `<div style=\"font-size:42px; font-weight:300; color:#888; line-height:0.8; margin-right:4px;\">(</div>`;\r\n            }\r\n\r\n            // Inner Big Parentheses Block\r\n            bd += `<div style=\"display:flex; align-items:center;\">`;\r\n            bd += `<div style=\"font-size:42px; font-weight:300; color:#555; line-height:0.8; margin-right:4px;\">(</div>`;\r\n            bd += `<div style=\"display:grid; grid-template-columns: auto auto auto auto auto; gap: 0 6px; text-align:left; font-family:monospace; font-size:16px; line-height:1.15; color:#e4e4e7; white-space:nowrap; align-items:center;\">`;\r\n            bd += `<div></div><div>Base</div><div>:</div><div style=\"text-align:right;\">€${mathBase.toFixed(2)}</div><div style=\"color:#888;\">(${baseHrs}h)</div>`;\r\n            if (stdExtraHrs > 0) bd += `<div>+</div><div>Extra</div><div>:</div><div style=\"text-align:right;\">€${mathStd.toFixed(2)}</div><div style=\"color:#888;\">(${stdExtraHrs.toFixed(1)}h)</div>`;\r\n            if (otHrs > 0) bd += `<div style=\"color:#ef4444\">+</div><div style=\"color:#ef4444\">OT</div><div style=\"color:#ef4444\">:</div><div style=\"color:#ef4444; text-align:right;\">€${mathOt.toFixed(2)}</div><div style=\"color:#888;\">(${otHrs.toFixed(1)}h)</div>`;\r\n            bd += `</div>`;\r\n            bd += `<div style=\"font-size:42px; font-weight:300; color:#555; line-height:0.8; margin-left:4px;\">)</div>`;\r\n            bd += `</div>`;\r\n\r\n            // Horizontal multipliers\r\n            bd += `<div style=\"display:flex; align-items:center; font-family:monospace; font-size:16px; margin-left:8px; gap:8px; white-space:nowrap;\">`;\r\n            if (shiftMult !== 1.0) bd += `<span style=\"color:#3b82f6;\">&times; Role(${shiftMult.toFixed(2)})</span>`;\r\n            if (roleBonus > 0) bd += `<span style=\"color:#f59e0b;\">+ Bonus(€${roleBonus.toFixed(2)})</span>`;\r\n            \r\n            // Optional OUTER CLOSING parenthesis\r\n            if (hasOuterParens) {\r\n                bd += `<div style=\"font-size:42px; font-weight:300; color:#888; line-height:0.8; margin-left:2px; margin-right:4px;\">)</div>`;\r\n            }\r\n\r\n            if (personMult !== 1.0) bd += `<span style=\"color:#10b981;\">&times; Person(${personMult.toFixed(2)})</span>`;\r\n            if (projMult !== 1.0) bd += `<span style=\"color:#a855f7;\">&times; Event(${projMult.toFixed(2)})</span>`;\r\n            bd += `</div>`;\r\n            bd += `</div>`;\r\n            \r\n            s.math = {\r\n                shiftType: shiftType,\r\n                shiftTypeDisplay: shiftType.toUpperCase(),\r\n                timeStr: `${formatT(sStartHr)} - ${formatT(sStartHr + dur)} (${dur.toFixed(1)}h)`,\r\n                finalVal: finalVal,\r\n                breakdownHtml: bd,\r\n                isPaid: isPaid\r\n            };\r\n            s.person = person || { uid: s.email, name: s.email, mult: 1.0, department: 'Unassigned', role: 'Unknown' };\r\n            s.proj = proj || { id: s.projectId, name: 'Unknown Event', diffMult: 1.0 };\r\n            s.deptUid = s.person.department || 'Unassigned';\r\n            \r\n            activeEnrichedShifts.push(s);\r\n        }\r\n    });\r\n}\r\n\r\nfunction renderPayrollByPerson() {\r\n    if (!activeEnrichedShifts) return;\r\n    let container = document.getElementById('fin-payroll-view-person');\r\n    let tree = {};\r\n    let anyData = false;\r\n    \r\n    activeEnrichedShifts.forEach(s => {\r\n        if (!tree[s.deptUid]) tree[s.deptUid] = { obj: typeof getDeptObj === 'function' ? getDeptObj(s.deptUid) : { name: s.deptUid, color: '#888' }, persons: {} };\r\n        if (!tree[s.deptUid].persons[s.person.uid]) tree[s.deptUid].persons[s.person.uid] = { obj: s.person, events: {} };\r\n        if (!tree[s.deptUid].persons[s.person.uid].events[s.proj.id]) tree[s.deptUid].persons[s.person.uid].events[s.proj.id] = { obj: s.proj, shifts: [] };\r\n        \r\n        tree[s.deptUid].persons[s.person.uid].events[s.proj.id].shifts.push(s);\r\n    });\r\n    \r\n    let html = '';\r\n    let sortedDepts = Object.keys(tree).sort((a,b) => tree[a].obj.name.localeCompare(tree[b].obj.name));\r\n    \r\n    sortedDepts.forEach(deptUid => {\r\n        anyData = true;\r\n        let dept = tree[deptUid];\r\n        let safeDept = deptUid.replace(/[^a-zA-Z0-9]/g, '-');\r\n        \r\n        let deptTotal = 0;\r\n        let personsHtml = '';\r\n        let sortedPersons = Object.keys(dept.persons).sort((a,b) => dept.persons[a].obj.name.localeCompare(dept.persons[b].obj.name));\r\n        \r\n        sortedPersons.forEach(pUid => {\r\n            let person = dept.persons[pUid];\r\n            let safePerson = pUid.replace(/[^a-zA-Z0-9]/g, '-');\r\n            let personTotal = 0;\r\n            let eventsHtml = '';\r\n            let sortedEvents = Object.keys(person.events).sort((a,b) => person.events[a].obj.name.localeCompare(person.events[b].obj.name));\r\n            \r\n            let personAllPaid = true;\r\n            sortedEvents.forEach(evId => {\r\n                person.events[evId].shifts.forEach(s => {\r\n                    if(!s.math.isPaid) personAllPaid = false;\r\n                });\r\n            });\r\n            \r\n            sortedEvents.forEach(evId => {\r\n                let ev = person.events[evId];\r\n                let safeEv = evId.replace(/[^a-zA-Z0-9]/g, '-');\r\n                let evTotal = 0;\r\n                let evAllPaid = ev.shifts.every(s => s.math.isPaid);\r\n                \r\n                let shiftsHtml = `\r\n                <div style=\"overflow-x:auto;\">\r\n                    <table style=\"width:100%; border-collapse:collapse; font-size:12px; text-align:left;\">\r\n                        <thead>\r\n                            <tr style=\"background:#111; color:#888; border-bottom:1px solid #333; text-transform:uppercase; font-size:10px; letter-spacing:0.5px;\">\r\n                                <th style=\"padding:10px 15px;\">Date & Time</th>\r\n                                <th style=\"padding:10px;\">Role & Phase</th>\r\n                                <th style=\"padding:10px; width:200px;\">Mathematical Breakdown</th>\r\n                                <th style=\"padding:10px 15px; text-align:right;\">Final Shift Payout</th>\r\n                                <th style=\"padding:10px 15px; text-align:center;\">Action</th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>`;\r\n                \r\n                ev.shifts.sort((a,b) => new Date(a.exactDateStr).getTime() - new Date(b.exactDateStr).getTime() || a.start - b.start).forEach(s => {\r\n                    evTotal += s.math.finalVal;\r\n                    \r\n                    let dObj = new Date(s.exactDateStr + \"T00:00:00Z\");\r\n                    let formattedDate = `${String(dObj.getUTCDate()).padStart(2, '0')}.${String(dObj.getUTCMonth() + 1).padStart(2, '0')}.${dObj.getUTCFullYear()}`;\r\n\r\n                    shiftsHtml += `\r\n                    <tr style=\"border-bottom:1px solid #222; background:#18181b;\" onmouseover=\"this.style.background='#27272a'\" onmouseout=\"this.style.background='#18181b'\">\r\n                        <td style=\"padding:12px 15px;\">\r\n                            <div style=\"color:#e4e4e7; font-weight:bold;\">${formattedDate}</div>\r\n                            <div style=\"color:#a1a1aa; font-size:11px; margin-top:4px;\">${s.math.timeStr}</div>\r\n                        </td>\r\n                        <td style=\"padding:12px 10px;\">\r\n                            <div style=\"color:#fff; font-weight:bold;\">${s.role}</div>\r\n                            <div style=\"color:#888; font-size:10px; margin-top:4px; text-transform:uppercase;\">${s.math.shiftTypeDisplay}</div>\r\n                        </td>\r\n                        <td style=\"padding:12px 10px;\">\r\n                            ${s.math.breakdownHtml}\r\n                        </td>\r\n                        <td style=\"padding:12px 15px; text-align:right;\">\r\n                            <div style=\"display:flex; align-items:center; justify-content:flex-end;\">€ <input type=\"number\" step=\"0.01\" id=\"pay-total-${s.id}\" class=\"pay-total-${safePerson} pay-total-ev-${safeEv}\" value=\"${s.math.finalVal.toFixed(2)}\" oninput=\"markShiftManual('${s.person.uid}', '${s.proj.id}')\" style=\"width:80px; background:#111; border:1px solid #10b981; color:#10b981; padding:6px; border-radius:4px; margin-left:4px; font-weight:900; text-align:right; font-size:14px; outline:none;\" ${s.math.isPaid ? 'disabled' : ''}></div>\r\n                        </td>\r\n                        <td style=\"padding:12px 15px; text-align:center;\">\r\n                            ${s.math.isPaid \r\n                              ? getPaidButtonHtml(s.id) \r\n                              : `<button class=\"btn-main btn-sm\" id=\"pay-btn-${s.id}\" onclick=\"approveAndPayShift('${s.id}')\" style=\"margin:0; padding:4px 8px !important;\">PAY SHIFT</button>`\r\n                            }\r\n                        </td>\r\n                    </tr>`;\r\n                });\r\n                shiftsHtml += `</tbody></table></div>`;\r\n                personTotal += evTotal;\r\n                \r\n                eventsHtml += `\r\n                <div style=\"background:#1a1a1e; border:1px solid #333; border-radius:6px; overflow:hidden; margin-bottom:15px;\">\r\n                    <div style=\"padding:10px 15px; background:rgba(255,255,255,0.03); border-bottom:1px solid #333; display:flex; justify-content:space-between; align-items:center;\">\r\n                        <div style=\"color:#e4e4e7; font-weight:bold; font-size:13px;\">${ev.obj.name}</div>\r\n                        <div style=\"display:flex; align-items:center; gap:15px;\">\r\n                            <div style=\"color:#f59e0b; font-size:11px; font-weight:bold;\">EVENT MULT: <input type=\"number\" step=\"0.1\" value=\"${ev.obj.diffMult.toFixed(1)}\" onchange=\"updateGlobalEventMult('${ev.obj.id}', this.value)\" style=\"width:40px; background:transparent; border:1px dashed #f59e0b; color:#f59e0b; padding:2px; border-radius:4px; font-weight:bold; text-align:center; outline:none;\">x</div>\r\n                            ${getBulkPayButtonHtml(pUid, evId, 'event', evAllPaid, 'PAY FULL EVENT')}\r\n                        </div>\r\n                    </div>\r\n                    ${shiftsHtml}\r\n                </div>`;\r\n            });\r\n            deptTotal += personTotal;\r\n            \r\n            personsHtml += `\r\n            <div style=\"margin-bottom:10px; border:1px solid #333; border-radius:8px; overflow:hidden;\">\r\n                <div onclick=\"toggleFinEl('person-${safePerson}')\" style=\"background:#18181b; padding:15px; cursor:pointer; display:flex; justify-content:space-between; align-items:center; transition:background 0.2s;\" onmouseover=\"this.style.background='#222'\" onmouseout=\"this.style.background='#18181b'\">\r\n                    <div style=\"display:flex; align-items:center; gap:15px;\">\r\n                        <span id=\"icon-person-${safePerson}\" style=\"color:#a1a1aa; font-size:12px; width:12px; text-align:center;\">▶</span>\r\n                            <span style=\"font-size:24px;\">${person.obj.isFleet ? '🚚' : '👤'}</span>\r\n                        <div>\r\n                            <div style=\"color:#fff; font-weight:900; font-size:16px;\">${person.obj.name}</div>\r\n                                <div style=\"color:#a855f7; font-size:11px; font-weight:bold; text-transform:uppercase;\">${person.obj.role} ${person.obj.isFleet ? '' : `<span style=\"color:#888; font-weight:normal;\">| Personal Mult: <span style=\"color:#fff;\">${person.obj.mult.toFixed(1)}x</span></span>`}</div>\r\n                        </div>\r\n                    </div>\r\n                    <div style=\"display:flex; align-items:center; gap:15px; text-align:right;\">\r\n                        ${getBulkPayButtonHtml(pUid, 'ALL', 'person_all', personAllPaid, 'PAY ALL PERSON')}\r\n                        <button class=\"btn-outline\" onclick=\"showGlobalUnpaid('${person.obj.uid}', '${person.obj.name.replace(/'/g, \"\\\\'\")}'); event.stopPropagation();\" style=\"margin:0; border-color:#ef4444; color:#ef4444;\">SHOW ALL UNPAID</button>\r\n                        <div>\r\n                            <div style=\"color:#888; font-size:10px; text-transform:uppercase; font-weight:bold;\">Total Payout</div>\r\n                            <div id=\"grand-total-${pUid}\" style=\"color:#10b981; font-weight:900; font-size:20px;\">€ ${personTotal.toFixed(2)}</div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div id=\"person-${safePerson}\" style=\"display:none; padding:15px; background:#0a0a0c;\">\r\n                    ${eventsHtml}\r\n                </div>\r\n            </div>`;\r\n        });\r\n        \r\n        html += `\r\n        <div style=\"margin-bottom:20px;\">\r\n            <div onclick=\"toggleFinEl('dept-${safeDept}')\" style=\"background:#1f1f23; color:#fff; cursor:pointer; border:1px solid ${dept.obj.color}; border-left:4px solid ${dept.obj.color}; padding:10px 15px; font-size:12px; font-weight:900; text-transform:uppercase; display:flex; justify-content:space-between; align-items:center; border-radius:4px;\">\r\n                <div><span id=\"icon-dept-${safeDept}\" style=\"margin-right:10px; display:inline-block; width:12px;\">▼</span> ${dept.obj.name}</div>\r\n                <div style=\"color:${dept.obj.color}; font-weight:900;\">€ ${deptTotal.toFixed(2)}</div>\r\n            </div>\r\n            <div id=\"dept-${safeDept}\" style=\"padding-top:10px;\">\r\n                ${personsHtml}\r\n            </div>\r\n        </div>`;\r\n    });\r\n    \r\n    if (!anyData) html = '<div style=\"text-align:center; padding: 40px; color: #888;\">No shifts found for this date range.</div>';\r\n    container.innerHTML = html;\r\n    restoreFinToggles();\r\n}\r\n\r\nfunction renderPayrollByEvent() {\r\n    if (!activeEnrichedShifts) return;\r\n    let container = document.getElementById('fin-payroll-view-event');\r\n    let tree = {};\r\n    let anyData = false;\r\n    \r\n    activeEnrichedShifts.forEach(s => {\r\n        if (!tree[s.proj.id]) tree[s.proj.id] = { obj: s.proj, depts: {} };\r\n        if (!tree[s.proj.id].depts[s.deptUid]) tree[s.proj.id].depts[s.deptUid] = { obj: typeof getDeptObj === 'function' ? getDeptObj(s.deptUid) : { name: s.deptUid, color: '#888' }, persons: {} };\r\n        if (!tree[s.proj.id].depts[s.deptUid].persons[s.person.uid]) tree[s.proj.id].depts[s.deptUid].persons[s.person.uid] = { obj: s.person, shifts: [] };\r\n        \r\n        tree[s.proj.id].depts[s.deptUid].persons[s.person.uid].shifts.push(s);\r\n    });\r\n    \r\n    let html = '';\r\n    let sortedEvents = Object.keys(tree).sort((a,b) => tree[a].obj.name.localeCompare(tree[b].obj.name));\r\n    \r\n    sortedEvents.forEach(evId => {\r\n        anyData = true;\r\n        let ev = tree[evId];\r\n        let safeEv = evId.replace(/[^a-zA-Z0-9]/g, '-');\r\n        \r\n        let evTotal = 0;\r\n        let deptsHtml = '';\r\n        let sortedDepts = Object.keys(ev.depts).sort((a,b) => ev.depts[a].obj.name.localeCompare(ev.depts[b].obj.name));\r\n        \r\n        sortedDepts.forEach(deptUid => {\r\n            let dept = ev.depts[deptUid];\r\n            let deptTotal = 0;\r\n            let personsHtml = '';\r\n            let sortedPersons = Object.keys(dept.persons).sort((a,b) => dept.persons[a].obj.name.localeCompare(dept.persons[b].obj.name));\r\n            \r\n            sortedPersons.forEach(pUid => {\r\n                let person = dept.persons[pUid];\r\n                let safePerson = pUid.replace(/[^a-zA-Z0-9]/g, '-');\r\n                let personTotal = 0;\r\n                let personEvAllPaid = person.shifts.every(s => s.math.isPaid);\r\n                \r\n                let shiftsHtml = `\r\n                <div style=\"overflow-x:auto;\">\r\n                    <table style=\"width:100%; border-collapse:collapse; font-size:14px; text-align:left;\">\r\n                        <thead>\r\n                            <tr style=\"background:#111; color:#888; border-bottom:1px solid #333; text-transform:uppercase; font-size:11px; letter-spacing:0.5px;\">\r\n                                <th style=\"padding:10px 15px;\">Date & Time</th>\r\n                                <th style=\"padding:10px;\">Role & Phase</th>\r\n                                <th style=\"padding:10px;\">Mathematical Breakdown</th>\r\n                                <th style=\"padding:10px 15px; text-align:right;\">Final Shift Payout</th>\r\n                                <th style=\"padding:10px 15px; text-align:center;\">Action</th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>`;\r\n                \r\n                person.shifts.sort((a,b) => new Date(a.exactDateStr).getTime() - new Date(b.exactDateStr).getTime() || a.start - b.start).forEach(s => {\r\n                    personTotal += s.math.finalVal;\r\n                    \r\n                    let dObj = new Date(s.exactDateStr + \"T00:00:00Z\");\r\n                    let formattedDate = `${String(dObj.getUTCDate()).padStart(2, '0')}.${String(dObj.getUTCMonth() + 1).padStart(2, '0')}.${dObj.getUTCFullYear()}`;\r\n\r\n                    shiftsHtml += `\r\n                    <tr style=\"border-bottom:1px solid #222; background:#18181b;\" onmouseover=\"this.style.background='#27272a'\" onmouseout=\"this.style.background='#18181b'\">\r\n                        <td style=\"padding:12px 15px;\">\r\n                            <div style=\"color:#e4e4e7; font-weight:bold; font-size:15px;\">${formattedDate}</div>\r\n                            <div style=\"color:#a1a1aa; font-size:13px; margin-top:4px;\">${s.math.timeStr}</div>\r\n                        </td>\r\n                        <td style=\"padding:12px 10px;\">\r\n                            <div style=\"color:#fff; font-weight:bold; font-size:15px;\">${s.role}</div>\r\n                            <div style=\"color:#888; font-size:12px; margin-top:4px; text-transform:uppercase;\">${s.math.shiftTypeDisplay}</div>\r\n                        </td>\r\n                        <td style=\"padding:12px 10px;\">\r\n                            ${s.math.breakdownHtml}\r\n                        </td>\r\n                        <td style=\"padding:12px 15px; text-align:right;\">\r\n                            <div style=\"display:flex; align-items:center; justify-content:flex-end;\">€ <input type=\"number\" step=\"0.01\" id=\"pay-total-${s.id}\" class=\"pay-total-${safePerson} pay-total-ev-${safeEv}\" value=\"${s.math.finalVal.toFixed(2)}\" oninput=\"markShiftManual('${s.person.uid}', '${s.proj.id}')\" style=\"width:80px; background:#111; border:1px solid #10b981; color:#10b981; padding:6px; border-radius:4px; margin-left:4px; font-weight:900; text-align:right; font-size:14px; outline:none;\" ${s.math.isPaid ? 'disabled' : ''}></div>\r\n                        </td>\r\n                        <td style=\"padding:12px 15px; text-align:center;\">\r\n                            ${s.math.isPaid \r\n                              ? getPaidButtonHtml(s.id) \r\n                              : `<button class=\"btn-main\" id=\"pay-btn-${s.id}\" onclick=\"approveAndPayShift('${s.id}')\" style=\"margin:0;\">PAY SHIFT</button>`\r\n                            }\r\n                        </td>\r\n                    </tr>`;\r\n                });\r\n                shiftsHtml += `</tbody></table></div>`;\r\n                deptTotal += personTotal;\r\n                \r\n                personsHtml += `\r\n                <div style=\"background:#1a1a1e; border:1px solid #333; border-radius:6px; overflow:hidden; margin-bottom:15px; margin-left:15px;\">\r\n                    <div style=\"padding:10px 15px; background:rgba(255,255,255,0.03); border-bottom:1px solid #333; display:flex; justify-content:space-between; align-items:center;\">\r\n                        <div style=\"display:flex; align-items:center; gap:10px;\">\r\n                            <span style=\"font-size:18px;\">${person.obj.isFleet ? '🚚' : '👤'}</span>\r\n                            <div>\r\n                                <div style=\"color:#e4e4e7; font-weight:bold; font-size:13px;\">${person.obj.name}</div>\r\n                                <div style=\"color:#a855f7; font-size:10px; font-weight:bold; text-transform:uppercase;\">${person.obj.role}</div>\r\n                            </div>\r\n                        </div>\r\n                        <div style=\"display:flex; align-items:center; gap:15px;\">\r\n                            <div id=\"subtotal-${safePerson}-${safeEv}\" style=\"color:#10b981; font-weight:900; font-size:14px;\">€ ${personTotal.toFixed(2)}</div>\r\n                            ${getBulkPayButtonHtml(pUid, evId, 'event', personEvAllPaid, 'PAY PERSON')}\r\n                        </div>\r\n                    </div>\r\n                    ${shiftsHtml}\r\n                </div>`;\r\n            });\r\n            \r\n            evTotal += deptTotal;\r\n            \r\n            deptsHtml += `\r\n            <div style=\"margin-bottom:10px;\">\r\n                <div onclick=\"toggleFinEl('ev-dept-${safeEv}-${deptUid.replace(/[^a-zA-Z0-9]/g, '-')}')\" style=\"background:#18181b; color:#fff; cursor:pointer; border:1px solid ${dept.obj.color}; border-left:4px solid ${dept.obj.color}; padding:8px 15px; font-size:11px; font-weight:900; text-transform:uppercase; display:flex; justify-content:space-between; align-items:center; border-radius:4px; margin-left:10px; margin-bottom:10px;\">\r\n                    <div><span id=\"icon-ev-dept-${safeEv}-${deptUid.replace(/[^a-zA-Z0-9]/g, '-')}\" style=\"margin-right:10px; display:inline-block; width:12px;\">▼</span> ${dept.obj.name}</div>\r\n                    <div style=\"color:${dept.obj.color}; font-weight:900;\">€ ${deptTotal.toFixed(2)}</div>\r\n                </div>\r\n                <div id=\"ev-dept-${safeEv}-${deptUid.replace(/[^a-zA-Z0-9]/g, '-')}\" style=\"padding-top:5px;\">\r\n                    ${personsHtml}\r\n                </div>\r\n            </div>`;\r\n        });\r\n        \r\n        let materialsHtml = '';\r\n        let matExpense = 0;\r\n        try {\r\n            let rState = JSON.parse(ev.obj.readinessState || '{}');\r\n            matExpense = parseFloat(rState.consumablesExpense) || 0;\r\n        } catch(e) {}\r\n        \r\n        if (matExpense > 0) {\r\n            materialsHtml = `\r\n            <div style=\"margin-top:20px; border-top:1px dashed #333; padding-top:15px;\">\r\n                <div style=\"display:flex; justify-content:space-between; align-items:center; background:rgba(239,68,68,0.05); border:1px solid rgba(239,68,68,0.2); padding:10px 15px; border-radius:6px;\">\r\n                    <div style=\"display:flex; align-items:center; gap:10px;\">\r\n                        <span style=\"font-size:18px;\">✂️</span>\r\n                        <div>\r\n                            <div style=\"color:#f87171; font-weight:bold; font-size:13px;\">Materials Expense</div>\r\n                            <div style=\"color:#888; font-size:11px;\">Consumables used during the event</div>\r\n                        </div>\r\n                    </div>\r\n                    <div style=\"color:#ef4444; font-weight:900; font-size:16px;\">€ ${matExpense.toFixed(2)}</div>\r\n                </div>\r\n            </div>`;\r\n        }\r\n\r\n        html += `\r\n        <div style=\"margin-bottom:20px; border:1px solid #333; border-radius:8px; overflow:hidden;\">\r\n            <div onclick=\"toggleFinEl('ev-${safeEv}')\" style=\"background:#1f1f23; padding:15px; cursor:pointer; display:flex; justify-content:space-between; align-items:center; transition:background 0.2s;\" onmouseover=\"this.style.background='#222'\" onmouseout=\"this.style.background='#1f1f23'\">\r\n                <div style=\"display:flex; align-items:center; gap:15px;\">\r\n                    <span id=\"icon-ev-${safeEv}\" style=\"color:#a1a1aa; font-size:12px; width:12px; text-align:center;\">▶</span>\r\n                    <span style=\"font-size:24px;\">📅</span>\r\n                    <div>\r\n                        <div style=\"color:#fff; font-weight:900; font-size:16px;\">${ev.obj.name}</div>\r\n                    </div>\r\n                </div>\r\n                <div style=\"display:flex; align-items:center; gap:20px;\">\r\n                    <div style=\"color:#f59e0b; font-size:11px; font-weight:bold;\" onclick=\"event.stopPropagation()\">\r\n                        EVENT MULT: <input type=\"number\" step=\"0.1\" value=\"${ev.obj.diffMult.toFixed(1)}\" onchange=\"updateGlobalEventMult('${ev.obj.id}', this.value)\" style=\"width:40px; background:transparent; border:1px dashed #f59e0b; color:#f59e0b; padding:2px; border-radius:4px; font-weight:bold; text-align:center; outline:none;\">x\r\n                    </div>\r\n                    <div style=\"text-align:right;\">\r\n                        <div style=\"color:#888; font-size:10px; text-transform:uppercase; font-weight:bold;\">Total Event Payout</div>\r\n                        <div id=\"grand-total-ev-${safeEv}\" style=\"color:#10b981; font-weight:900; font-size:20px;\">€ ${evTotal.toFixed(2)}</div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div id=\"ev-${safeEv}\" style=\"display:none; padding:15px; background:#0a0a0c;\">\r\n                ${deptsHtml}\r\n                ${materialsHtml}\r\n            </div>\r\n        </div>`;\r\n    });\r\n    \r\n    if (!anyData) html = '<div style=\"text-align:center; padding: 40px; color: #888;\">No shifts found for this date range.</div>';\r\n    container.innerHTML = html;\r\n    restoreFinToggles();\r\n}\r\n\r\n// @INDEX: FINANCIALS -> Interactive Ledger & Payments\r\nfunction markShiftManual(uid, evId) {\r\n    recalcGrandTotal(uid);\r\n    recalcEventGrandTotal(evId);\r\n    recalcEventPersonTotal(evId, uid);\r\n}\r\n\r\nfunction recalcGrandTotal(uid) {\r\n    let safePerson = uid.replace(/[^a-zA-Z0-9]/g, '-');\r\n    let grandTotal = 0;\r\n    let inputs = document.querySelectorAll(`.pay-total-${safePerson}`);\r\n    inputs.forEach(inp => {\r\n        grandTotal += parseFloat(inp.value) || 0;\r\n    });\r\n    let gtEl = document.getElementById(`grand-total-${uid}`);\r\n    if (gtEl) gtEl.innerText = `€ ${grandTotal.toFixed(2)}`;\r\n}\r\n\r\nfunction recalcEventGrandTotal(evId) {\r\n    let safeEv = evId.replace(/[^a-zA-Z0-9]/g, '-');\r\n    let grandTotal = 0;\r\n    let inputs = document.querySelectorAll(`.pay-total-ev-${safeEv}`);\r\n    inputs.forEach(inp => {\r\n        grandTotal += parseFloat(inp.value) || 0;\r\n    });\r\n    let gtEl = document.getElementById(`grand-total-ev-${safeEv}`);\r\n    if (gtEl) gtEl.innerText = `€ ${grandTotal.toFixed(2)}`;\r\n}\r\n\r\nfunction recalcEventPersonTotal(evId, pUid) {\r\n    let safeEv = evId.replace(/[^a-zA-Z0-9]/g, '-');\r\n    let safePerson = pUid.replace(/[^a-zA-Z0-9]/g, '-');\r\n    let total = 0;\r\n    let inputs = document.querySelectorAll(`.pay-total-${safePerson}.pay-total-ev-${safeEv}`);\r\n    inputs.forEach(inp => {\r\n        total += parseFloat(inp.value) || 0;\r\n    });\r\n    let subEl = document.getElementById(`subtotal-${safePerson}-${safeEv}`);\r\n    if (subEl) subEl.innerText = `€ ${total.toFixed(2)}`;\r\n}\r\n\r\nfunction updateGlobalEventMult(projId, newMult) {\r\n    let mult = parseFloat(newMult) || 1.0;\r\n    let proj = activePayrollData.projects.find(p => p.id === projId);\r\n    if (proj) proj.diffMult = mult;\r\n    \r\n    let startStr = document.getElementById('fin-payroll-start').value;\r\n    let endStr = document.getElementById('fin-payroll-end').value;\r\n    enrichShiftsWithMath(startStr, endStr);\r\n    if (currentPayrollView === 'person') renderPayrollByPerson(); else renderPayrollByEvent();\r\n    \r\n    google.script.run\r\n        .withFailureHandler(err => alert(\"Failed to save Event Multiplier: \" + err.message))\r\n        .setProjectDifficultyMultiplier(projId, mult);\r\n}\r\n\r\nfunction approveAndPayShift(shiftId) {\r\n    let finalAmount = parseFloat(document.getElementById(`pay-total-${shiftId}`).value) || 0;\r\n    let btn = document.getElementById(`pay-btn-${shiftId}`);\r\n    let origText = btn.innerText;\r\n    btn.innerText = \"SAVING...\";\r\n    btn.disabled = true;\r\n    \r\n    let shift = activeEnrichedShifts.find(s => s.id === shiftId);\r\n    \r\n    if (!shift) {\r\n        alert(\"Shift not found.\");\r\n        btn.innerText = origText; btn.disabled = false;\r\n        return;\r\n    }\r\n    \r\n    google.script.run\r\n        .withSuccessHandler(res => {\r\n            btn.outerHTML = getPaidButtonHtml(shiftId);\r\n            \r\n            document.getElementById(`pay-total-${shiftId}`).disabled = true;\r\n            \r\n            shift.status = 'Paid';\r\n            shift.amount = finalAmount;\r\n            shift.math.isPaid = true;\r\n        })\r\n        .withFailureHandler(err => {\r\n            alert(\"Payment lock failed: \" + err.message);\r\n            btn.innerText = origText; btn.disabled = false;\r\n        })\r\n        .approveShiftPayments([shiftId], finalAmount.toFixed(2), \"Paid\");\r\n}\r\n\r\nfunction executeBulkPay(uid, evId, type, btnId) {\r\n    let btn = document.getElementById(btnId);\r\n    if(btn) { btn.innerText = \"SAVING...\"; btn.disabled = true; }\r\n    \r\n    let safePerson = uid.replace(/[^a-zA-Z0-9]/g, '-');\r\n    let safeEv = evId === 'ALL' ? '' : evId.replace(/[^a-zA-Z0-9]/g, '-');\r\n    \r\n    let selector = `.pay-total-${safePerson}`;\r\n    if (evId !== 'ALL') selector += `.pay-total-ev-${safeEv}`;\r\n    \r\n    let inputs = document.querySelectorAll(selector);\r\n    let allShifts = [];\r\n    let totalAmount = 0;\r\n    \r\n    let payload = [];\r\n    inputs.forEach(inp => {\r\n        if (inp.disabled) return; \r\n        let shiftId = inp.id.replace('pay-total-', '');\r\n        let amount = parseFloat(inp.value) || 0;\r\n        let shiftObj = activeEnrichedShifts.find(s => s.id === shiftId);\r\n        if (shiftObj) {\r\n            payload.push({ id: shiftId, amount: amount.toFixed(2), obj: shiftObj });\r\n            let sBtn = document.getElementById(`pay-btn-${shiftId}`);\r\n            if (sBtn) { sBtn.innerText = \"SAVING...\"; sBtn.disabled = true; }\r\n        }\r\n    });\r\n    \r\n    if (payload.length === 0) {\r\n        if(btn) { btn.innerText = \"PAY\"; btn.disabled = false; }\r\n        return;\r\n    }\r\n    \r\n    google.script.run\r\n        .withSuccessHandler(res => {\r\n            payload.forEach(item => {\r\n                let shiftId = item.id;\r\n                let shiftObj = item.obj;\r\n                shiftObj.status = 'Paid';\r\n                shiftObj.amount = item.amount;\r\n                shiftObj.math.isPaid = true;\r\n                let sBtn = document.getElementById(`pay-btn-${shiftId}`);\r\n                if (sBtn) sBtn.outerHTML = getPaidButtonHtml(shiftId);\r\n                let inputEl = document.getElementById(`pay-total-${shiftId}`);\r\n                if (inputEl) { inputEl.value = item.amount; inputEl.disabled = true; }\r\n            });\r\n            if (currentPayrollView === 'person') renderPayrollByPerson(); else renderPayrollByEvent();\r\n        })\r\n        .withFailureHandler(err => {\r\n            alert(\"Payment lock failed: \" + err.message);\r\n            if(btn) { btn.innerText = \"PAY\"; btn.disabled = false; }\r\n            payload.forEach(item => {\r\n                let sBtn = document.getElementById(`pay-btn-${item.id}`);\r\n                if (sBtn) { sBtn.innerText = \"PAY SHIFT\"; sBtn.disabled = false; }\r\n            });\r\n        })\r\n        .approveShiftPayments(payload.map(p => ({id: p.id, amount: p.amount})), \"\", \"Paid\");\r\n}\r\n\r\nlet unpayTimers = {};\r\n\r\nfunction getPaidButtonHtml(shiftId) {\r\n    return `<button class=\"btn-outline pay-paid-btn\" id=\"pay-btn-${shiftId}\" \r\n       onmousedown=\"startUnpay('${shiftId}')\" onmouseup=\"cancelUnpay('${shiftId}')\" onmouseleave=\"cancelUnpay('${shiftId}')\"\r\n       ontouchstart=\"startUnpay('${shiftId}')\" ontouchend=\"cancelUnpay('${shiftId}')\"\r\n       style=\"margin:0; border-color:#10b981; color:#10b981; position:relative; overflow:hidden; user-select:none; -webkit-user-select:none; cursor:pointer;\">\r\n       <span style=\"position:relative; z-index:2; pointer-events:none;\">PAID ✓</span>\r\n       <div id=\"unpay-progress-${shiftId}\" style=\"position:absolute; left:0; top:0; bottom:0; width:0%; background:rgba(239,68,68,0.5); z-index:1; pointer-events:none;\"></div>\r\n     </button>`;\r\n}\r\n\r\nfunction startUnpay(shiftId) {\r\n    let prog = document.getElementById(`unpay-progress-${shiftId}`);\r\n    let btn = document.getElementById(`pay-btn-${shiftId}`);\r\n    if(!prog || !btn) return;\r\n    \r\n    prog.style.transition = 'width 1.5s linear';\r\n    prog.style.width = '100%';\r\n    btn.style.borderColor = '#ef4444';\r\n    btn.style.color = '#ef4444';\r\n    \r\n    unpayTimers[shiftId] = setTimeout(() => {\r\n        unpayShift(shiftId);\r\n    }, 1500);\r\n}\r\n\r\nfunction cancelUnpay(shiftId) {\r\n    if(unpayTimers[shiftId]) {\r\n        clearTimeout(unpayTimers[shiftId]);\r\n        delete unpayTimers[shiftId];\r\n    }\r\n    let prog = document.getElementById(`unpay-progress-${shiftId}`);\r\n    let btn = document.getElementById(`pay-btn-${shiftId}`);\r\n    if(prog) {\r\n        prog.style.transition = 'width 0.2s linear';\r\n        prog.style.width = '0%';\r\n    }\r\n    if(btn) {\r\n        btn.style.borderColor = '#10b981';\r\n        btn.style.color = '#10b981';\r\n    }\r\n}\r\n\r\nfunction unpayShift(shiftId) {\r\n    let btn = document.getElementById(`pay-btn-${shiftId}`);\r\n    if(!btn) return;\r\n    let origText = btn.innerHTML;\r\n    btn.innerHTML = `<span style=\"position:relative; z-index:2; pointer-events:none;\">UNDOING...</span>`;\r\n    btn.disabled = true;\r\n    \r\n    let shift = activeEnrichedShifts.find(s => s.id === shiftId);\r\n    if (!shift) return;\r\n    \r\n    google.script.run\r\n        .withSuccessHandler(res => {\r\n            btn.outerHTML = `<button class=\"btn-main\" id=\"pay-btn-${shiftId}\" onclick=\"approveAndPayShift('${shiftId}')\" style=\"margin:0;\">PAY SHIFT</button>`;\r\n            let totInp = document.getElementById(`pay-total-${shiftId}`);\r\n            if(totInp) totInp.disabled = false;\r\n            shift.status = 'Pending';\r\n            shift.amount = '';\r\n            shift.math.isPaid = false;\r\n        })\r\n        .withFailureHandler(err => {\r\n            alert(\"Undo failed: \" + err.message);\r\n            btn.innerHTML = origText; \r\n            btn.disabled = false;\r\n            cancelUnpay(shiftId);\r\n        })\r\n        .approveShiftPayments([shiftId], \"\", \"Pending\");\r\n}\r\n\r\nlet bulkPayTimers = {};\r\n\r\nfunction getBulkPayButtonHtml(uid, evId, type, isAllPaid, label) {\r\n    let btnId = `bulk-pay-btn-${uid}-${evId}-${type}`;\r\n    if (!isAllPaid) {\r\n        return `<button class=\"btn-main btn-sm\" id=\"${btnId}\" onclick=\"executeBulkPay('${uid}', '${evId}', '${type}', '${btnId}')\" style=\"margin:0;\">${label}</button>`;\r\n    } else {\r\n        return `<button class=\"btn-outline btn-sm bulk-unpay-btn\" id=\"${btnId}\" \r\n           onmousedown=\"startBulkUnpay('${uid}', '${evId}', '${type}', '${btnId}', '${label}')\" onmouseup=\"cancelBulkUnpay('${btnId}')\" onmouseleave=\"cancelBulkUnpay('${btnId}')\"\r\n           ontouchstart=\"startBulkUnpay('${uid}', '${evId}', '${type}', '${btnId}', '${label}')\" ontouchend=\"cancelBulkUnpay('${btnId}')\"\r\n           style=\"margin:0; padding:4px 8px !important; border-color:#10b981; color:#10b981; position:relative; overflow:hidden; user-select:none; -webkit-user-select:none; cursor:pointer;\">\r\n           <span style=\"position:relative; z-index:2; pointer-events:none;\">PAID ✓</span>\r\n           <div id=\"bulk-unpay-progress-${btnId}\" style=\"position:absolute; left:0; top:0; bottom:0; width:0%; background:rgba(239,68,68,0.5); z-index:1; pointer-events:none;\"></div>\r\n         </button>`;\r\n    }\r\n}\r\n\r\nfunction startBulkUnpay(uid, evId, type, btnId, origLabel) {\r\n    let prog = document.getElementById(`bulk-unpay-progress-${btnId}`);\r\n    let btn = document.getElementById(btnId);\r\n    if(!prog || !btn) return;\r\n    \r\n    prog.style.transition = 'width 1.5s linear';\r\n    prog.style.width = '100%';\r\n    btn.style.borderColor = '#ef4444';\r\n    btn.style.color = '#ef4444';\r\n    \r\n    bulkPayTimers[btnId] = setTimeout(() => {\r\n        executeBulkUnpay(uid, evId, type, btnId, origLabel);\r\n    }, 1500);\r\n}\r\n\r\nfunction cancelBulkUnpay(btnId) {\r\n    if(bulkPayTimers[btnId]) {\r\n        clearTimeout(bulkPayTimers[btnId]);\r\n        delete bulkPayTimers[btnId];\r\n    }\r\n    let prog = document.getElementById(`bulk-unpay-progress-${btnId}`);\r\n    let btn = document.getElementById(btnId);\r\n    if(prog) {\r\n        prog.style.transition = 'width 0.2s linear';\r\n        prog.style.width = '0%';\r\n    }\r\n    if(btn) {\r\n        btn.style.borderColor = '#10b981';\r\n        btn.style.color = '#10b981';\r\n    }\r\n}\r\n\r\nfunction executeBulkUnpay(uid, evId, type, btnId, origLabel) {\r\n    let btn = document.getElementById(btnId);\r\n    if(btn) { btn.innerHTML = `<span style=\"position:relative; z-index:2; pointer-events:none;\">UNDOING...</span>`; btn.disabled = true; }\r\n    \r\n    let safePerson = uid.replace(/[^a-zA-Z0-9]/g, '-');\r\n    let safeEv = evId === 'ALL' ? '' : evId.replace(/[^a-zA-Z0-9]/g, '-');\r\n    \r\n    let selector = `.pay-total-${safePerson}`;\r\n    if (evId !== 'ALL') selector += `.pay-total-ev-${safeEv}`;\r\n    \r\n    let inputs = document.querySelectorAll(selector);\r\n    let allShifts = [];\r\n    \r\n    inputs.forEach(inp => {\r\n        let shiftId = inp.id.replace('pay-total-', '');\r\n        let shiftObj = activeEnrichedShifts.find(s => s.id === shiftId);\r\n        if (shiftObj && shiftObj.math.isPaid) {\r\n            allShifts.push(shiftObj);\r\n            let sBtn = document.getElementById(`pay-btn-${shiftId}`);\r\n            if (sBtn) { sBtn.innerHTML = `<span style=\"position:relative; z-index:2; pointer-events:none;\">UNDOING...</span>`; sBtn.disabled = true; }\r\n        }\r\n    });\r\n    \r\n    if (allShifts.length === 0) {\r\n        if(btn) { btn.outerHTML = getBulkPayButtonHtml(uid, evId, type, false, origLabel); }\r\n        return;\r\n    }\r\n    \r\n    let shiftIds = allShifts.map(s => s.id);\r\n    \r\n    google.script.run\r\n        .withSuccessHandler(res => {\r\n            allShifts.forEach(shiftObj => {\r\n                let shiftId = shiftObj.id;\r\n                shiftObj.status = 'Pending';\r\n                shiftObj.amount = '';\r\n                shiftObj.math.isPaid = false;\r\n                \r\n                let sBtn = document.getElementById(`pay-btn-${shiftId}`);\r\n                if (sBtn) sBtn.outerHTML = `<button class=\"btn-main\" id=\"pay-btn-${shiftId}\" onclick=\"approveAndPayShift('${shiftId}')\" style=\"margin:0;\">PAY SHIFT</button>`;\r\n                let inputEl = document.getElementById(`pay-total-${shiftId}`);\r\n                if (inputEl) { inputEl.disabled = false; }\r\n            });\r\n            if (currentPayrollView === 'person') renderPayrollByPerson(); else renderPayrollByEvent();\r\n        })\r\n        .withFailureHandler(err => {\r\n            alert(\"Undo failed: \" + err.message);\r\n            cancelBulkUnpay(btnId);\r\n            if (currentPayrollView === 'person') renderPayrollByPerson(); else renderPayrollByEvent();\r\n        })\r\n        .approveShiftPayments(shiftIds, \"\", \"Pending\");\r\n}\r\n\r\n// @INDEX: FINANCIALS -> Global Unpaid Viewer\r\nfunction showGlobalUnpaid(uid, name) {\r\n    globalUnpaidUids.add(uid);\r\n    let startStr = document.getElementById('fin-payroll-start').value;\r\n    let endStr = document.getElementById('fin-payroll-end').value;\r\n    enrichShiftsWithMath(startStr, endStr);\r\n    \r\n    if (currentPayrollView !== 'person') {\r\n        currentPayrollView = 'person';\r\n        document.getElementById('fin-tab-person').className = 'btn-main';\r\n        document.getElementById('fin-tab-event').className = 'btn-outline';\r\n        document.getElementById('fin-payroll-view-person').style.display = 'block';\r\n        document.getElementById('fin-payroll-view-event').style.display = 'none';\r\n    }\r\n    \r\n    let safePerson = uid.replace(/[^a-zA-Z0-9]/g, '-');\r\n    finToggleState['person-' + safePerson] = 'block';\r\n    \r\n    renderPayrollByPerson();\r\n}\r\n\r\n\r\n// @INDEX: FINANCIALS -> Settings & Overheads\r\nfunction loadFinSettingsUI() {\r\n    document.getElementById('fin-subtab-labor').style.opacity = '0.5';\r\n    google.script.run.withSuccessHandler(res => {\r\n        renderFinRolesUI(res.roles || {});\r\n        finOverheadsList = res.overheads || [];\r\n        renderFinOverheadsUI();\r\n        \r\n        let t = res.trucks || {};\r\n        const setV = (id, val) => { \r\n            let el = document.getElementById(id); \r\n            if (el) el.value = (val !== undefined && typeof val !== 'object') ? val : ''; \r\n        };\r\n        setV('fin-set-truck-t1-in', t.truck_t1_in); setV('fin-set-truck-t1-out', t.truck_t1_out); setV('fin-set-truck-t1-stay', t.truck_t1_stay);\r\n        setV('fin-set-truck-t2-in', t.truck_t2_in); setV('fin-set-truck-t2-out', t.truck_t2_out); setV('fin-set-truck-t2-stay', t.truck_t2_stay);\r\n        setV('fin-set-truck-t3-in', t.truck_t3_in); setV('fin-set-truck-t3-out', t.truck_t3_out); setV('fin-set-truck-t3-stay', t.truck_t3_stay);\r\n        setV('fin-set-truck-t4-in', t.truck_t4_in); setV('fin-set-truck-t4-out', t.truck_t4_out); setV('fin-set-truck-t4-stay', t.truck_t4_stay);\r\n\r\n        let g = res.globals || {};\r\n        setV('fin-set-prep-rate', g.prep_rate); setV('fin-set-prep-hours', g.prep_hours);\r\n        setV('fin-set-recovery-rate', g.recovery_rate); setV('fin-set-recovery-hours', g.recovery_hours);\r\n        setV('fin-set-build-rate', g.build_rate); setV('fin-set-build-hours', g.build_hours);\r\n        setV('fin-set-duty-rate', g.duty_rate); setV('fin-set-duty-hours', g.duty_hours);\r\n        setV('fin-set-break-rate', g.break_rate); setV('fin-set-break-hours', g.break_hours);\r\n        setV('fin-set-default-shift-period', g.default_shift_period);\r\n        setV('fin-set-overtime-multiplier', g.overtime_multiplier);\r\n        setV('fin-set-followspot-bonus', g.followspot_bonus);\r\n        setV('fin-set-console-bonus', g.console_bonus);\r\n        setV('fin-set-extra-rate-standard', g.extra_rate_standard !== undefined ? g.extra_rate_standard : 15);\r\n        setV('fin-set-extra-rate-prep', g.extra_rate_prep !== undefined ? g.extra_rate_prep : 15);\r\n\r\n        document.getElementById('fin-subtab-labor').style.opacity = '1';\r\n    }).getFinancialSettings();\r\n}\r\n\r\nfunction switchFinSubTab(tab) {\r\n    document.getElementById('fin-subtab-labor').style.display = 'none';\r\n    document.getElementById('fin-subtab-overheads').style.display = 'none';\r\n    \r\n    ['labor', 'overheads'].forEach(function(t) {\r\n        var btn = document.getElementById('fin-subtab-btn-' + t);\r\n        if (btn) btn.classList.toggle('active', t === tab);\r\n    });\r\n    \r\n    document.getElementById('fin-subtab-' + tab).style.display = 'flex';\r\n}\r\n\r\nfunction renderFinRolesUI(savedRoles) {\r\n    let html = '';\r\n    if (typeof ROLE_COLORS !== 'undefined') {\r\n        Object.keys(ROLE_COLORS).sort().forEach(role => {\r\n                let saved = savedRoles[role] || { mult: 1.0 };\r\n            let bgCol = ROLE_COLORS[role].bg || '#86efac';\r\n            html += `\r\n            <div class=\"fin-role-row\" data-role=\"${role.replace(/\"/g, '&quot;')}\" style=\"display:flex; flex-wrap:wrap; gap:10px; background:#222; padding:12px; border-radius:6px; border:1px solid #333; align-items:center;\">\r\n                <div style=\"flex:1; min-width:120px; display:flex; align-items:center; gap:8px;\">\r\n                    <span style=\"color:${bgCol}; font-weight:bold; font-size:13px;\">${role}</span>\r\n                </div>\r\n                    <div style=\"width:80px;\">\r\n                        <div class=\"input-label\" style=\"font-size:9px;\">Multiplier</div>\r\n                        <input type=\"number\" step=\"0.1\" class=\"role-mult\" value=\"${saved.mult !== undefined ? saved.mult : 1.0}\" style=\"padding:6px; width:100%; box-sizing:border-box;\" title=\"Role Multiplier\">\r\n                </div>\r\n            </div>`;\r\n        });\r\n    }\r\n    document.getElementById('fin-roles-container').innerHTML = html;\r\n}\r\n\r\nfunction addFinOverheadRow() {\r\n    finOverheadsList.push({ name: '', amount: 0, frequency: 'Monthly' });\r\n    renderFinOverheadsUI();\r\n}\r\n\r\nfunction renderFinOverheadsUI() {\r\n    let html = '';\r\n    finOverheadsList.forEach((item, idx) => {\r\n        html += `\r\n        <div style=\"display:flex; gap:10px; background:#222; padding:12px; border-radius:6px; border:1px solid #333; align-items:center;\">\r\n            <div style=\"flex:2;\">\r\n                <div class=\"input-label\" style=\"font-size:9px;\">Expense Name</div>\r\n                <input type=\"text\" value=\"${item.name.replace(/\"/g, '&quot;')}\" oninput=\"finOverheadsList[${idx}].name = this.value\" placeholder=\"e.g. Warehouse Rent\" style=\"padding:6px; width:100%; box-sizing:border-box;\">\r\n            </div>\r\n            <div style=\"flex:1;\">\r\n                <div class=\"input-label\" style=\"font-size:9px;\">Amount (€)</div>\r\n                <input type=\"number\" step=\"0.01\" value=\"${item.amount}\" oninput=\"finOverheadsList[${idx}].amount = parseFloat(this.value)||0\" style=\"padding:6px; width:100%; box-sizing:border-box;\">\r\n            </div>\r\n            <div style=\"flex:1;\">\r\n                <div class=\"input-label\" style=\"font-size:9px;\">Frequency</div>\r\n                <select onchange=\"finOverheadsList[${idx}].frequency = this.value\" style=\"padding:6px; width:100%; box-sizing:border-box; border-radius:4px; background:#111; color:#fff; border:1px solid #444; height:32px;\">\r\n                    <option value=\"Monthly\" ${item.frequency === 'Monthly' ? 'selected' : ''}>Monthly</option>\r\n                    <option value=\"Yearly\" ${item.frequency === 'Yearly' ? 'selected' : ''}>Yearly</option>\r\n                </select>\r\n            </div>\r\n            <button class=\"btn-delete\" style=\"margin-top:14px; padding:6px 12px !important;\" onclick=\"finOverheadsList.splice(${idx}, 1); renderFinOverheadsUI();\">X</button>\r\n        </div>`;\r\n    });\r\n    if(html === '') html = '<div style=\"color:#888; font-size:12px; font-style:italic; text-align:center; padding:20px;\">No overheads added.</div>';\r\n    document.getElementById('fin-overheads-container').innerHTML = html;\r\n}\r\n\r\nfunction handleSaveFinancialSettings() {\r\n    let btn = event.currentTarget;\r\n    let orig = btn.innerText;\r\n    btn.innerText = \"SAVING...\"; btn.disabled = true;\r\n\r\n    let roles = {};\r\n    document.querySelectorAll('.fin-role-row').forEach(row => {\r\n        let role = row.dataset.role;\r\n        roles[role] = {\r\n            mult: parseFloat(row.querySelector('.role-mult').value) || 1.0\r\n        };\r\n    });\r\n\r\n    const getVal = (id, def = 0) => {\r\n        let el = document.getElementById(id);\r\n        if(!el) return def;\r\n        let v = parseFloat(el.value);\r\n        return isNaN(v) ? def : v;\r\n    };\r\n\r\n    let trucks = {\r\n        truck_t1_in: getVal('fin-set-truck-t1-in'), truck_t1_out: getVal('fin-set-truck-t1-out'), truck_t1_stay: getVal('fin-set-truck-t1-stay'),\r\n        truck_t2_in: getVal('fin-set-truck-t2-in'), truck_t2_out: getVal('fin-set-truck-t2-out'), truck_t2_stay: getVal('fin-set-truck-t2-stay'),\r\n        truck_t3_in: getVal('fin-set-truck-t3-in'), truck_t3_out: getVal('fin-set-truck-t3-out'), truck_t3_stay: getVal('fin-set-truck-t3-stay'),\r\n        truck_t4_in: getVal('fin-set-truck-t4-in'), truck_t4_out: getVal('fin-set-truck-t4-out'), truck_t4_stay: getVal('fin-set-truck-t4-stay')\r\n    };\r\n    \r\n    let globals = {\r\n        prep_rate: getVal('fin-set-prep-rate', 80),\r\n        prep_hours: getVal('fin-set-prep-hours', 8),\r\n        recovery_rate: getVal('fin-set-recovery-rate', 80),\r\n        recovery_hours: getVal('fin-set-recovery-hours', 8),\r\n        build_rate: getVal('fin-set-build-rate', 100),\r\n        build_hours: getVal('fin-set-build-hours', 6),\r\n        duty_rate: getVal('fin-set-duty-rate', 120),\r\n        duty_hours: getVal('fin-set-duty-hours', 8),\r\n        break_rate: getVal('fin-set-break-rate', 80),\r\n        break_hours: getVal('fin-set-break-hours', 4),\r\n        default_shift_period: getVal('fin-set-default-shift-period', 12),\r\n        overtime_multiplier: getVal('fin-set-overtime-multiplier', 1.5),\r\n        followspot_bonus: getVal('fin-set-followspot-bonus', 0),\r\n        console_bonus: getVal('fin-set-console-bonus', 0),\r\n        extra_rate_standard: getVal('fin-set-extra-rate-standard', 15),\r\n        extra_rate_prep: getVal('fin-set-extra-rate-prep', 15)\r\n    };\r\n\r\n    let payload = {\r\n        roles: roles,\r\n        overheads: finOverheadsList,\r\n        trucks: trucks,\r\n        globals: globals\r\n    };\r\n\r\n    google.script.run\r\n        .withSuccessHandler(() => {\r\n            btn.innerText = \"SAVED ✓\";\r\n            setTimeout(() => { btn.innerText = orig; btn.disabled = false; }, 2000);\r\n        })\r\n        .withFailureHandler(err => {\r\n            alert(\"Error saving settings: \" + err.message);\r\n            btn.innerText = orig; btn.disabled = false;\r\n        })\r\n        .saveFinancialSettings(payload);\r\n}\r\n\n\n";
